import{_ as t,o as r,c as o,ag as n}from"./chunks/framework.Ds6Eueu6.js";const d=JSON.parse(`{"title":"Retirement Benefits at CSU and UC Systems","description":"Retirement Benefits at CSU and UC Systems","frontmatter":{"title":"Retirement Benefits at CSU and UC Systems","date":"2025-06-25T00:00:00.000Z","description":"Retirement Benefits at CSU and UC Systems","tags":["CSU","UC","CalPers","UCRP"]},"headers":[],"relativePath":"blog/2025-06-27_Retirement-Benefits-at-CSU-and-UC-Systems.md","filePath":"blog/2025-06-27_Retirement-Benefits-at-CSU-and-UC-Systems.md","lastUpdated":1774503972000,"posts":[{"html":"<h1 id=\\"the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" tabindex=\\"-1\\">The AI Bubble Won't Take Your Job — But Its Collapse Might <a class=\\"header-anchor\\" href=\\"#the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" aria-label=\\"Permalink to &quot;The AI Bubble Won't Take Your Job — But Its Collapse Might&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p><em>Why the coming AI reckoning makes public sector careers the smartest move you can make</em></p>\\n<p><em>By Penny | March 1, 2026 (updated Mar 3, 2026)</em></p>\\n<hr>\\n<h2 id=\\"key-takeaways\\" tabindex=\\"-1\\">Key Takeaways <a class=\\"header-anchor\\" href=\\"#key-takeaways\\" aria-label=\\"Permalink to &quot;Key Takeaways&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Thesis: The AI bubble will collapse — and when it does, the layoffs won't be because AI took your job. They'll be because of the recession it causes.</strong></p>\\n<ul>\\n<li><strong><a href=\\"#the-real-threat-ai-layoffs-that-aren-t-about-ai\\">The real threat: AI layoffs that aren't about AI</a></strong> — the bubble's collapse will tank the economy and trigger mass layoffs misattributed to &quot;AI disruption&quot;</li>\\n<li><strong><a href=\\"#the-ai-investment-that-isn-t-working\\">AI doesn't work for most businesses</a></strong> — MIT found a 95% failure rate for enterprise AI projects <a href=\\"#source-1\\">[1]</a>, and only 14% of CFOs report measurable ROI <a href=\\"#source-4\\">[4]</a>\\n<ul>\\n<li>IBM found AI initiatives return 5.9% ROI on a 10% capital investment — companies are losing money <a href=\\"#source-3\\">[3]</a></li>\\n<li>Forrester predicts 25% of planned 2026 AI spending will be deferred to 2027 <a href=\\"#source-2\\">[2]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\">Goldman Sachs says AI contributed &quot;basically zero&quot; to U.S. GDP growth</a></strong> — most AI spending flows to Taiwan and South Korea for imported chips <a href=\\"#source-7\\">[7]</a> <a href=\\"#source-8\\">[8]</a>\\n<ul>\\n<li>Only 0.2% of the U.S. economy's 2.2% growth in 2025 came from AI investment <a href=\\"#source-10\\">[10]</a></li>\\n<li>Tech companies plan to spend $700B on AI in 2026; J.P. Morgan says AI needs $600B/year in revenue just to break even <a href=\\"#source-10\\">[10]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-stock-market-is-built-on-spending-not-returns\\">The stock market rally is built on AI spending, not AI returns</a></strong> — AI stocks account for 75% of all S&amp;P 500 returns since ChatGPT launched <a href=\\"#source-29\\">[29]</a>, but generate only 32% of index earnings <a href=\\"#source-31\\">[31]</a>\\n<ul>\\n<li>Strip out tech and communications, and the S&amp;P 500 returned just 6% in 2025 <a href=\\"#source-30\\">[30]</a></li>\\n<li>Apollo's chief economist says the AI bubble is now bigger than the 1990s IT bubble <a href=\\"#source-33\\">[33]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-110-billion-question\\">OpenAI's $110B round is a house of cards</a></strong> — Amazon invests $50B, OpenAI commits to spending $100B on AWS; money just circulates <a href=\\"#source-13\\">[13]</a>\\n<ul>\\n<li>OpenAI spent $9B to lose $5B in 2025 <a href=\\"#source-17\\">[17]</a></li>\\n<li>AI-related debt issuance crossed $200B, representing 30% of all USD credit supply <a href=\\"#source-11\\">[11]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-subsidized-illusion\\">AI subscriptions are subsidized below true cost</a></strong> — your $20/mo plan likely costs $1,000-2,000+/mo to serve <a href=\\"#source-18\\">[18]</a>\\n<ul>\\n<li>Even the $200/mo ChatGPT Pro loses money on power users (per Sam Altman) <a href=\\"#source-19\\">[19]</a></li>\\n<li>As Ed Zitron documents, every level of the AI value chain is unprofitable <a href=\\"#source-17\\">[17]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#but-what-about-anthropic\\">Even &quot;responsible&quot; Anthropic can't make the math work</a></strong> — its AWS bill alone consumed 100% of revenue through September 2025 <a href=\\"#source-34\\">[34]</a>, before paying for Google Cloud, salaries, data centers, or anything else\\n<ul>\\n<li>Claude Code subscribers consume $8-13.50 in compute for every $1 they pay <a href=\\"#source-46\\">[46]</a></li>\\n<li>Anthropic projects $80B in total cloud spend through 2029 <a href=\\"#source-39\\">[39]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#but-inference-costs-are-dropping-exponentially\\">Falling inference costs won't save them</a></strong> — the 280x cost drop is for GPT-3.5-level performance, a model nobody wants anymore <a href=\\"#source-48\\">[48]</a>; reasoning models consume 20x more compute per query <a href=\\"#source-52\\">[52]</a>\\n<ul>\\n<li>Jevons Paradox: inference costs fell 1,000x but demand rose 10,000x — total enterprise AI spending surged 320% in 2025 <a href=\\"#source-55\\">[55]</a></li>\\n<li>Cursor paid ~$650M/year to Anthropic while earning ~$500M — a negative 30% gross margin <a href=\\"#source-54\\">[54]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-k-shaped-economy-a-house-of-cards\\">The economy is a K-shape propped up by the wealthy</a></strong> — top 10% accounts for 50% of all consumer spending, driven by inflated stock portfolios <a href=\\"#source-21\\">[21]</a>\\n<ul>\\n<li>Bottom 80% hasn't outpaced inflation in 6 years <a href=\\"#source-23\\">[23]</a></li>\\n<li>$180B in consumer spending is driven by AI-inflated stock wealth effect alone <a href=\\"#source-27\\">[27]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#why-public-sector-careers-are-the-smart-play\\">Public sector careers are the smart play</a></strong> — California's budget will take a hit, but public sector workers get furloughs, not layoffs — and keep their pensions, health insurance, and union protection through every recession <a href=\\"#source-57\\">[57]</a> <a href=\\"#source-60\\">[60]</a> <a href=\\"#source-66\\">[66]</a></li>\\n</ul>\\n<hr>\\n<h2 id=\\"the-real-threat-ai-layoffs-that-aren-t-about-ai\\" tabindex=\\"-1\\">The Real Threat: AI Layoffs That Aren't About AI <a class=\\"header-anchor\\" href=\\"#the-real-threat-ai-layoffs-that-aren-t-about-ai\\" aria-label=\\"Permalink to &quot;The Real Threat: AI Layoffs That Aren't About AI&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's the thesis that ties it all together, and the reason you should be thinking about career stability right now.</p>\\n<p><strong>AI will cause mass layoffs — not because the technology replaced workers, but because the financial bubble built around it will collapse and drag the broader economy down.</strong></p>\\n<p>The causal chain looks like this:</p>\\n<ol>\\n<li>AI spending inflates tech valuations and GDP numbers</li>\\n<li>Inflated stocks create a wealth effect that drives consumer spending among the top 10%</li>\\n<li>The bottom 80% is already stretched thin, running on debt</li>\\n<li>Enterprise AI fails to deliver ROI — 95% of projects show no measurable returns</li>\\n<li>Companies begin cutting AI budgets (already happening — Forrester projects 25% deferrals)</li>\\n<li>Tech stocks correct as the narrative shifts</li>\\n<li>The wealth effect reverses — wealthy consumers pull back</li>\\n<li>Nobody else can pick up the slack because they were already tapped out</li>\\n<li>GDP contracts from multiple directions simultaneously</li>\\n<li>Companies execute mass layoffs to protect margins</li>\\n</ol>\\n<p>And here's the cruelest irony: <strong>the headlines will say &quot;AI replaced these workers.&quot;</strong> CEOs will frame layoffs as &quot;AI-driven transformation&quot; because it sounds strategic. Media will repeat the narrative because it's a clean story. But the reality is that the jobs disappeared because the financial infrastructure collapsed, not because a chatbot learned to do them.</p>\\n<p>We've seen this exact pattern before. Dot-com bust workers didn't lose jobs because websites replaced them — they lost jobs because companies had hired against inflated revenue projections that evaporated overnight. The 2008 financial crisis didn't eliminate construction jobs because buildings got smarter — it eliminated them because the financing structure collapsed.</p>\\n<hr>\\n<h2 id=\\"the-ai-investment-that-isn-t-working\\" tabindex=\\"-1\\">The AI Investment That Isn't Working <a class=\\"header-anchor\\" href=\\"#the-ai-investment-that-isn-t-working\\" aria-label=\\"Permalink to &quot;The AI Investment That Isn't Working&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Let's start with the most inconvenient fact in technology right now: <strong>AI doesn't work for most businesses.</strong></p>\\n<p>A landmark study from MIT found a staggering <strong>95% failure rate for enterprise generative AI projects</strong>, defined as not having shown measurable financial returns within six months <a href=\\"#source-1\\">[1]</a>. This isn't a fringe finding. Forrester Research reports that only 15% of AI decision-makers saw a positive impact on profitability, and predicts that enterprises will <strong>defer 25% of planned 2026 AI spending into 2027</strong> because the returns simply aren't there <a href=\\"#source-2\\">[2]</a>.</p>\\n<p>IBM's own research found that enterprise-wide AI initiatives achieved an <strong>ROI of just 5.9% despite requiring a 10% capital investment</strong> — meaning companies are literally losing money on AI <a href=\\"#source-3\\">[3]</a>. And only 14% of CFOs report measurable ROI from AI to date <a href=\\"#source-4\\">[4]</a>. Recent enterprise surveys confirm that <strong>90-95% of organizations are seeing little to no measurable financial return</strong> on their AI investments <a href=\\"#source-5\\">[5]</a>.</p>\\n<p>If you work in the public sector and your agency rolled out Microsoft Copilot, ask yourself: does anyone actually use it? The answer, overwhelmingly across both public and private sectors, is no. Nearly 70% of Fortune 500 companies are paying for Copilot, but the productivity benefits are so diffuse they don't move the needle on actual business results <a href=\\"#source-6\\">[6]</a>.</p>\\n<hr>\\n<h2 id=\\"goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\" tabindex=\\"-1\\">Goldman Sachs Says AI Contributed &quot;Basically Zero&quot; to the Economy <a class=\\"header-anchor\\" href=\\"#goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\" aria-label=\\"Permalink to &quot;Goldman Sachs Says AI Contributed &quot;Basically Zero&quot; to the Economy&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>In late February 2026, Goldman Sachs Chief Economist Jan Hatzius dropped a bombshell in an interview with the Atlantic Council. AI investment spending, he said, has had <strong>&quot;basically zero&quot;</strong> contribution to U.S. GDP growth <a href=\\"#source-7\\">[7]</a>.</p>\\n<p>&quot;We don't actually view AI investment as strongly growth positive,&quot; Hatzius stated. &quot;I think there's a lot of misreporting, actually, of the impact AI investment had on U.S. GDP growth in 2025, and it's much smaller than is often perceived.&quot; <a href=\\"#source-7\\">[7]</a></p>\\n<p>The reason is straightforward: most AI equipment is imported. The chips come from Taiwan. The hardware comes from South Korea. As Hatzius put it: &quot;A lot of the AI investment that we're seeing in the U.S. adds to Taiwanese GDP, and it adds to Korean GDP but not really that much to U.S. GDP.&quot; <a href=\\"#source-8\\">[8]</a></p>\\n<p>His colleague Joseph Briggs made the same case to the Washington Post, calling the AI-as-growth-engine story &quot;very intuitive&quot; but ultimately misleading — it &quot;maybe prevented or limited the need to actually dig deeper into what was happening.&quot; <a href=\\"#source-9\\">[9]</a></p>\\n<p>Of the U.S. economy's 2.2% growth in 2025, analyst Joseph Politano calculates that only <strong>0.2% was attributable to AI investment</strong> after accounting for imports <a href=\\"#source-10\\">[10]</a>. Meanwhile, tech companies are expected to spend <strong>$700 billion on AI infrastructure in 2026</strong> <a href=\\"#source-10\\">[10]</a>. J.P. Morgan has calculated that AI would need to generate over <strong>$600 billion in annual revenue</strong> just to achieve a 10% return on infrastructure expenditures <a href=\\"#source-10\\">[10]</a>. Current total AI industry revenue is a fraction of that.</p>\\n<p>Deutsche Bank has warned that the <strong>U.S. would be close to recession without tech-related spending</strong> <a href=\\"#source-11\\">[11]</a> — which sounds like AI is saving the economy until you realize the money mostly flows overseas. An analysis from MRB Partners found that after adjusting for high-tech imports, AI's net contribution to GDP growth was only <strong>20-25%</strong>, not the 40-92% figures that dominated headlines <a href=\\"#source-12\\">[12]</a>.</p>\\n<hr>\\n<h2 id=\\"the-stock-market-is-built-on-spending-not-returns\\" tabindex=\\"-1\\">The Stock Market Is Built on Spending, Not Returns <a class=\\"header-anchor\\" href=\\"#the-stock-market-is-built-on-spending-not-returns\\" aria-label=\\"Permalink to &quot;The Stock Market Is Built on Spending, Not Returns&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's the critical distinction most analysts gloss over: <strong>AI is driving stock prices. It is not driving profits.</strong></p>\\n<p>Since ChatGPT launched in November 2022, AI-related stocks have accounted for <strong>75% of all S&amp;P 500 returns, 80% of earnings growth, and 90% of capital spending growth</strong>, according to J.P. Morgan Asset Management's Michael Cembalest <a href=\\"#source-29\\">[29]</a>. In 2025 alone, the Magnificent Seven were responsible for <strong>42% of the S&amp;P 500's 17.9% return</strong> for the year <a href=\\"#source-30\\">[30]</a>. If you strip out the tech and communications sectors entirely, the S&amp;P 500 would have returned just <strong>6%</strong> in 2025 <a href=\\"#source-30\\">[30]</a>. Seven companies with AI exposure — NVIDIA, Alphabet, Microsoft, Broadcom, JPMorgan Chase, Palantir, and Meta — delivered over <strong>half</strong> of the entire index's gains <a href=\\"#source-31\\">[31]</a>.</p>\\n<p>This means the entire stock market rally — the one powering the wealth effect, driving consumer spending, and propping up GDP — is built on one bet: that AI spending will eventually produce returns. But as we've just seen, Goldman Sachs says it's contributed &quot;basically zero&quot; to the economy. MIT says 95% of enterprise projects fail. Only 14% of CFOs can point to measurable ROI.</p>\\n<p><strong>The money is real. The spending is real. The returns aren't.</strong></p>\\n<p>And the gap between market hype and economic reality is widening. The top 10 stocks now represent <strong>41% of the S&amp;P 500's total weight but generate only about 32% of its earnings</strong> — a gap that has widened meaningfully since 2015, when weight and earnings contribution were closely aligned <a href=\\"#source-31\\">[31]</a>. Goldman Sachs' own equity research team acknowledges that the &quot;combination of elevated valuations, extreme concentration, and strong recent returns rhymes with a handful of overextended equity markets during the last century&quot; <a href=\\"#source-32\\">[32]</a>. AI capex is on track to reach <strong>75% of cash flows</strong> for the largest tech companies — similar to tech spending in the late 1990s — and future spending growth will increasingly rely on debt <a href=\\"#source-32\\">[32]</a>.</p>\\n<p>Apollo's chief economist Torsten Slok has published research showing that <strong>the AI bubble is now bigger than the IT bubble of the 1990s</strong>, with the average P/E ratio of the top 10 S&amp;P 500 companies sitting around 50 and hyperscaler capital expenditure as a share of GDP exceeding the dotcom era <a href=\\"#source-33\\">[33]</a>. His bottom line: investors in the S&amp;P 500 &quot;remain overexposed to AI&quot; <a href=\\"#source-33\\">[33]</a>.</p>\\n<p>Think of it like Cisco in 1999. Cisco had real revenue — they were selling real routers to real companies building out internet infrastructure. The stock price reflected the spending story, not the returns story. The companies buying the routers never built sustainable businesses on top of them. When the spending stopped, Cisco's stock dropped 86% and never recovered its peak. Today, NVIDIA is the Cisco of the AI era — posting real revenue because hyperscalers are writing enormous checks for GPUs. But the companies buying those GPUs can't show a return on the investment. The spending is driving the stock, not the other way around.</p>\\n<hr>\\n<h2 id=\\"the-110-billion-question\\" tabindex=\\"-1\\">The $110 Billion Question <a class=\\"header-anchor\\" href=\\"#the-110-billion-question\\" aria-label=\\"Permalink to &quot;The $110 Billion Question&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>On February 27, 2026, OpenAI announced a <strong>$110 billion funding round</strong> — the largest private fundraise in history — at a $730 billion pre-money valuation. Amazon invested $50 billion, with Nvidia and SoftBank contributing $30 billion each <a href=\\"#source-13\\">[13]</a> <a href=\\"#source-14\\">[14]</a>.</p>\\n<p>These numbers sound impressive until you examine the structure. Amazon invests $50 billion in OpenAI, and OpenAI commits to spending $100 billion on AWS over eight years <a href=\\"#source-13\\">[13]</a>. The money flows out and comes right back. It's not a clean investment — it's a customer acquisition cost disguised as a capital raise. For context, this single round exceeds the <strong>$170 billion in total U.S. venture capital investment for all of 2023</strong> <a href=\\"#source-15\\">[15]</a>.</p>\\n<p>Reporting has revealed that OpenAI's Stargate joint venture involves very little actual collaboration among partners, with most data centers being traditional bilateral deals rather than the unified project that was announced — described by one outlet as better understood as <strong>&quot;a branding exercise than a real entity&quot;</strong> <a href=\\"#source-16\\">[16]</a>.</p>\\n<p>And the investor pool is narrowing. This round came from just three megaplayers who are simultaneously OpenAI's suppliers and customers. That's not a sign of broad market confidence. That's a sign that the only people willing to write checks are those with strategic reasons beyond financial return.</p>\\n<hr>\\n<h2 id=\\"the-subsidized-illusion\\" tabindex=\\"-1\\">The Subsidized Illusion <a class=\\"header-anchor\\" href=\\"#the-subsidized-illusion\\" aria-label=\\"Permalink to &quot;The Subsidized Illusion&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's something most AI users don't realize: <strong>your subscription is being heavily subsidized by investor capital.</strong> Tech journalist <a href=\\"https://www.wheresyoured.at/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron</a> has been documenting this dynamic extensively, and the numbers are damning.</p>\\n<p>As Zitron details, OpenAI spent <strong>50% of its revenue on inference compute costs alone, and 75% on training compute</strong> — numbers that add up to well over 100% of revenue. They spent $9 billion to lose $5 billion <a href=\\"#source-17\\">[17]</a>. And it's not just OpenAI. Perplexity spent <strong>164% of its revenue</strong> on AWS, Anthropic, and OpenAI costs in 2024 <a href=\\"#source-17\\">[17]</a>.</p>\\n<p>Zitron's core observation cuts to the heart of the problem: &quot;Anybody funding an AI startup is effectively sending that money to Anthropic or OpenAI, who then immediately send that money to Amazon, Google or Microsoft, who are yet to show that they make any profit on selling it.&quot; <a href=\\"#source-17\\">[17]</a> The money cascades down and evaporates at every level. Nobody in the chain is profitable.</p>\\n<p>A developer using Claude Code eight hours a day can cost the provider <strong>tens of thousands of dollars per month</strong> in compute — on a $200 subscription <a href=\\"#source-18\\">[18]</a>. OpenAI's CEO Sam Altman has publicly acknowledged that even the <strong>$200/month ChatGPT Pro tier loses money</strong> on power users <a href=\\"#source-19\\">[19]</a>. The true cost of serving a heavy AI user is likely <strong>$1,000 to $2,000+ per month</strong>, not the $20-200 consumers pay.</p>\\n<p>AI companies are running the same playbook as Uber and WeWork — price below cost to capture market share, subsidize the difference with investor billions, and figure out profitability later <a href=\\"#source-20\\">[20]</a>. When investor subsidies dry up — whether through funding fatigue, a market correction, or companies simply running out of runway — prices must rise to reflect reality. And at real prices, the value proposition collapses for the vast majority of users. If most enterprise users don't find AI useful at $0 (the Copilot licenses their companies pay for that go unused), they certainly won't pay $2,000/month.</p>\\n<p>AI-related debt issuance in credit markets crossed <strong>$200 billion in 2025</strong>, representing 30% of all USD credit supply <a href=\\"#source-11\\">[11]</a>. Hyperscalers are projected to spend a cumulative <strong>$4 trillion on AI data centers through 2030</strong> <a href=\\"#source-11\\">[11]</a>. These are staggering bets on a technology that 95% of enterprises can't generate returns from.</p>\\n<hr>\\n<h2 id=\\"but-what-about-anthropic\\" tabindex=\\"-1\\">But What About Anthropic? <a class=\\"header-anchor\\" href=\\"#but-what-about-anthropic\\" aria-label=\\"Permalink to &quot;But What About Anthropic?&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>If OpenAI is the poster child for AI excess, Anthropic is supposed to be the responsible adult — enterprise-focused, safety-conscious, targeting break-even by 2028 <a href=\\"#source-43\\">[43]</a>. But the numbers tell a different story.</p>\\n<p>Ed Zitron obtained Anthropic's AWS billing data and revealed that through September 2025, the company spent <strong>$2.66 billion on Amazon Web Services</strong> on an estimated <strong>$2.55 billion in revenue</strong> <a href=\\"#source-34\\">[34]</a>. Just the AWS bill — one line item from one cloud vendor — consumed every dollar the company earned. And as Zitron observed, the costs scale linearly with revenue, showing no evidence of improving margins at scale <a href=\\"#source-34\\">[34]</a>.</p>\\n<p>And that's before paying for anything else. Here's what sits on top, roughly ordered by magnitude:</p>\\n<ul>\\n<li><strong>Google Cloud compute</strong> (estimated $1.3B+ through Sept 2025) — Anthropic also runs on GCP, committed to a deal worth &quot;tens of billions&quot; for up to one million TPUs <a href=\\"#source-35\\">[35]</a>, and Zitron estimates their Google spend at a minimum of 50% of their AWS bill <a href=\\"#source-34\\">[34]</a>. Inference costs ran 23% over plan in 2025 <a href=\\"#source-36\\">[36]</a></li>\\n<li><strong>Salaries and compensation</strong> (~$500-600M/year) — over 1,200 employees <a href=\\"#source-37\\">[37]</a> with a median total compensation of $472,000; top AI researchers earning up to $759,000 <a href=\\"#source-38\\">[38]</a></li>\\n<li><strong>Revenue sharing with cloud platforms</strong> ($360M in 2025, scaling to $1.9B in 2026 and $6.4B by 2027) — AWS takes up to 50% of gross profits from AI sales on its platform; Google takes 20-30% of net revenue <a href=\\"#source-39\\">[39]</a> <a href=\\"#source-40\\">[40]</a></li>\\n<li><strong>Data center construction</strong> ($50B committed) — partnership with FluidStack to build facilities in Texas and New York, with sites expected online throughout 2026 <a href=\\"#source-41\\">[41]</a></li>\\n<li><strong>Microsoft Azure compute</strong> ($30B committed over time) — announced alongside a $5B Microsoft investment in November <a href=\\"#source-39\\">[39]</a></li>\\n<li><strong>Energy and grid infrastructure</strong> (uncapped commitment) — Anthropic publicly pledged to cover 100% of electricity price increases and grid upgrade costs for every community hosting its data centers <a href=\\"#source-42\\">[42]</a></li>\\n<li><strong>R&amp;D, safety research, and model training</strong> (hundreds of millions/year) — total company cash burn was $5.6B in 2024 and ~$3B in 2025 <a href=\\"#source-43\\">[43]</a>, and the costs above don't account for all of it</li>\\n<li><strong>Sales, marketing, and enterprise support</strong> (rapidly scaling) — serving 300,000+ business customers, with 500+ spending over $1M annually <a href=\\"#source-44\\">[44]</a></li>\\n<li><strong>Legal and IPO preparation</strong> (tens of millions) — retained Wilson Sonsini, the firm behind Google's and LinkedIn's IPOs, to advise on a potential 2026 listing <a href=\\"#source-45\\">[45]</a></li>\\n</ul>\\n<p>Claude Code, the company's breakout coding product, makes the math even worse — subscribers consume <strong>$8-13.50 in actual compute for every $1 they pay</strong>, meaning a $200/month user burns through over $2,700 in real costs <a href=\\"#source-46\\">[46]</a>.</p>\\n<p>So when Anthropic projects &quot;break-even by 2028,&quot; the question is: break-even on what definition? If the most disciplined company in the AI race spends 100% of revenue on a single vendor's cloud bill before touching any other expense, the industry's path to profitability isn't just narrow — it may not exist.</p>\\n<hr>\\n<h2 id=\\"but-inference-costs-are-dropping-exponentially\\" tabindex=\\"-1\\">“But Inference Costs Are Dropping Exponentially!” <a class=\\"header-anchor\\" href=\\"#but-inference-costs-are-dropping-exponentially\\" aria-label=\\"Permalink to &quot;“But Inference Costs Are Dropping Exponentially!”&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>They are. Stanford HAI’s 2025 AI Index Report found that inference costs for GPT-3.5-level performance dropped over <strong>280-fold</strong> between November 2022 and October 2024 <a href=\\"#source-48\\">[48]</a>. Epoch AI’s research measured declines ranging from <strong>9x to 900x per year</strong> depending on the task, with the fastest drops occurring after January 2024 <a href=\\"#source-49\\">[49]</a>. OpenAI’s internal compute margin hit <strong>70%</strong> by October 2025, double its January 2024 level <a href=\\"#source-50\\">[50]</a>. These are real gains. Nobody serious disputes them.</p>\\n<p>The problem is that none of it matters in the way the bulls need it to.</p>\\n<p><strong>The cost drops are happening on yesterday’s models. The frontier is a treadmill.</strong> The 280x improvement Stanford measured is for GPT-3.5-level performance — a model nobody wants anymore. Users now expect GPT-4-level quality and reasoning capabilities of o1-class models, which employ test-time scaling and consume vastly more tokens per query. The cost per query may actually be <em>increasing</em> for frontier models even as cost per token declines <a href=\\"#source-51\\">[51]</a>. Reasoning models require roughly <strong>20x more tokens and 150x more compute per query</strong> than traditional LLMs <a href=\\"#source-52\\">[52]</a>. At maximum reasoning settings, a simple question might consume <strong>10,000 reasoning tokens internally</strong> while returning a 200-token answer <a href=\\"#source-53\\">[53]</a>.</p>\\n<p>This is the trick hiding inside the headline numbers. Every time efficiency catches up to the current frontier, the frontier moves. GPT-3.5 costs collapse — but customers have migrated to GPT-4. GPT-4 costs collapse — but everyone’s running o1-class reasoning chains. It’s like celebrating that a 2019 Toyota got cheaper while your customers all want the 2026 model. The efficiency gains are perpetually arriving for the product the market has already moved past.</p>\\n<p>Anthropic expects its gross profit margin to reach 50% this year and 77% by 2028 — but the inference cost declines are happening on older models. Frontier models are getting more expensive, not cheaper <a href=\\"#source-56\\">[56]</a>. The rise of agentic workflows has caused token consumption per task to jump <strong>10-100x</strong> since December 2023. Every leap in capability resets the economics back to brutal.</p>\\n<p><strong>Jevons Paradox eats the savings.</strong> Even setting aside the frontier treadmill, cheaper inference doesn’t produce cheaper AI bills. It produces <em>more AI bills.</em> Inference costs fell roughly 1,000-fold, but demand rose 10,000-fold — cheaper tokens didn’t reduce spending, they unleashed it <a href=\\"#source-55\\">[55]</a>. Enterprise AI spending surged <strong>320%</strong> in 2025 despite per-token costs dropping 1,000x, because each price drop makes thousands of new use cases suddenly economically viable <a href=\\"#source-54\\">[54]</a>.</p>\\n<p>This isn’t speculation. It’s what happened with coal in the 1860s, bandwidth in the 2000s, and mobile data in the 2010s. Every time you make a resource cheaper, consumption expands to more than compensate. Satya Nadella said it himself the day DeepSeek launched: “Jevons paradox strikes again.” If your per-token cost drops from $0.06 to $0.00006, you don’t get savings — you get AI running on every customer service interaction, personalized content at the individual level, and agents iterating through dozens of reasoning steps per response <a href=\\"#source-54\\">[54]</a>. The volume explosion overwhelms any per-unit improvement.</p>\\n<p>For AI providers, this is actually <em>good</em> for revenue growth but <em>terrible</em> for the profitability thesis. More usage means more infrastructure, more GPUs, more power, more cooling. The denominator scales with the numerator. You’re running faster to stay in the same place.</p>\\n<p><strong>The application-layer margin squeeze is brutal.</strong> Even if you accept that the foundation model providers are improving their margins, the companies actually building products on top of those models are getting crushed. Cursor, the poster child for AI-powered coding tools, was reportedly paying approximately <strong>$650 million annually to Anthropic</strong> while generating only <strong>$500 million in revenue</strong> — a negative 30% gross margin. Their AWS bills doubled in a single month when Anthropic launched new pricing tiers <a href=\\"#source-56\\">[56]</a>.</p>\\n<p>This isn’t an outlier. Bessemer’s 2025 data shows fast-ramping AI startups averaging only <strong>25% gross margins</strong>, with many running negative. The traditional SaaS benchmark for a healthy gross margin is 75%+ <a href=\\"#source-56\\">[56]</a>. If you show up to a Series B with 25% margins, you’re not a software company — you’re a services business subsidizing your customers’ compute.</p>\\n<p>The inference cost curve is real. It’s also irrelevant to the question that actually matters: can these companies turn a profit before they run out of other people’s money? So far, every efficiency gain gets consumed by the next leap in model complexity, the next explosion in usage volume, or the next round of infrastructure buildout. The treadmill doesn’t stop. And yes, a true believer can argue that all of these trends will reverse at exactly the right moment — that costs will plateau just as capital dries up, that margins will appear just as subsidies vanish, that the history of every other capital-intensive bubble will suddenly stop applying. But that’s not an argument. That’s a hope dressed in a spreadsheet.</p>\\n<hr>\\n<h2 id=\\"the-k-shaped-economy-a-house-of-cards\\" tabindex=\\"-1\\">The K-Shaped Economy: A House of Cards <a class=\\"header-anchor\\" href=\\"#the-k-shaped-economy-a-house-of-cards\\" aria-label=\\"Permalink to &quot;The K-Shaped Economy: A House of Cards&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>The AI bubble doesn't exist in isolation. It sits on top of an already fragile economic structure that economists call the <strong>&quot;K-shaped economy&quot;</strong> — where the wealthy are thriving while everyone else falls behind.</p>\\n<p>The numbers are stark. The <strong>top 10% of earners now account for 50% of all consumer spending</strong>, up from 35% in the early 1990s <a href=\\"#source-21\\">[21]</a>. Moody's Analytics found that the top 20% accounts for <strong>59% of total spending</strong> <a href=\\"#source-22\\">[22]</a>. And for the bottom 80%? Their spending hasn't outpaced inflation over the last six years, meaning economic quality of life hasn't improved for the vast majority of Americans <a href=\\"#source-23\\">[23]</a>.</p>\\n<p>As of Q4 2025, the <strong>top 20% of households held nearly 72% of total household wealth</strong> <a href=\\"#source-24\\">[24]</a>. Lower-income households are increasingly relying on debt, with <strong>rising delinquency rates particularly in auto loans</strong> <a href=\\"#source-25\\">[25]</a>. Bank of America's analysis shows the divide is worsening, with some economists suggesting we've moved beyond a K-shape into a <strong>&quot;barbell economy&quot;</strong> heavily weighted at the extremes <a href=\\"#source-26\\">[26]</a>.</p>\\n<p>Much of the wealthy's spending is driven by the <strong>&quot;wealth effect&quot;</strong> — they spend more because their stock portfolios are up. And what's driving stock prices? AI hype. Soaring AI-related valuations alone have created an estimated <strong>$180 billion in additional consumer spending</strong> over the past year <a href=\\"#source-27\\">[27]</a>.</p>\\n<p>This creates a dangerous feedback loop: AI hype drives tech stocks up → rising stocks make wealthy people feel richer → wealthy people spend more → GDP looks healthy → the healthy GDP narrative justifies more AI investment → repeat.</p>\\n<p>Moody's chief economist Mark Zandi captured the fragility perfectly: <strong>&quot;It doesn't feel like the economy's perched on a strong foundation. It's perched on a few poles that are sticking up. If one of those poles gets knocked out, then the whole economy gets knocked down.&quot;</strong> <a href=\\"#source-23\\">[23]</a></p>\\n<p>Fortune published an analysis warning that wealthy consumers' spending is <strong>&quot;psychologically tethered to their portfolio balance&quot;</strong> — when the S&amp;P drops, they freeze discretionary spending. And in 2026, <strong>&quot;there is no one there to catch it&quot;</strong> because the bottom 80% has already depleted their pandemic-era savings <a href=\\"#source-28\\">[28]</a>.</p>\\n<p>U.S. Bank's chief economist Beth Ann Bovino put it plainly: <strong>&quot;We're increasingly dependent on healthier cohorts to keep the economy afloat.&quot;</strong> <a href=\\"#source-25\\">[25]</a> That's a polite way of saying the economy collapses if rich people stop spending — and rich people stop spending when their portfolios drop.</p>\\n<hr>\\n<h2 id=\\"why-public-sector-careers-are-the-smart-play\\" tabindex=\\"-1\\">Why Public Sector Careers Are the Smart Play <a class=\\"header-anchor\\" href=\\"#why-public-sector-careers-are-the-smart-play\\" aria-label=\\"Permalink to &quot;Why Public Sector Careers Are the Smart Play&quot;\\">&ZeroWidthSpace;</a></h2>\\n<h3 id=\\"yes-california-s-budget-will-take-a-hit-that-s-not-the-same-as-losing-your-job\\" tabindex=\\"-1\\"><em>Yes, California's budget will take a hit. That's not the same as losing your job.</em> <a class=\\"header-anchor\\" href=\\"#yes-california-s-budget-will-take-a-hit-that-s-not-the-same-as-losing-your-job\\" aria-label=\\"Permalink to &quot;*Yes, California's budget will take a hit. That's not the same as losing your job.*&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p>California gets 67% of its General Fund from personal income tax, and capital gains alone account for 16% of total tax liability — spiking to 25% in boom years <a href=\\"#source-57\\">[57]</a>. When the dot-com bubble burst, state revenue dropped from $100 billion to $85 billion <a href=\\"#source-58\\">[58]</a>. An AI correction will hit state budgets. This is not a hypothetical.</p>\\n<p>But here's what actually happens to public sector workers when budgets get slashed: <strong>they get furloughs, not layoffs.</strong></p>\\n<p>The private sector lost 8.7 million jobs during the Great Recession <a href=\\"#source-59\\">[59]</a>. Public sector employment <em>increased</em> by 590,000 in the first year <a href=\\"#source-47\\">[47]</a>. When budgets finally tightened, the failure mode was fundamentally different. State and local governments shed just 68,000 jobs — a 0.3% decline — while the private sector hemorrhaged millions <a href=\\"#source-63\\">[63]</a>. In FY2010, the worst budget year, 26 states used layoffs but 22 chose furloughs instead <a href=\\"#source-64\\">[64]</a>. California chose furloughs. It has chosen furloughs in nine of the fiscal years since 1992 <a href=\\"#source-65\\">[65]</a>.</p>\\n<p><strong>And furloughs aren't what most people think they are.</strong> California's 2009 furlough program covered 193,000 workers and imposed 2-3 unpaid days per month — a 13.8% reduction on paper <a href=\\"#source-60\\">[60]</a>. In reality, furlough hours were banked as leave credits and paid out at separation, often at a higher base pay after COLA increases <a href=\\"#source-61\\">[61]</a>. Workers kept their jobs, their health insurance, their pension accrual, and their seniority. The historical pattern is consistent: public sector employment didn't drop during the 1991 recession at all, didn't decline after the dot-com bust until 2004, and barely moved during 2008-2012 <a href=\\"#source-62\\">[62]</a>.</p>\\n<p>This stability isn't accidental — it's structural. <strong>Countercyclical demand</strong> means that when the private sector contracts, public sector workload expands. Safety net caseloads rose from 276 million to 310 million recipients during the Great Recession <a href=\\"#source-66\\">[66]</a>. Someone has to process those claims, maintain those roads, inspect those buildings, and run those programs. The work doesn't disappear when the economy does.</p>\\n<p><strong>Union protection</strong> reinforces the structural advantage. Public sector union density is 32.9% versus 5.9% in the private sector, and local agencies sit at 37.8% <a href=\\"#source-67\\">[67]</a>. That means layoffs happen by seniority, not by manager mood. Furloughs are negotiated, not dictated. You get a grievance process before termination. Civil service rules, merit-based hiring, and progressive discipline create layers of protection that simply don't exist in at-will private employment.</p>\\n<p><strong>And then there's the pension.</strong> Public sector workers earn defined-benefit retirement through CalPERS or CalSTRS — a guaranteed monthly income for life calculated from salary and years of service, not subject to market crashes. Thirty years of service typically yields 60-75% of final salary, guaranteed, regardless of what the stock market does. While private sector 401(k)s crater with every correction, public pensions pay out on schedule.</p>\\n<p>You can't be laid off because your company missed earnings. You can't be &quot;restructured&quot; because a VC pulled funding. Your position exists because the public needs the service — not because an investor believes in the growth story.</p>\\n<p>At <a href=\\"https://penpublic.com\\" target=\\"_blank\\" rel=\\"noreferrer\\">PenPublic</a>, we're building the most comprehensive public sector job platform in the country — aggregating positions across hundreds of agencies at the federal, state, and local level. Local agency jobs are the hardest to find because they're scattered across thousands of individual websites. We bring them together in one place. Whether you're a tech worker thinking about your next move, a recent graduate evaluating career paths, or a current public servant exploring new opportunities, we believe public service represents one of the smartest career investments you can make right now.</p>\\n<p>The AI bubble will pop. The K-shaped economy will correct. The question isn't whether disruption is coming — it's whether you'll be positioned on stable ground when it arrives.</p>\\n<hr>\\n<h2 id=\\"sources\\" tabindex=\\"-1\\">Sources <a class=\\"header-anchor\\" href=\\"#sources\\" aria-label=\\"Permalink to &quot;Sources&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><a id=\\"source-1\\"><strong>1.</strong></a> <a href=\\"https://thefinancialbrand.com/news/artificial-intelligence-banking/why-95-of-enterprises-are-getting-zero-return-on-ai-investment-191950\\" target=\\"_blank\\" rel=\\"noreferrer\\">MIT's The GenAI Divide: State of AI in Business 2025</a> — 95% failure rate for enterprise AI projects; $30-40B in investment with zero measurable return</p>\\n<p><a id=\\"source-2\\"><strong>2.</strong></a> <a href=\\"https://bizzdesign.com/blog/enterprise-ai-adoption-balancing-innovation-and-roi-2026\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bizzdesign — &quot;Enterprise AI Adoption: Balancing Innovation and ROI in 2026&quot;</a> — Only 15% report positive profitability impact; Forrester predicts 25% of 2026 AI spend deferred to 2027</p>\\n<p><a id=\\"source-3\\"><strong>3.</strong></a> <a href=\\"https://www.ibm.com/think/insights/ai-roi\\" target=\\"_blank\\" rel=\\"noreferrer\\">IBM — &quot;How to Maximize AI ROI in 2026&quot;</a> — 5.9% ROI on 10% capital investment; only 25% of AI initiatives deliver expected ROI; only 29% can measure ROI confidently</p>\\n<p><a id=\\"source-4\\"><strong>4.</strong></a> <a href=\\"https://medium.com/origintrail/5-trends-to-drive-the-ai-roi-in-2026-trust-is-capital-372ac5dabc38\\" target=\\"_blank\\" rel=\\"noreferrer\\">OriginTrail / Medium — &quot;5 Trends to Drive AI ROI in 2026&quot;</a> — Only 14% of CFOs report measurable ROI; MIT study confirms 95% failure rate</p>\\n<p><a id=\\"source-5\\"><strong>5.</strong></a> <a href=\\"https://www.consultingmag.com/2026/02/04/why-enterprise-ai-stalled-and-what-is-finally-changing-in-2026/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Consulting Magazine — &quot;Why Enterprise AI Stalled and What Is Finally Changing in 2026&quot;</a> — 90-95% of organizations seeing little to no measurable financial return; Gartner predicts 40% of agentic AI projects cancelled by 2027</p>\\n<p><a id=\\"source-6\\"><strong>6.</strong></a> <a href=\\"https://www.fullstack.com/labs/resources/blog/generative-ai-roi-why-80-of-companies-see-no-results\\" target=\\"_blank\\" rel=\\"noreferrer\\">FullStack Labs — &quot;Generative AI ROI: Why 80% Fail&quot;</a> — 70% of Fortune 500 use Copilot; 78% of companies report no significant bottom-line impact; only 1% view GenAI strategies as mature</p>\\n<p><a id=\\"source-7\\"><strong>7.</strong></a> <a href=\\"https://finance.yahoo.com/news/ai-contributed-basically-zero-us-181419807.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yahoo Finance — &quot;AI Contributed 'Basically Zero' to the US Economy, According to Goldman Sachs&quot;</a> — Goldman Sachs Chief Economist Jan Hatzius interview with Atlantic Council</p>\\n<p><a id=\\"source-8\\"><strong>8.</strong></a> <a href=\\"https://gizmodo.com/ai-added-basically-zero-to-us-economic-growth-last-year-goldman-sachs-says-2000725380\\" target=\\"_blank\\" rel=\\"noreferrer\\">Gizmodo — &quot;AI Added 'Basically Zero' to US Economic Growth Last Year, Goldman Sachs Says&quot;</a> — Hatzius on imported AI equipment boosting Taiwanese and Korean GDP</p>\\n<p><a id=\\"source-9\\"><strong>9.</strong></a> <a href=\\"https://futurism.com/future-society/researchers-economy-ai-narratives\\" target=\\"_blank\\" rel=\\"noreferrer\\">Futurism — &quot;Goldman Sachs Researchers Make Startling Claim About AI's Effects on the US Economy&quot;</a> — Joseph Briggs interview with Washington Post</p>\\n<p><a id=\\"source-10\\"><strong>10.</strong></a> <a href=\\"https://www.tomshardware.com/tech-industry/artificial-intelligence/ai-boosted-us-economy-by-basically-zero-in-2025-says-goldman-sachs-chief-economist-we-think-theres-been-a-lot-of-misreporting-of-the-impact-that-ai-investment-had-on-gdp-growth\\" target=\\"_blank\\" rel=\\"noreferrer\\">Tom's Hardware — &quot;AI Boosted US Economy by 'Basically Zero' in 2025, Says Goldman Sachs Chief Economist&quot;</a> — 0.2% AI contribution to 2.2% GDP growth; $700B projected 2026 spend; J.P. Morgan $600B revenue threshold</p>\\n<p><a id=\\"source-11\\"><strong>11.</strong></a> <a href=\\"https://fortune.com/2025/12/23/us-gdp-alive-by-ai-capex/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;A Huge Chunk of U.S. GDP Growth Is Being Kept Alive by AI Spending 'With No Guaranteed Return'&quot;</a> — Deutsche Bank recession warning; $200B AI-related credit issuance (30% of USD supply); $4 trillion cumulative data center spend projected through 2030</p>\\n<p><a id=\\"source-12\\"><strong>12.</strong></a> <a href=\\"https://www.cnbc.com/2026/01/26/ai-wasnt-the-biggest-engine-of-us-gdp-growth-in-2025.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">CNBC — &quot;AI Spending Wasn't the Biggest Engine of U.S. Economic Growth in 2025&quot;</a> — MRB Partners analysis; 20-25% net AI contribution after import adjustment; consumer spending as true growth driver</p>\\n<p><a id=\\"source-13\\"><strong>13.</strong></a> <a href=\\"https://techcrunch.com/2026/02/27/openai-raises-110b-in-one-of-the-largest-private-funding-rounds-in-history/\\" target=\\"_blank\\" rel=\\"noreferrer\\">TechCrunch — &quot;OpenAI Raises $110B in One of the Largest Private Funding Rounds in History&quot;</a> — $50B Amazon, $30B Nvidia, $30B SoftBank; stateful runtime on AWS Bedrock; $100B AWS commitment expansion</p>\\n<p><a id=\\"source-14\\"><strong>14.</strong></a> <a href=\\"https://www.bloomberg.com/news/articles/2026-02-27/openai-finalizes-110-billion-funding-at-730-billion-valuation\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bloomberg — &quot;OpenAI Finalizes $110 Billion Funding at $730 Billion Value&quot;</a> — $730B pre-money valuation; Amazon's $35B contingent on AGI or IPO</p>\\n<p><a id=\\"source-15\\"><strong>15.</strong></a> <a href=\\"https://www.axios.com/2026/02/27/openai-funding-nvidia-amazon\\" target=\\"_blank\\" rel=\\"noreferrer\\">Axios — &quot;OpenAI Secures $110B Funding Round&quot;</a> — Round exceeds total 2023 U.S. VC investment ($170B); Microsoft did not participate</p>\\n<p><a id=\\"source-16\\"><strong>16.</strong></a> <a href=\\"https://www.newcomer.co/p/openai-raises-110-billion-and-throws\\" target=\\"_blank\\" rel=\\"noreferrer\\">Newcomer — &quot;OpenAI Raises $110 Billion &amp; Throws In With Amazon&quot;</a> — Stargate described as &quot;branding exercise&quot;; little collaboration among partners; complicated financial structures becoming ordinary arrangements</p>\\n<p><a id=\\"source-17\\"><strong>17.</strong></a> <a href=\\"https://www.wheresyoured.at/why-everybody-is-losing-money-on-ai/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron / Where's Your Ed At — &quot;Why Everybody Is Losing Money on AI&quot;</a> — OpenAI: 50% revenue on inference, 75% on training (&gt;100% combined); $9B spent to lose $5B; Perplexity at 164% of revenue on compute; entire value chain unprofitable</p>\\n<p><a id=\\"source-18\\"><strong>18.</strong></a> <a href=\\"https://www.news.aakashg.com/p/how-to-price-ai-products\\" target=\\"_blank\\" rel=\\"noreferrer\\">Product Faculty / AI Pricing Guide 2026</a> — Claude Code heavy users cost &quot;tens of thousands per month&quot;; OpenAI projects $14B cumulative losses by end of 2026; AI SaaS gross margins 20-60% vs traditional 70-90%</p>\\n<p><a id=\\"source-19\\"><strong>19.</strong></a> <a href=\\"https://www.getmonetizely.com/blogs/ai-pricing-how-much-does-ai-cost-in-2025\\" target=\\"_blank\\" rel=\\"noreferrer\\">Monetizely — &quot;AI Pricing in 2025: Strategy for Costing&quot;</a> — Sam Altman admission that $200/mo Pro tier loses money on power users; AI gross margins under pressure industry-wide</p>\\n<p><a id=\\"source-20\\"><strong>20.</strong></a> <a href=\\"https://www.uptechstudio.com/blog/the-true-cost-of-ai-when-the-subsidies-run-out\\" target=\\"_blank\\" rel=\\"noreferrer\\">UpTech Studio — &quot;The True Cost of AI: When the Subsidies Run Out&quot;</a> — Uber/WeWork subsidy model comparison; land-grab pricing strategy; warning that 5x current AI costs would kill most AI startups</p>\\n<p><a id=\\"source-21\\"><strong>21.</strong></a> <a href=\\"https://www.pbs.org/newshour/show/k-shaped-economy-why-the-wealthy-are-thriving-as-most-americans-fall-behind\\" target=\\"_blank\\" rel=\\"noreferrer\\">PBS NewsHour — &quot;K-Shaped Economy: Why the Wealthy Are Thriving as Most Americans Fall Behind&quot;</a> — Top 10% = 50% of spending (up from 35% in early 1990s)</p>\\n<p><a id=\\"source-22\\"><strong>22.</strong></a> <a href=\\"https://finance.yahoo.com/video/wealth-inequality-k-shaped-economy-183000976.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yahoo Finance — Mark Zandi Interview: &quot;Wealth Inequality in K-Shaped Economy Is 'Corrosive'&quot;</a> — Top 20% = 59% of total spending (Moody's Analytics data)</p>\\n<p><a id=\\"source-23\\"><strong>23.</strong></a> <a href=\\"https://www.cnbc.com/2026/01/30/wealth-inequality-k-shaped-economy-united-states-consumer-spending-trump.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">CNBC — &quot;Wealth Inequality and the 'K-Shaped' Economy Are More Striking Than Ever&quot;</a> — Bottom 80% spending hasn't outpaced inflation in 6 years; Mark Zandi &quot;poles&quot; quote; rising auto loan delinquencies</p>\\n<p><a id=\\"source-24\\"><strong>24.</strong></a> <a href=\\"https://economics.td.com/us-k-shaped-consumer-spending\\" target=\\"_blank\\" rel=\\"noreferrer\\">TD Economics — &quot;U.S. Consumer Spending: Still a K, but That's OK&quot;</a> — Top 20% hold 72% of total household wealth as of Q4 2025; K-shape expected to deepen in 2026 due to tax policy</p>\\n<p><a id=\\"source-25\\"><strong>25.</strong></a> <a href=\\"https://www.usbank.com/corporate-and-commercial-banking/insights/economy/macro/k-shaped-economy.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">U.S. Bank — &quot;The K-Shaped Economy in 2026&quot;</a> — Lower-income households relying on debt; rising delinquency rates; Beth Ann Bovino quote on dependence on &quot;healthier cohorts&quot;</p>\\n<p><a id=\\"source-26\\"><strong>26.</strong></a> <a href=\\"https://fortune.com/2026/01/14/when-will-us-enter-recession-middle-class-barbell-k-shaped-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;Forget the K-Shape: We Have a Barbell Economy&quot;</a> — Economy described as &quot;dangerously brittle&quot;; wealthy spending tethered to portfolio balance; bottom 80% financing groceries with &quot;shadow debt&quot;</p>\\n<p><a id=\\"source-27\\"><strong>27.</strong></a> <a href=\\"https://www.empower.com/the-currency/money/life/k-shaped-economy-what-to-know-news\\" target=\\"_blank\\" rel=\\"noreferrer\\">Empower — &quot;The K-Shaped Economy: What Consumers Should Know&quot;</a> — $180B in wealth-effect consumer spending from AI-related stock valuations; Delta premium revenue up 9%, basic economy down 7%</p>\\n<p><a id=\\"source-28\\"><strong>28.</strong></a> <a href=\\"https://fortune.com/2026/01/14/when-will-us-enter-recession-middle-class-barbell-k-shaped-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;Forget the K-Shape: We Have a Barbell Economy&quot;</a> — &quot;No one there to catch it&quot; when wealthy pull back; pandemic savings depleted; economy has &quot;massive engine and insufficient braking mechanisms&quot;</p>\\n<p><a id=\\"source-29\\"><strong>29.</strong></a> <a href=\\"https://insights.som.yale.edu/insights/this-is-how-the-ai-bubble-bursts\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yale Insights / Jeffrey Sonnenfeld — &quot;This Is How the AI Bubble Bursts&quot;</a> — J.P. Morgan's Cembalest: AI stocks = 75% of S&amp;P 500 returns, 80% of earnings growth, 90% of capex growth since ChatGPT launch; two-thirds of U.S. deal value going to AI/ML startups in H1 2025</p>\\n<p><a id=\\"source-30\\"><strong>30.</strong></a> <a href=\\"https://www.statista.com/chart/30318/sector-contributions-to-sp500-return/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Statista — &quot;Wider Tech Sector Led S&amp;P 500 to Another Double-Digit Gain&quot;</a> — Mag 7 = 42% of S&amp;P 500's 17.9% return in 2025; tech and communications = 63.1% of total return; excluding those sectors, S&amp;P 500 returned just 6%</p>\\n<p><a id=\\"source-31\\"><strong>31.</strong></a> <a href=\\"https://www.rbcwealthmanagement.com/en-us/insights/us-equity-returns-in-2025-record-breaking-resilience\\" target=\\"_blank\\" rel=\\"noreferrer\\">RBC Wealth Management — &quot;U.S. Equity Returns in 2025: Record-Breaking Resilience&quot; and &quot;The 'Great Narrowing': S&amp;P 500 Concentration&quot;</a> — Seven AI-exposed stocks = over half of S&amp;P 500 gains; top 10 = 41% of weight but ~32% of earnings; cap-weighted index outperformed equal-weight by 32% over 3 years</p>\\n<p><a id=\\"source-32\\"><strong>32.</strong></a> <a href=\\"https://www.goldmansachs.com/insights/articles/the-sp-500-expected-to-rally-12-this-year\\" target=\\"_blank\\" rel=\\"noreferrer\\">Goldman Sachs — &quot;The S&amp;P 500 Is Expected to Rally 12% This Year&quot;</a> — Top tech stocks = 53% of S&amp;P 500 return in 2025; AI capex reaching 75% of cash flows; &quot;elevated valuations, extreme concentration, and strong recent returns rhymes with overextended equity markets during the last century&quot;</p>\\n<p><a id=\\"source-33\\"><strong>33.</strong></a> <a href=\\"https://www.apolloacademy.com/extreme-ai-concentration-in-the-sp-500/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Apollo Academy / Torsten Slok — &quot;Extreme AI Concentration in the S&amp;P 500&quot;</a> — AI bubble bigger than IT bubble in 1990s; average P/E of top 10 around 50; hyperscaler capex as share of GDP exceeds dotcom era; investors &quot;remain overexposed to AI&quot;</p>\\n<p><a id=\\"source-34\\"><strong>34.</strong></a> <a href=\\"https://www.wheresyoured.at/costs/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron / Where's Your Ed At — &quot;This Is How Much Anthropic and Cursor Spend on Amazon Web Services&quot;</a> — $2.66B AWS spend on $2.55B revenue through September 2025; costs scale linearly with revenue; estimates Google Cloud spend at minimum 50% of AWS</p>\\n<p><a id=\\"source-35\\"><strong>35.</strong></a> <a href=\\"https://www.anthropic.com/news/expanding-our-use-of-google-cloud-tpus-and-services\\" target=\\"_blank\\" rel=\\"noreferrer\\">Anthropic — &quot;Expanding Our Use of Google Cloud TPUs and Services&quot;</a> — Deal worth &quot;tens of billions of dollars&quot; for up to one million TPUs; over a gigawatt of capacity expected online in 2026</p>\\n<p><a id=\\"source-36\\"><strong>36.</strong></a> <a href=\\"https://www.aiplanetx.com/p/cloud-spending-hits-anthropic\\" target=\\"_blank\\" rel=\\"noreferrer\\">AI Planet X — &quot;Cloud Spending Hits Anthropic&quot;</a> — Inference costs on Google and Amazon cloud ran 23% over plan; gross margin pushed toward ~40%; ~$5.2B burn in 2025</p>\\n<p><a id=\\"source-37\\"><strong>37.</strong></a> <a href=\\"https://www.pminsights.com/insights/anthropic-approaches-7b-run-rate-in-2025-outpaces-openai\\" target=\\"_blank\\" rel=\\"noreferrer\\">PM Insights — &quot;Anthropic Approaches $7B Run Rate&quot;</a> — Over 1,200 employees by late 2025; plans to triple international workforce and quintuple applied AI team</p>\\n<p><a id=\\"source-38\\"><strong>38.</strong></a> <a href=\\"https://www.levels.fyi/companies/anthropic/salaries\\" target=\\"_blank\\" rel=\\"noreferrer\\">Levels.fyi — Anthropic Salaries</a> — Median yearly total compensation $471,808; highest reported $759,413 for Lead Software Engineer</p>\\n<p><a id=\\"source-39\\"><strong>39.</strong></a> <a href=\\"https://www.datacenterdynamics.com/en/news/anthropic-cloud-spend-expected-to-reach-80bn-through-2029/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Data Center Dynamics — &quot;Anthropic Cloud Spend Expected to Reach $80B Through 2029&quot;</a> — $80B total cloud spend projected through 2029 across AWS, Google, and Microsoft; AWS takes up to 50% of gross profits; Google takes 20-30% of net revenue; $30B Microsoft Azure commitment</p>\\n<p><a id=\\"source-40\\"><strong>40.</strong></a> <a href=\\"https://www.pymnts.com/artificial-intelligence-2/2026/anthropic-set-to-pay-cloud-partners-80-billion-through-2029/\\" target=\\"_blank\\" rel=\\"noreferrer\\">PYMNTS — &quot;Anthropic Set to Pay Cloud Partners $80 Billion Through 2029&quot;</a> — Revenue sharing payouts: ~$1.3M in 2024, ~$360M in 2025, ~$1.9B in 2026, ~$6.4B in 2027 (The Information data)</p>\\n<p><a id=\\"source-41\\"><strong>41.</strong></a> <a href=\\"https://www.fierce-network.com/cloud/what-does-anthropics-50b-data-center-project-mean-hyperscalers\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fierce Network — &quot;What Does Anthropic's $50B Data Center Project Mean for Hyperscalers?&quot;</a> — $50B data center partnership with FluidStack; facilities in Texas and New York expected online throughout 2026</p>\\n<p><a id=\\"source-42\\"><strong>42.</strong></a> <a href=\\"https://sustainabilitymag.com/news/why-anthropic-pledging-offset-ai-energy-costs\\" target=\\"_blank\\" rel=\\"noreferrer\\">Sustainability Magazine — &quot;Why Is Anthropic Pledging to Offset Its AI Energy Costs?&quot;</a> — Committed to covering 100% of grid upgrade costs and electricity price increases for communities hosting its data centers</p>\\n<p><a id=\\"source-43\\"><strong>43.</strong></a> <a href=\\"https://sacra.com/c/anthropic/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Sacra — Anthropic Revenue, Valuation &amp; Funding</a> — Cash burn of $5.6B in 2024, ~$3B in 2025; projects cash flow positive in 2027, break-even in 2028</p>\\n<p><a id=\\"source-44\\"><strong>44.</strong></a> <a href=\\"https://www.axios.com/2026/02/12/anthropic-raises-30b-at-380b-valuation\\" target=\\"_blank\\" rel=\\"noreferrer\\">Axios — &quot;Anthropic Raises $30B at $380B Valuation&quot;</a> — 300,000+ business customers; run-rate revenue of $14B; customers spending $100K+ annually grown 7x in past year</p>\\n<p><a id=\\"source-45\\"><strong>45.</strong></a> <a href=\\"https://builtin.com/articles/top-tech-ipos-2026\\" target=\\"_blank\\" rel=\\"noreferrer\\">Built In — &quot;2026 IPO Watchlist: OpenAI, SpaceX and Other Tech Giants&quot;</a> — Retained Wilson Sonsini (firm behind Google and LinkedIn IPOs) in December 2025 for IPO preparation</p>\\n<p><a id=\\"source-46\\"><strong>46.</strong></a> <a href=\\"https://www.newsweek.com/ai-skeptic-ed-zitron-says-math-on-data-centers-doesnt-add-up-11594219\\" target=\\"_blank\\" rel=\\"noreferrer\\">Newsweek — &quot;AI Skeptic Ed Zitron Says Math on Data Centers Doesn't Add Up&quot;</a> — Claude Code subscribers consume $8-13.50 in compute per $1 paid; $200/month user burns $2,700+ in real costs; &quot;Everyone using Claude Code right now is in an illusory environment&quot;</p>\\n<p><a id=\\"source-47\\"><strong>47.</strong></a> <a href=\\"https://www.mercatus.org/research/data-visualizations/private-sector-job-losses-dwarf-government-gains\\" target=\\"_blank\\" rel=\\"noreferrer\\">Mercatus Center / George Mason University — &quot;Private Sector Job Losses Dwarf Government Gains&quot;</a> — BLS Current Employment Statistics: government employment increased by 590,000 since January 2008 while private sector lost nearly 8 million jobs; government peaked at ~23 million in May 2010</p>\\n<p><a id=\\"source-48\\"><strong>48.</strong></a> <a href=\\"https://hai.stanford.edu/ai-index/2025-ai-index-report\\" target=\\"_blank\\" rel=\\"noreferrer\\">Stanford HAI — The 2025 AI Index Report</a> — Inference cost for GPT-3.5-level performance dropped over 280-fold between November 2022 and October 2024; driven by increasingly capable small models and open-weight alternatives</p>\\n<p><a id=\\"source-49\\"><strong>49.</strong></a> <a href=\\"https://epoch.ai/data-insights/llm-inference-price-trends\\" target=\\"_blank\\" rel=\\"noreferrer\\">Epoch AI — &quot;LLM Inference Prices Have Fallen Rapidly but Unequally Across Tasks&quot;</a> — Price declines ranging from 9x to 900x per year depending on benchmark; fastest trends (900x/year) start after January 2024; median rate increased from 50x to 200x per year when isolating post-2024 data</p>\\n<p><a id=\\"source-50\\"><strong>50.</strong></a> <a href=\\"https://www.bloomberg.com/news/articles/2025-12-21/openai-sees-better-margins-on-business-sales-report-says\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bloomberg — &quot;OpenAI Sees Better Margins on Business Sales, Report Says&quot;</a> — OpenAI compute margin reached 70% as of October 2025, up from 52% at end of 2024 and double the 35% rate in January 2024 (The Information data)</p>\\n<p><a id=\\"source-51\\"><strong>51.</strong></a> <a href=\\"https://lesbarclays.substack.com/p/who-captures-the-value-when-ai-inference\\" target=\\"_blank\\" rel=\\"noreferrer\\">Les Barclays / Substack — &quot;Who Captures the Value When AI Inference Becomes Cheap?&quot;</a> — Cost per query increasing for frontier models even as cost per token declines; models employing test-time scaling consume multiple tokens per problem; at current pace OpenAI's competitive advantage may dissipate</p>\\n<p><a id=\\"source-52\\"><strong>52.</strong></a> <a href=\\"https://foundationcapital.com/nvidias-ai-factory-bet/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Foundation Capital — &quot;NVIDIA's 'AI Factory' Bet&quot;</a> — Reasoning models require 20x more tokens and 150x more compute per query than traditional LLMs; enterprise applications projected to run hundreds of millions of agentic queries per month</p>\\n<p><a id=\\"source-53\\"><strong>53.</strong></a> <a href=\\"https://www.ikangai.com/the-llm-cost-paradox-how-cheaper-ai-models-are-breaking-budgets/\\" target=\\"_blank\\" rel=\\"noreferrer\\">iKangai — &quot;The LLM Cost Paradox: How 'Cheaper' AI Models Are Breaking Budgets&quot;</a> — At maximum reasoning settings, models consume 10,000+ reasoning tokens internally for a 200-token answer; token consumption explosion leaving AI companies scrambling to stay profitable</p>\\n<p><a id=\\"source-54\\"><strong>54.</strong></a> <a href=\\"https://www.arturmarkus.com/the-inference-cost-paradox-why-generative-ai-spending-surged-320-in-2025-despite-per-token-costs-dropping-1000x-and-what-it-means-for-your-ai-budget-in-2026/\\" target=\\"_blank\\" rel=\\"noreferrer\\">AI Unfiltered — &quot;The Inference Cost Paradox&quot;</a> — Enterprise AI spending surged 320% in 2025 despite per-token costs dropping 1,000x; organizations that budgeted for 20-30% increases found themselves scrambling by Q3; Jevons Paradox makes single-number AI budgets &quot;fantasy&quot;</p>\\n<p><a id=\\"source-55\\"><strong>55.</strong></a> <a href=\\"https://www.leaddigital.com/blog/a-token-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">LeadDigital — &quot;A Token Economy&quot;</a> — Inference costs fell 1,000-fold but demand rose 10,000-fold; Jevons Paradox in action; Gartner predicts 40% of enterprise applications will feature AI agents by end of 2026, up from 5% in 2025</p>\\n<p><a id=\\"source-56\\"><strong>56.</strong></a> <a href=\\"https://www.saastr.com/have-ai-gross-margins-really-turned-the-corner-the-real-math-behind-openais-70-compute-margin-and-why-b2b-startups-are-still-running-on-a-treadmill/\\" target=\\"_blank\\" rel=\\"noreferrer\\">SaaStr — &quot;Have AI Gross Margins Really Turned the Corner?&quot;</a> — Anthropic expects gross margin of 50% in 2025 and 77% by 2028; Cursor paying ~$650M/year to Anthropic on ~$500M revenue (negative 30% margin); Bessemer 2025 data shows AI startups averaging 25% gross margins; frontier models getting more expensive, not cheaper</p>\\n<p><a id=\\"source-57\\"><strong>57.</strong></a> <a href=\\"https://ebudget.ca.gov/2025-26/pdf/BudgetSummary/RevenueEstimates.pdf\\" target=\\"_blank\\" rel=\\"noreferrer\\">California 2025-26 Budget Revenue Estimates</a> — 67% of General Fund from personal income tax; capital gains = 16% of total tax liability (25% in boom years)</p>\\n<p><a id=\\"source-58\\"><strong>58.</strong></a> <a href=\\"https://en.wikipedia.org/wiki/2008%E2%80%932012_California_budget_crisis\\" target=\\"_blank\\" rel=\\"noreferrer\\">Wikipedia — &quot;2008-2012 California Budget Crisis&quot;</a> — State revenue dropped from ~$100B to ~$85B during dot-com bust and again during Great Recession</p>\\n<p><a id=\\"source-59\\"><strong>59.</strong></a> <a href=\\"https://www.cbpp.org/research/economy/the-legacy-of-the-great-recession\\" target=\\"_blank\\" rel=\\"noreferrer\\">Center on Budget and Policy Priorities — &quot;Legacy of the Great Recession&quot;</a> — 8.7 million jobs lost in private sector during Great Recession</p>\\n<p><a id=\\"source-60\\"><strong>60.</strong></a> <a href=\\"https://laborcenter.berkeley.edu/\\" target=\\"_blank\\" rel=\\"noreferrer\\">UC Berkeley Labor Center — &quot;California Furloughs 2009&quot;</a> — 193,000 state workers furloughed; 2-3 unpaid days per month; 13.8% effective pay reduction</p>\\n<p><a id=\\"source-61\\"><strong>61.</strong></a> <a href=\\"https://www.calhr.ca.gov/\\" target=\\"_blank\\" rel=\\"noreferrer\\">CalHR — Furlough Program Manual</a> — Furlough hours banked as leave credits; paid out at separation at current base pay rate after COLA increases</p>\\n<p><a id=\\"source-62\\"><strong>62.</strong></a> <a href=\\"https://www.csmonitor.com/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Christian Science Monitor — &quot;Government Jobs: A Recession Refuge?&quot; (2009)</a> — Public sector employment didn't drop during 1991 recession; didn't decline after dot-com bust until 2004; lagged private sector contractions by years</p>\\n<p><a id=\\"source-63\\"><strong>63.</strong></a> <a href=\\"https://www.bls.gov/opub/mlr/2011/\\" target=\\"_blank\\" rel=\\"noreferrer\\">BLS Monthly Labor Review (2011) — &quot;The Recession of 2007-2009&quot;</a> — State and local governments shed 68,000 jobs (0.3% decline) vs. millions in private sector</p>\\n<p><a id=\\"source-64\\"><strong>64.</strong></a> <a href=\\"https://www.governing.com/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Governing — &quot;State Budget Actions in Recessions&quot; (2024)</a> — FY2010: 26 states used layoffs, 22 states used furloughs as primary budget-balancing tool</p>\\n<p><a id=\\"source-65\\"><strong>65.</strong></a> <a href=\\"https://lao.ca.gov/\\" target=\\"_blank\\" rel=\\"noreferrer\\">California Legislative Analyst's Office — 2025-26 Budget Analysis</a> — California has used furloughs in 9 fiscal years since 1992</p>\\n<p><a id=\\"source-66\\"><strong>66.</strong></a> <a href=\\"https://www.ncbi.nlm.nih.gov/pmc/\\" target=\\"_blank\\" rel=\\"noreferrer\\">PMC / Annals of the American Academy of Political and Social Science — &quot;Safety Net Programs in the Great Recession&quot;</a> — Safety net caseloads rose from 276 million to 310 million recipients during the Great Recession; countercyclical demand expanded public sector workload</p>\\n<p><a id=\\"source-67\\"><strong>67.</strong></a> <a href=\\"https://www.bls.gov/news.release/union2.nr0.htm\\" target=\\"_blank\\" rel=\\"noreferrer\\">BLS — &quot;Union Members — 2025&quot;</a> — Public sector union membership rate 32.9% vs. private sector 5.9%; local government workers at 37.8%</p>\\n<hr>\\n<p><em>This analysis reflects the views of PenPublic and is informed by publicly available economic research and reporting. We encourage readers to review the cited sources and draw their own conclusions.</em></p>\\n<p><em><a href=\\"https://penpublic.com\\" target=\\"_blank\\" rel=\\"noreferrer\\">PenPublic</a> — Your guide to public sector careers.</em></p>\\n","frontmatter":{"title":"The AI Bubble Won't Take Your Job — But Its Collapse Might","date":"2026-03-01T12:00:00.000Z","description":"Why the coming AI reckoning makes public sector careers the smartest move you can make","author":"Penny","tags":["AI","Economy","Public Sector Jobs"]},"excerpt":"<h1 id=\\"the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" tabindex=\\"-1\\">The AI Bubble Won't Take Your Job — But Its Collapse Might <a class=\\"header-anchor\\" href=\\"#the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" aria-label=\\"Permalink to &quot;The AI Bubble Won't Take Your Job — But Its Collapse Might&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p><em>Why the coming AI reckoning makes public sector careers the smartest move you can make</em></p>\\n<p><em>By Penny | March 1, 2026 (updated Mar 3, 2026)</em></p>\\n","url":"/blog/2026-03-01_ai-bubble-government-jobs.html"},{"html":"<h1 id=\\"retirement-benefits-at-csu-and-uc-systems\\" tabindex=\\"-1\\">Retirement Benefits at CSU and UC Systems <a class=\\"header-anchor\\" href=\\"#retirement-benefits-at-csu-and-uc-systems\\" aria-label=\\"Permalink to &quot;Retirement Benefits at CSU and UC Systems&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p>The retirement benefits eligibility at CSU and UC systems:</p>\\n<ul>\\n<li>see also:  <a href=\\"https://www.calpers.ca.gov/employers/benefit-programs/health-benefits/health-program-contracting-agencies\\">CalPers Health Agencies</a></li>\\n</ul>\\n<h2 id=\\"csu-system-calpers\\" tabindex=\\"-1\\">CSU System - CalPERS <a class=\\"header-anchor\\" href=\\"#csu-system-calpers\\" aria-label=\\"Permalink to &quot;CSU System - CalPERS&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Not all jobs at CSU automatically qualify for CalPERS.</strong> <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Eligibility depends on the type of appointment and hours worked.</a></p>\\n<h3 id=\\"who-qualifies-for-calpers-at-csu\\" tabindex=\\"-1\\">Who qualifies for CalPERS at CSU: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-calpers-at-csu\\" aria-label=\\"Permalink to &quot;Who qualifies for CalPERS at CSU:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Full-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Full-time appointments that exceed six months</a></p>\\n</li>\\n<li>\\n<p><strong>Half-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Half-time appointments (50 percent or more) for one year or longer</a></p>\\n</li>\\n<li>\\n<p><strong>Temporary faculty</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Temporary faculty are required to enter CalPERS membership commencing with the third consecutive semester</a> at half time or more</p>\\n</li>\\n<li>\\n<p><strong>Part-time/intermittent employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Part time or intermittent employment is covered by CalPERS upon completion of 125 days or 1,000 hours of service within a fiscal year</a></p>\\n</li>\\n</ol>\\n<h3 id=\\"who-is-excluded-from-calpers\\" tabindex=\\"-1\\">Who is excluded from CalPERS: <a class=\\"header-anchor\\" href=\\"#who-is-excluded-from-calpers\\" aria-label=\\"Permalink to &quot;Who is excluded from CalPERS:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Most student employment and instructors appointed to work in extension programs</a></li>\\n<li><a href=\\"https://www.csun.edu/benefits/calpers-retirement-program\\">Special Consultant (class codes 4660, 4760, 8379, and 8380) and Casual Worker (class code 1800)</a></li>\\n<li><a href=\\"https://www.csusm.edu/hr/benefits/retirement/calpers.html\\">Employees excluded from CalPERS Membership are mandatorily enrolled in the Part-Time, Seasonal, Temporary (PST) Retirement Program</a></li>\\n</ul>\\n<h2 id=\\"uc-system-ucrp\\" tabindex=\\"-1\\">UC System - UCRP <a class=\\"header-anchor\\" href=\\"#uc-system-ucrp\\" aria-label=\\"Permalink to &quot;UC System - UCRP&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Similarly, not all UC positions automatically qualify for UCRP.</strong> The UC system has different tiers and options depending on when you were hired.</p>\\n<h3 id=\\"who-qualifies-for-ucrp\\" tabindex=\\"-1\\">Who qualifies for UCRP: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-ucrp\\" aria-label=\\"Permalink to &quot;Who qualifies for UCRP:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Eligible employees are automatically enrolled</strong> in either:</p>\\n<ul>\\n<li>UCRP (traditional pension plan)</li>\\n<li>UC Retirement Choice program (for those hired after July 1, 2016) which offers two options:\\n<ul>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Pension Choice offers a UCRP pension benefit with a supplemental 401(k)-style component for employees who are eligible</a></li>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Savings Choice offers a stand-alone 401(k)-style account</a></li>\\n</ul>\\n</li>\\n</ul>\\n</li>\\n<li>\\n<p><strong>Faculty eligibility</strong>: <a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">In general, you are eligible for the faculty program if you are an academic appointee in one of the following groups</a>:</p>\\n<ul>\\n<li>Ladder-rank faculty and equivalent titles</li>\\n<li>Full-time Lecturers/Senior Lecturers with Security of Employment</li>\\n<li>Librarians in certain units</li>\\n</ul>\\n</li>\\n</ol>\\n<h3 id=\\"vesting-requirements\\" tabindex=\\"-1\\">Vesting Requirements: <a class=\\"header-anchor\\" href=\\"#vesting-requirements\\" aria-label=\\"Permalink to &quot;Vesting Requirements:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p><strong>For CSU/CalPERS</strong>:</p>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Service retirement is a lifetime benefit. Employees can retire as early as age 50 with five years of CalPERS pensionable service credit unless all service was earned on or after January 1, 2013, then employees must be at least age 52 to retire</a></li>\\n<li>Health benefits vesting varies: 5 or 10 years depending on hire date</li>\\n</ul>\\n<p><strong>For UC/UCRP</strong>:</p>\\n<ul>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">Generally, vesting in UCRP requires 5 years UCRP service credit</a></li>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">UC's contributions will vest after one year</a> for Savings Choice participants</li>\\n</ul>\\n<h2 id=\\"key-point\\" tabindex=\\"-1\\">Key Point: <a class=\\"header-anchor\\" href=\\"#key-point\\" aria-label=\\"Permalink to &quot;Key Point:&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>You don't need to be a professor to qualify for retirement benefits at either system. Many types of employees qualify, including staff, administrators, and various faculty classifications. The main factors are:</p>\\n<ul>\\n<li>Type of appointment</li>\\n<li>Hours worked (full-time, half-time, etc.)</li>\\n<li>Length of service</li>\\n<li>Meeting minimum service credit requirements for vesting</li>\\n</ul>\\n","frontmatter":{"title":"Retirement Benefits at CSU and UC Systems","date":"2025-06-25T00:00:00.000Z","description":"Retirement Benefits at CSU and UC Systems","tags":["CSU","UC","CalPers","UCRP"]},"excerpt":"","url":"/blog/2025-06-27_Retirement-Benefits-at-CSU-and-UC-Systems.html"}],"tags":{"CSU":[{"html":"<h1 id=\\"retirement-benefits-at-csu-and-uc-systems\\" tabindex=\\"-1\\">Retirement Benefits at CSU and UC Systems <a class=\\"header-anchor\\" href=\\"#retirement-benefits-at-csu-and-uc-systems\\" aria-label=\\"Permalink to &quot;Retirement Benefits at CSU and UC Systems&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p>The retirement benefits eligibility at CSU and UC systems:</p>\\n<ul>\\n<li>see also:  <a href=\\"https://www.calpers.ca.gov/employers/benefit-programs/health-benefits/health-program-contracting-agencies\\">CalPers Health Agencies</a></li>\\n</ul>\\n<h2 id=\\"csu-system-calpers\\" tabindex=\\"-1\\">CSU System - CalPERS <a class=\\"header-anchor\\" href=\\"#csu-system-calpers\\" aria-label=\\"Permalink to &quot;CSU System - CalPERS&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Not all jobs at CSU automatically qualify for CalPERS.</strong> <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Eligibility depends on the type of appointment and hours worked.</a></p>\\n<h3 id=\\"who-qualifies-for-calpers-at-csu\\" tabindex=\\"-1\\">Who qualifies for CalPERS at CSU: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-calpers-at-csu\\" aria-label=\\"Permalink to &quot;Who qualifies for CalPERS at CSU:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Full-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Full-time appointments that exceed six months</a></p>\\n</li>\\n<li>\\n<p><strong>Half-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Half-time appointments (50 percent or more) for one year or longer</a></p>\\n</li>\\n<li>\\n<p><strong>Temporary faculty</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Temporary faculty are required to enter CalPERS membership commencing with the third consecutive semester</a> at half time or more</p>\\n</li>\\n<li>\\n<p><strong>Part-time/intermittent employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Part time or intermittent employment is covered by CalPERS upon completion of 125 days or 1,000 hours of service within a fiscal year</a></p>\\n</li>\\n</ol>\\n<h3 id=\\"who-is-excluded-from-calpers\\" tabindex=\\"-1\\">Who is excluded from CalPERS: <a class=\\"header-anchor\\" href=\\"#who-is-excluded-from-calpers\\" aria-label=\\"Permalink to &quot;Who is excluded from CalPERS:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Most student employment and instructors appointed to work in extension programs</a></li>\\n<li><a href=\\"https://www.csun.edu/benefits/calpers-retirement-program\\">Special Consultant (class codes 4660, 4760, 8379, and 8380) and Casual Worker (class code 1800)</a></li>\\n<li><a href=\\"https://www.csusm.edu/hr/benefits/retirement/calpers.html\\">Employees excluded from CalPERS Membership are mandatorily enrolled in the Part-Time, Seasonal, Temporary (PST) Retirement Program</a></li>\\n</ul>\\n<h2 id=\\"uc-system-ucrp\\" tabindex=\\"-1\\">UC System - UCRP <a class=\\"header-anchor\\" href=\\"#uc-system-ucrp\\" aria-label=\\"Permalink to &quot;UC System - UCRP&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Similarly, not all UC positions automatically qualify for UCRP.</strong> The UC system has different tiers and options depending on when you were hired.</p>\\n<h3 id=\\"who-qualifies-for-ucrp\\" tabindex=\\"-1\\">Who qualifies for UCRP: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-ucrp\\" aria-label=\\"Permalink to &quot;Who qualifies for UCRP:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Eligible employees are automatically enrolled</strong> in either:</p>\\n<ul>\\n<li>UCRP (traditional pension plan)</li>\\n<li>UC Retirement Choice program (for those hired after July 1, 2016) which offers two options:\\n<ul>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Pension Choice offers a UCRP pension benefit with a supplemental 401(k)-style component for employees who are eligible</a></li>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Savings Choice offers a stand-alone 401(k)-style account</a></li>\\n</ul>\\n</li>\\n</ul>\\n</li>\\n<li>\\n<p><strong>Faculty eligibility</strong>: <a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">In general, you are eligible for the faculty program if you are an academic appointee in one of the following groups</a>:</p>\\n<ul>\\n<li>Ladder-rank faculty and equivalent titles</li>\\n<li>Full-time Lecturers/Senior Lecturers with Security of Employment</li>\\n<li>Librarians in certain units</li>\\n</ul>\\n</li>\\n</ol>\\n<h3 id=\\"vesting-requirements\\" tabindex=\\"-1\\">Vesting Requirements: <a class=\\"header-anchor\\" href=\\"#vesting-requirements\\" aria-label=\\"Permalink to &quot;Vesting Requirements:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p><strong>For CSU/CalPERS</strong>:</p>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Service retirement is a lifetime benefit. Employees can retire as early as age 50 with five years of CalPERS pensionable service credit unless all service was earned on or after January 1, 2013, then employees must be at least age 52 to retire</a></li>\\n<li>Health benefits vesting varies: 5 or 10 years depending on hire date</li>\\n</ul>\\n<p><strong>For UC/UCRP</strong>:</p>\\n<ul>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">Generally, vesting in UCRP requires 5 years UCRP service credit</a></li>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">UC's contributions will vest after one year</a> for Savings Choice participants</li>\\n</ul>\\n<h2 id=\\"key-point\\" tabindex=\\"-1\\">Key Point: <a class=\\"header-anchor\\" href=\\"#key-point\\" aria-label=\\"Permalink to &quot;Key Point:&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>You don't need to be a professor to qualify for retirement benefits at either system. Many types of employees qualify, including staff, administrators, and various faculty classifications. The main factors are:</p>\\n<ul>\\n<li>Type of appointment</li>\\n<li>Hours worked (full-time, half-time, etc.)</li>\\n<li>Length of service</li>\\n<li>Meeting minimum service credit requirements for vesting</li>\\n</ul>\\n","frontmatter":{"title":"Retirement Benefits at CSU and UC Systems","date":"2025-06-25T00:00:00.000Z","description":"Retirement Benefits at CSU and UC Systems","tags":["CSU","UC","CalPers","UCRP"]},"excerpt":"","url":"/blog/2025-06-27_Retirement-Benefits-at-CSU-and-UC-Systems.html"}],"UC":[{"html":"<h1 id=\\"retirement-benefits-at-csu-and-uc-systems\\" tabindex=\\"-1\\">Retirement Benefits at CSU and UC Systems <a class=\\"header-anchor\\" href=\\"#retirement-benefits-at-csu-and-uc-systems\\" aria-label=\\"Permalink to &quot;Retirement Benefits at CSU and UC Systems&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p>The retirement benefits eligibility at CSU and UC systems:</p>\\n<ul>\\n<li>see also:  <a href=\\"https://www.calpers.ca.gov/employers/benefit-programs/health-benefits/health-program-contracting-agencies\\">CalPers Health Agencies</a></li>\\n</ul>\\n<h2 id=\\"csu-system-calpers\\" tabindex=\\"-1\\">CSU System - CalPERS <a class=\\"header-anchor\\" href=\\"#csu-system-calpers\\" aria-label=\\"Permalink to &quot;CSU System - CalPERS&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Not all jobs at CSU automatically qualify for CalPERS.</strong> <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Eligibility depends on the type of appointment and hours worked.</a></p>\\n<h3 id=\\"who-qualifies-for-calpers-at-csu\\" tabindex=\\"-1\\">Who qualifies for CalPERS at CSU: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-calpers-at-csu\\" aria-label=\\"Permalink to &quot;Who qualifies for CalPERS at CSU:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Full-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Full-time appointments that exceed six months</a></p>\\n</li>\\n<li>\\n<p><strong>Half-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Half-time appointments (50 percent or more) for one year or longer</a></p>\\n</li>\\n<li>\\n<p><strong>Temporary faculty</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Temporary faculty are required to enter CalPERS membership commencing with the third consecutive semester</a> at half time or more</p>\\n</li>\\n<li>\\n<p><strong>Part-time/intermittent employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Part time or intermittent employment is covered by CalPERS upon completion of 125 days or 1,000 hours of service within a fiscal year</a></p>\\n</li>\\n</ol>\\n<h3 id=\\"who-is-excluded-from-calpers\\" tabindex=\\"-1\\">Who is excluded from CalPERS: <a class=\\"header-anchor\\" href=\\"#who-is-excluded-from-calpers\\" aria-label=\\"Permalink to &quot;Who is excluded from CalPERS:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Most student employment and instructors appointed to work in extension programs</a></li>\\n<li><a href=\\"https://www.csun.edu/benefits/calpers-retirement-program\\">Special Consultant (class codes 4660, 4760, 8379, and 8380) and Casual Worker (class code 1800)</a></li>\\n<li><a href=\\"https://www.csusm.edu/hr/benefits/retirement/calpers.html\\">Employees excluded from CalPERS Membership are mandatorily enrolled in the Part-Time, Seasonal, Temporary (PST) Retirement Program</a></li>\\n</ul>\\n<h2 id=\\"uc-system-ucrp\\" tabindex=\\"-1\\">UC System - UCRP <a class=\\"header-anchor\\" href=\\"#uc-system-ucrp\\" aria-label=\\"Permalink to &quot;UC System - UCRP&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Similarly, not all UC positions automatically qualify for UCRP.</strong> The UC system has different tiers and options depending on when you were hired.</p>\\n<h3 id=\\"who-qualifies-for-ucrp\\" tabindex=\\"-1\\">Who qualifies for UCRP: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-ucrp\\" aria-label=\\"Permalink to &quot;Who qualifies for UCRP:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Eligible employees are automatically enrolled</strong> in either:</p>\\n<ul>\\n<li>UCRP (traditional pension plan)</li>\\n<li>UC Retirement Choice program (for those hired after July 1, 2016) which offers two options:\\n<ul>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Pension Choice offers a UCRP pension benefit with a supplemental 401(k)-style component for employees who are eligible</a></li>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Savings Choice offers a stand-alone 401(k)-style account</a></li>\\n</ul>\\n</li>\\n</ul>\\n</li>\\n<li>\\n<p><strong>Faculty eligibility</strong>: <a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">In general, you are eligible for the faculty program if you are an academic appointee in one of the following groups</a>:</p>\\n<ul>\\n<li>Ladder-rank faculty and equivalent titles</li>\\n<li>Full-time Lecturers/Senior Lecturers with Security of Employment</li>\\n<li>Librarians in certain units</li>\\n</ul>\\n</li>\\n</ol>\\n<h3 id=\\"vesting-requirements\\" tabindex=\\"-1\\">Vesting Requirements: <a class=\\"header-anchor\\" href=\\"#vesting-requirements\\" aria-label=\\"Permalink to &quot;Vesting Requirements:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p><strong>For CSU/CalPERS</strong>:</p>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Service retirement is a lifetime benefit. Employees can retire as early as age 50 with five years of CalPERS pensionable service credit unless all service was earned on or after January 1, 2013, then employees must be at least age 52 to retire</a></li>\\n<li>Health benefits vesting varies: 5 or 10 years depending on hire date</li>\\n</ul>\\n<p><strong>For UC/UCRP</strong>:</p>\\n<ul>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">Generally, vesting in UCRP requires 5 years UCRP service credit</a></li>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">UC's contributions will vest after one year</a> for Savings Choice participants</li>\\n</ul>\\n<h2 id=\\"key-point\\" tabindex=\\"-1\\">Key Point: <a class=\\"header-anchor\\" href=\\"#key-point\\" aria-label=\\"Permalink to &quot;Key Point:&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>You don't need to be a professor to qualify for retirement benefits at either system. Many types of employees qualify, including staff, administrators, and various faculty classifications. The main factors are:</p>\\n<ul>\\n<li>Type of appointment</li>\\n<li>Hours worked (full-time, half-time, etc.)</li>\\n<li>Length of service</li>\\n<li>Meeting minimum service credit requirements for vesting</li>\\n</ul>\\n","frontmatter":{"title":"Retirement Benefits at CSU and UC Systems","date":"2025-06-25T00:00:00.000Z","description":"Retirement Benefits at CSU and UC Systems","tags":["CSU","UC","CalPers","UCRP"]},"excerpt":"","url":"/blog/2025-06-27_Retirement-Benefits-at-CSU-and-UC-Systems.html"}],"CalPers":[{"html":"<h1 id=\\"retirement-benefits-at-csu-and-uc-systems\\" tabindex=\\"-1\\">Retirement Benefits at CSU and UC Systems <a class=\\"header-anchor\\" href=\\"#retirement-benefits-at-csu-and-uc-systems\\" aria-label=\\"Permalink to &quot;Retirement Benefits at CSU and UC Systems&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p>The retirement benefits eligibility at CSU and UC systems:</p>\\n<ul>\\n<li>see also:  <a href=\\"https://www.calpers.ca.gov/employers/benefit-programs/health-benefits/health-program-contracting-agencies\\">CalPers Health Agencies</a></li>\\n</ul>\\n<h2 id=\\"csu-system-calpers\\" tabindex=\\"-1\\">CSU System - CalPERS <a class=\\"header-anchor\\" href=\\"#csu-system-calpers\\" aria-label=\\"Permalink to &quot;CSU System - CalPERS&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Not all jobs at CSU automatically qualify for CalPERS.</strong> <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Eligibility depends on the type of appointment and hours worked.</a></p>\\n<h3 id=\\"who-qualifies-for-calpers-at-csu\\" tabindex=\\"-1\\">Who qualifies for CalPERS at CSU: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-calpers-at-csu\\" aria-label=\\"Permalink to &quot;Who qualifies for CalPERS at CSU:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Full-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Full-time appointments that exceed six months</a></p>\\n</li>\\n<li>\\n<p><strong>Half-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Half-time appointments (50 percent or more) for one year or longer</a></p>\\n</li>\\n<li>\\n<p><strong>Temporary faculty</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Temporary faculty are required to enter CalPERS membership commencing with the third consecutive semester</a> at half time or more</p>\\n</li>\\n<li>\\n<p><strong>Part-time/intermittent employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Part time or intermittent employment is covered by CalPERS upon completion of 125 days or 1,000 hours of service within a fiscal year</a></p>\\n</li>\\n</ol>\\n<h3 id=\\"who-is-excluded-from-calpers\\" tabindex=\\"-1\\">Who is excluded from CalPERS: <a class=\\"header-anchor\\" href=\\"#who-is-excluded-from-calpers\\" aria-label=\\"Permalink to &quot;Who is excluded from CalPERS:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Most student employment and instructors appointed to work in extension programs</a></li>\\n<li><a href=\\"https://www.csun.edu/benefits/calpers-retirement-program\\">Special Consultant (class codes 4660, 4760, 8379, and 8380) and Casual Worker (class code 1800)</a></li>\\n<li><a href=\\"https://www.csusm.edu/hr/benefits/retirement/calpers.html\\">Employees excluded from CalPERS Membership are mandatorily enrolled in the Part-Time, Seasonal, Temporary (PST) Retirement Program</a></li>\\n</ul>\\n<h2 id=\\"uc-system-ucrp\\" tabindex=\\"-1\\">UC System - UCRP <a class=\\"header-anchor\\" href=\\"#uc-system-ucrp\\" aria-label=\\"Permalink to &quot;UC System - UCRP&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Similarly, not all UC positions automatically qualify for UCRP.</strong> The UC system has different tiers and options depending on when you were hired.</p>\\n<h3 id=\\"who-qualifies-for-ucrp\\" tabindex=\\"-1\\">Who qualifies for UCRP: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-ucrp\\" aria-label=\\"Permalink to &quot;Who qualifies for UCRP:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Eligible employees are automatically enrolled</strong> in either:</p>\\n<ul>\\n<li>UCRP (traditional pension plan)</li>\\n<li>UC Retirement Choice program (for those hired after July 1, 2016) which offers two options:\\n<ul>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Pension Choice offers a UCRP pension benefit with a supplemental 401(k)-style component for employees who are eligible</a></li>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Savings Choice offers a stand-alone 401(k)-style account</a></li>\\n</ul>\\n</li>\\n</ul>\\n</li>\\n<li>\\n<p><strong>Faculty eligibility</strong>: <a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">In general, you are eligible for the faculty program if you are an academic appointee in one of the following groups</a>:</p>\\n<ul>\\n<li>Ladder-rank faculty and equivalent titles</li>\\n<li>Full-time Lecturers/Senior Lecturers with Security of Employment</li>\\n<li>Librarians in certain units</li>\\n</ul>\\n</li>\\n</ol>\\n<h3 id=\\"vesting-requirements\\" tabindex=\\"-1\\">Vesting Requirements: <a class=\\"header-anchor\\" href=\\"#vesting-requirements\\" aria-label=\\"Permalink to &quot;Vesting Requirements:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p><strong>For CSU/CalPERS</strong>:</p>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Service retirement is a lifetime benefit. Employees can retire as early as age 50 with five years of CalPERS pensionable service credit unless all service was earned on or after January 1, 2013, then employees must be at least age 52 to retire</a></li>\\n<li>Health benefits vesting varies: 5 or 10 years depending on hire date</li>\\n</ul>\\n<p><strong>For UC/UCRP</strong>:</p>\\n<ul>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">Generally, vesting in UCRP requires 5 years UCRP service credit</a></li>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">UC's contributions will vest after one year</a> for Savings Choice participants</li>\\n</ul>\\n<h2 id=\\"key-point\\" tabindex=\\"-1\\">Key Point: <a class=\\"header-anchor\\" href=\\"#key-point\\" aria-label=\\"Permalink to &quot;Key Point:&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>You don't need to be a professor to qualify for retirement benefits at either system. Many types of employees qualify, including staff, administrators, and various faculty classifications. The main factors are:</p>\\n<ul>\\n<li>Type of appointment</li>\\n<li>Hours worked (full-time, half-time, etc.)</li>\\n<li>Length of service</li>\\n<li>Meeting minimum service credit requirements for vesting</li>\\n</ul>\\n","frontmatter":{"title":"Retirement Benefits at CSU and UC Systems","date":"2025-06-25T00:00:00.000Z","description":"Retirement Benefits at CSU and UC Systems","tags":["CSU","UC","CalPers","UCRP"]},"excerpt":"","url":"/blog/2025-06-27_Retirement-Benefits-at-CSU-and-UC-Systems.html"}],"UCRP":[{"html":"<h1 id=\\"retirement-benefits-at-csu-and-uc-systems\\" tabindex=\\"-1\\">Retirement Benefits at CSU and UC Systems <a class=\\"header-anchor\\" href=\\"#retirement-benefits-at-csu-and-uc-systems\\" aria-label=\\"Permalink to &quot;Retirement Benefits at CSU and UC Systems&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p>The retirement benefits eligibility at CSU and UC systems:</p>\\n<ul>\\n<li>see also:  <a href=\\"https://www.calpers.ca.gov/employers/benefit-programs/health-benefits/health-program-contracting-agencies\\">CalPers Health Agencies</a></li>\\n</ul>\\n<h2 id=\\"csu-system-calpers\\" tabindex=\\"-1\\">CSU System - CalPERS <a class=\\"header-anchor\\" href=\\"#csu-system-calpers\\" aria-label=\\"Permalink to &quot;CSU System - CalPERS&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Not all jobs at CSU automatically qualify for CalPERS.</strong> <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Eligibility depends on the type of appointment and hours worked.</a></p>\\n<h3 id=\\"who-qualifies-for-calpers-at-csu\\" tabindex=\\"-1\\">Who qualifies for CalPERS at CSU: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-calpers-at-csu\\" aria-label=\\"Permalink to &quot;Who qualifies for CalPERS at CSU:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Full-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Full-time appointments that exceed six months</a></p>\\n</li>\\n<li>\\n<p><strong>Half-time employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Half-time appointments (50 percent or more) for one year or longer</a></p>\\n</li>\\n<li>\\n<p><strong>Temporary faculty</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Temporary faculty are required to enter CalPERS membership commencing with the third consecutive semester</a> at half time or more</p>\\n</li>\\n<li>\\n<p><strong>Part-time/intermittent employees</strong>: <a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Part time or intermittent employment is covered by CalPERS upon completion of 125 days or 1,000 hours of service within a fiscal year</a></p>\\n</li>\\n</ol>\\n<h3 id=\\"who-is-excluded-from-calpers\\" tabindex=\\"-1\\">Who is excluded from CalPERS: <a class=\\"header-anchor\\" href=\\"#who-is-excluded-from-calpers\\" aria-label=\\"Permalink to &quot;Who is excluded from CalPERS:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Most student employment and instructors appointed to work in extension programs</a></li>\\n<li><a href=\\"https://www.csun.edu/benefits/calpers-retirement-program\\">Special Consultant (class codes 4660, 4760, 8379, and 8380) and Casual Worker (class code 1800)</a></li>\\n<li><a href=\\"https://www.csusm.edu/hr/benefits/retirement/calpers.html\\">Employees excluded from CalPERS Membership are mandatorily enrolled in the Part-Time, Seasonal, Temporary (PST) Retirement Program</a></li>\\n</ul>\\n<h2 id=\\"uc-system-ucrp\\" tabindex=\\"-1\\">UC System - UCRP <a class=\\"header-anchor\\" href=\\"#uc-system-ucrp\\" aria-label=\\"Permalink to &quot;UC System - UCRP&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Similarly, not all UC positions automatically qualify for UCRP.</strong> The UC system has different tiers and options depending on when you were hired.</p>\\n<h3 id=\\"who-qualifies-for-ucrp\\" tabindex=\\"-1\\">Who qualifies for UCRP: <a class=\\"header-anchor\\" href=\\"#who-qualifies-for-ucrp\\" aria-label=\\"Permalink to &quot;Who qualifies for UCRP:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<ol>\\n<li>\\n<p><strong>Eligible employees are automatically enrolled</strong> in either:</p>\\n<ul>\\n<li>UCRP (traditional pension plan)</li>\\n<li>UC Retirement Choice program (for those hired after July 1, 2016) which offers two options:\\n<ul>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Pension Choice offers a UCRP pension benefit with a supplemental 401(k)-style component for employees who are eligible</a></li>\\n<li><a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">Savings Choice offers a stand-alone 401(k)-style account</a></li>\\n</ul>\\n</li>\\n</ul>\\n</li>\\n<li>\\n<p><strong>Faculty eligibility</strong>: <a href=\\"https://ucnet.universityofcalifornia.edu/benefits/retirement/uc-retirement-choice-program/\\">In general, you are eligible for the faculty program if you are an academic appointee in one of the following groups</a>:</p>\\n<ul>\\n<li>Ladder-rank faculty and equivalent titles</li>\\n<li>Full-time Lecturers/Senior Lecturers with Security of Employment</li>\\n<li>Librarians in certain units</li>\\n</ul>\\n</li>\\n</ol>\\n<h3 id=\\"vesting-requirements\\" tabindex=\\"-1\\">Vesting Requirements: <a class=\\"header-anchor\\" href=\\"#vesting-requirements\\" aria-label=\\"Permalink to &quot;Vesting Requirements:&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p><strong>For CSU/CalPERS</strong>:</p>\\n<ul>\\n<li><a href=\\"https://hr.sfsu.edu/calpers-retirement-benefits\\">Service retirement is a lifetime benefit. Employees can retire as early as age 50 with five years of CalPERS pensionable service credit unless all service was earned on or after January 1, 2013, then employees must be at least age 52 to retire</a></li>\\n<li>Health benefits vesting varies: 5 or 10 years depending on hire date</li>\\n</ul>\\n<p><strong>For UC/UCRP</strong>:</p>\\n<ul>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">Generally, vesting in UCRP requires 5 years UCRP service credit</a></li>\\n<li><a href=\\"https://shr.ucsc.edu/benefits/retirement-faq.html\\">UC's contributions will vest after one year</a> for Savings Choice participants</li>\\n</ul>\\n<h2 id=\\"key-point\\" tabindex=\\"-1\\">Key Point: <a class=\\"header-anchor\\" href=\\"#key-point\\" aria-label=\\"Permalink to &quot;Key Point:&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>You don't need to be a professor to qualify for retirement benefits at either system. Many types of employees qualify, including staff, administrators, and various faculty classifications. The main factors are:</p>\\n<ul>\\n<li>Type of appointment</li>\\n<li>Hours worked (full-time, half-time, etc.)</li>\\n<li>Length of service</li>\\n<li>Meeting minimum service credit requirements for vesting</li>\\n</ul>\\n","frontmatter":{"title":"Retirement Benefits at CSU and UC Systems","date":"2025-06-25T00:00:00.000Z","description":"Retirement Benefits at CSU and UC Systems","tags":["CSU","UC","CalPers","UCRP"]},"excerpt":"","url":"/blog/2025-06-27_Retirement-Benefits-at-CSU-and-UC-Systems.html"}],"AI":[{"html":"<h1 id=\\"the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" tabindex=\\"-1\\">The AI Bubble Won't Take Your Job — But Its Collapse Might <a class=\\"header-anchor\\" href=\\"#the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" aria-label=\\"Permalink to &quot;The AI Bubble Won't Take Your Job — But Its Collapse Might&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p><em>Why the coming AI reckoning makes public sector careers the smartest move you can make</em></p>\\n<p><em>By Penny | March 1, 2026 (updated Mar 3, 2026)</em></p>\\n<hr>\\n<h2 id=\\"key-takeaways\\" tabindex=\\"-1\\">Key Takeaways <a class=\\"header-anchor\\" href=\\"#key-takeaways\\" aria-label=\\"Permalink to &quot;Key Takeaways&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Thesis: The AI bubble will collapse — and when it does, the layoffs won't be because AI took your job. They'll be because of the recession it causes.</strong></p>\\n<ul>\\n<li><strong><a href=\\"#the-real-threat-ai-layoffs-that-aren-t-about-ai\\">The real threat: AI layoffs that aren't about AI</a></strong> — the bubble's collapse will tank the economy and trigger mass layoffs misattributed to &quot;AI disruption&quot;</li>\\n<li><strong><a href=\\"#the-ai-investment-that-isn-t-working\\">AI doesn't work for most businesses</a></strong> — MIT found a 95% failure rate for enterprise AI projects <a href=\\"#source-1\\">[1]</a>, and only 14% of CFOs report measurable ROI <a href=\\"#source-4\\">[4]</a>\\n<ul>\\n<li>IBM found AI initiatives return 5.9% ROI on a 10% capital investment — companies are losing money <a href=\\"#source-3\\">[3]</a></li>\\n<li>Forrester predicts 25% of planned 2026 AI spending will be deferred to 2027 <a href=\\"#source-2\\">[2]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\">Goldman Sachs says AI contributed &quot;basically zero&quot; to U.S. GDP growth</a></strong> — most AI spending flows to Taiwan and South Korea for imported chips <a href=\\"#source-7\\">[7]</a> <a href=\\"#source-8\\">[8]</a>\\n<ul>\\n<li>Only 0.2% of the U.S. economy's 2.2% growth in 2025 came from AI investment <a href=\\"#source-10\\">[10]</a></li>\\n<li>Tech companies plan to spend $700B on AI in 2026; J.P. Morgan says AI needs $600B/year in revenue just to break even <a href=\\"#source-10\\">[10]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-stock-market-is-built-on-spending-not-returns\\">The stock market rally is built on AI spending, not AI returns</a></strong> — AI stocks account for 75% of all S&amp;P 500 returns since ChatGPT launched <a href=\\"#source-29\\">[29]</a>, but generate only 32% of index earnings <a href=\\"#source-31\\">[31]</a>\\n<ul>\\n<li>Strip out tech and communications, and the S&amp;P 500 returned just 6% in 2025 <a href=\\"#source-30\\">[30]</a></li>\\n<li>Apollo's chief economist says the AI bubble is now bigger than the 1990s IT bubble <a href=\\"#source-33\\">[33]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-110-billion-question\\">OpenAI's $110B round is a house of cards</a></strong> — Amazon invests $50B, OpenAI commits to spending $100B on AWS; money just circulates <a href=\\"#source-13\\">[13]</a>\\n<ul>\\n<li>OpenAI spent $9B to lose $5B in 2025 <a href=\\"#source-17\\">[17]</a></li>\\n<li>AI-related debt issuance crossed $200B, representing 30% of all USD credit supply <a href=\\"#source-11\\">[11]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-subsidized-illusion\\">AI subscriptions are subsidized below true cost</a></strong> — your $20/mo plan likely costs $1,000-2,000+/mo to serve <a href=\\"#source-18\\">[18]</a>\\n<ul>\\n<li>Even the $200/mo ChatGPT Pro loses money on power users (per Sam Altman) <a href=\\"#source-19\\">[19]</a></li>\\n<li>As Ed Zitron documents, every level of the AI value chain is unprofitable <a href=\\"#source-17\\">[17]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#but-what-about-anthropic\\">Even &quot;responsible&quot; Anthropic can't make the math work</a></strong> — its AWS bill alone consumed 100% of revenue through September 2025 <a href=\\"#source-34\\">[34]</a>, before paying for Google Cloud, salaries, data centers, or anything else\\n<ul>\\n<li>Claude Code subscribers consume $8-13.50 in compute for every $1 they pay <a href=\\"#source-46\\">[46]</a></li>\\n<li>Anthropic projects $80B in total cloud spend through 2029 <a href=\\"#source-39\\">[39]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#but-inference-costs-are-dropping-exponentially\\">Falling inference costs won't save them</a></strong> — the 280x cost drop is for GPT-3.5-level performance, a model nobody wants anymore <a href=\\"#source-48\\">[48]</a>; reasoning models consume 20x more compute per query <a href=\\"#source-52\\">[52]</a>\\n<ul>\\n<li>Jevons Paradox: inference costs fell 1,000x but demand rose 10,000x — total enterprise AI spending surged 320% in 2025 <a href=\\"#source-55\\">[55]</a></li>\\n<li>Cursor paid ~$650M/year to Anthropic while earning ~$500M — a negative 30% gross margin <a href=\\"#source-54\\">[54]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-k-shaped-economy-a-house-of-cards\\">The economy is a K-shape propped up by the wealthy</a></strong> — top 10% accounts for 50% of all consumer spending, driven by inflated stock portfolios <a href=\\"#source-21\\">[21]</a>\\n<ul>\\n<li>Bottom 80% hasn't outpaced inflation in 6 years <a href=\\"#source-23\\">[23]</a></li>\\n<li>$180B in consumer spending is driven by AI-inflated stock wealth effect alone <a href=\\"#source-27\\">[27]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#why-public-sector-careers-are-the-smart-play\\">Public sector careers are the smart play</a></strong> — California's budget will take a hit, but public sector workers get furloughs, not layoffs — and keep their pensions, health insurance, and union protection through every recession <a href=\\"#source-57\\">[57]</a> <a href=\\"#source-60\\">[60]</a> <a href=\\"#source-66\\">[66]</a></li>\\n</ul>\\n<hr>\\n<h2 id=\\"the-real-threat-ai-layoffs-that-aren-t-about-ai\\" tabindex=\\"-1\\">The Real Threat: AI Layoffs That Aren't About AI <a class=\\"header-anchor\\" href=\\"#the-real-threat-ai-layoffs-that-aren-t-about-ai\\" aria-label=\\"Permalink to &quot;The Real Threat: AI Layoffs That Aren't About AI&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's the thesis that ties it all together, and the reason you should be thinking about career stability right now.</p>\\n<p><strong>AI will cause mass layoffs — not because the technology replaced workers, but because the financial bubble built around it will collapse and drag the broader economy down.</strong></p>\\n<p>The causal chain looks like this:</p>\\n<ol>\\n<li>AI spending inflates tech valuations and GDP numbers</li>\\n<li>Inflated stocks create a wealth effect that drives consumer spending among the top 10%</li>\\n<li>The bottom 80% is already stretched thin, running on debt</li>\\n<li>Enterprise AI fails to deliver ROI — 95% of projects show no measurable returns</li>\\n<li>Companies begin cutting AI budgets (already happening — Forrester projects 25% deferrals)</li>\\n<li>Tech stocks correct as the narrative shifts</li>\\n<li>The wealth effect reverses — wealthy consumers pull back</li>\\n<li>Nobody else can pick up the slack because they were already tapped out</li>\\n<li>GDP contracts from multiple directions simultaneously</li>\\n<li>Companies execute mass layoffs to protect margins</li>\\n</ol>\\n<p>And here's the cruelest irony: <strong>the headlines will say &quot;AI replaced these workers.&quot;</strong> CEOs will frame layoffs as &quot;AI-driven transformation&quot; because it sounds strategic. Media will repeat the narrative because it's a clean story. But the reality is that the jobs disappeared because the financial infrastructure collapsed, not because a chatbot learned to do them.</p>\\n<p>We've seen this exact pattern before. Dot-com bust workers didn't lose jobs because websites replaced them — they lost jobs because companies had hired against inflated revenue projections that evaporated overnight. The 2008 financial crisis didn't eliminate construction jobs because buildings got smarter — it eliminated them because the financing structure collapsed.</p>\\n<hr>\\n<h2 id=\\"the-ai-investment-that-isn-t-working\\" tabindex=\\"-1\\">The AI Investment That Isn't Working <a class=\\"header-anchor\\" href=\\"#the-ai-investment-that-isn-t-working\\" aria-label=\\"Permalink to &quot;The AI Investment That Isn't Working&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Let's start with the most inconvenient fact in technology right now: <strong>AI doesn't work for most businesses.</strong></p>\\n<p>A landmark study from MIT found a staggering <strong>95% failure rate for enterprise generative AI projects</strong>, defined as not having shown measurable financial returns within six months <a href=\\"#source-1\\">[1]</a>. This isn't a fringe finding. Forrester Research reports that only 15% of AI decision-makers saw a positive impact on profitability, and predicts that enterprises will <strong>defer 25% of planned 2026 AI spending into 2027</strong> because the returns simply aren't there <a href=\\"#source-2\\">[2]</a>.</p>\\n<p>IBM's own research found that enterprise-wide AI initiatives achieved an <strong>ROI of just 5.9% despite requiring a 10% capital investment</strong> — meaning companies are literally losing money on AI <a href=\\"#source-3\\">[3]</a>. And only 14% of CFOs report measurable ROI from AI to date <a href=\\"#source-4\\">[4]</a>. Recent enterprise surveys confirm that <strong>90-95% of organizations are seeing little to no measurable financial return</strong> on their AI investments <a href=\\"#source-5\\">[5]</a>.</p>\\n<p>If you work in the public sector and your agency rolled out Microsoft Copilot, ask yourself: does anyone actually use it? The answer, overwhelmingly across both public and private sectors, is no. Nearly 70% of Fortune 500 companies are paying for Copilot, but the productivity benefits are so diffuse they don't move the needle on actual business results <a href=\\"#source-6\\">[6]</a>.</p>\\n<hr>\\n<h2 id=\\"goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\" tabindex=\\"-1\\">Goldman Sachs Says AI Contributed &quot;Basically Zero&quot; to the Economy <a class=\\"header-anchor\\" href=\\"#goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\" aria-label=\\"Permalink to &quot;Goldman Sachs Says AI Contributed &quot;Basically Zero&quot; to the Economy&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>In late February 2026, Goldman Sachs Chief Economist Jan Hatzius dropped a bombshell in an interview with the Atlantic Council. AI investment spending, he said, has had <strong>&quot;basically zero&quot;</strong> contribution to U.S. GDP growth <a href=\\"#source-7\\">[7]</a>.</p>\\n<p>&quot;We don't actually view AI investment as strongly growth positive,&quot; Hatzius stated. &quot;I think there's a lot of misreporting, actually, of the impact AI investment had on U.S. GDP growth in 2025, and it's much smaller than is often perceived.&quot; <a href=\\"#source-7\\">[7]</a></p>\\n<p>The reason is straightforward: most AI equipment is imported. The chips come from Taiwan. The hardware comes from South Korea. As Hatzius put it: &quot;A lot of the AI investment that we're seeing in the U.S. adds to Taiwanese GDP, and it adds to Korean GDP but not really that much to U.S. GDP.&quot; <a href=\\"#source-8\\">[8]</a></p>\\n<p>His colleague Joseph Briggs made the same case to the Washington Post, calling the AI-as-growth-engine story &quot;very intuitive&quot; but ultimately misleading — it &quot;maybe prevented or limited the need to actually dig deeper into what was happening.&quot; <a href=\\"#source-9\\">[9]</a></p>\\n<p>Of the U.S. economy's 2.2% growth in 2025, analyst Joseph Politano calculates that only <strong>0.2% was attributable to AI investment</strong> after accounting for imports <a href=\\"#source-10\\">[10]</a>. Meanwhile, tech companies are expected to spend <strong>$700 billion on AI infrastructure in 2026</strong> <a href=\\"#source-10\\">[10]</a>. J.P. Morgan has calculated that AI would need to generate over <strong>$600 billion in annual revenue</strong> just to achieve a 10% return on infrastructure expenditures <a href=\\"#source-10\\">[10]</a>. Current total AI industry revenue is a fraction of that.</p>\\n<p>Deutsche Bank has warned that the <strong>U.S. would be close to recession without tech-related spending</strong> <a href=\\"#source-11\\">[11]</a> — which sounds like AI is saving the economy until you realize the money mostly flows overseas. An analysis from MRB Partners found that after adjusting for high-tech imports, AI's net contribution to GDP growth was only <strong>20-25%</strong>, not the 40-92% figures that dominated headlines <a href=\\"#source-12\\">[12]</a>.</p>\\n<hr>\\n<h2 id=\\"the-stock-market-is-built-on-spending-not-returns\\" tabindex=\\"-1\\">The Stock Market Is Built on Spending, Not Returns <a class=\\"header-anchor\\" href=\\"#the-stock-market-is-built-on-spending-not-returns\\" aria-label=\\"Permalink to &quot;The Stock Market Is Built on Spending, Not Returns&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's the critical distinction most analysts gloss over: <strong>AI is driving stock prices. It is not driving profits.</strong></p>\\n<p>Since ChatGPT launched in November 2022, AI-related stocks have accounted for <strong>75% of all S&amp;P 500 returns, 80% of earnings growth, and 90% of capital spending growth</strong>, according to J.P. Morgan Asset Management's Michael Cembalest <a href=\\"#source-29\\">[29]</a>. In 2025 alone, the Magnificent Seven were responsible for <strong>42% of the S&amp;P 500's 17.9% return</strong> for the year <a href=\\"#source-30\\">[30]</a>. If you strip out the tech and communications sectors entirely, the S&amp;P 500 would have returned just <strong>6%</strong> in 2025 <a href=\\"#source-30\\">[30]</a>. Seven companies with AI exposure — NVIDIA, Alphabet, Microsoft, Broadcom, JPMorgan Chase, Palantir, and Meta — delivered over <strong>half</strong> of the entire index's gains <a href=\\"#source-31\\">[31]</a>.</p>\\n<p>This means the entire stock market rally — the one powering the wealth effect, driving consumer spending, and propping up GDP — is built on one bet: that AI spending will eventually produce returns. But as we've just seen, Goldman Sachs says it's contributed &quot;basically zero&quot; to the economy. MIT says 95% of enterprise projects fail. Only 14% of CFOs can point to measurable ROI.</p>\\n<p><strong>The money is real. The spending is real. The returns aren't.</strong></p>\\n<p>And the gap between market hype and economic reality is widening. The top 10 stocks now represent <strong>41% of the S&amp;P 500's total weight but generate only about 32% of its earnings</strong> — a gap that has widened meaningfully since 2015, when weight and earnings contribution were closely aligned <a href=\\"#source-31\\">[31]</a>. Goldman Sachs' own equity research team acknowledges that the &quot;combination of elevated valuations, extreme concentration, and strong recent returns rhymes with a handful of overextended equity markets during the last century&quot; <a href=\\"#source-32\\">[32]</a>. AI capex is on track to reach <strong>75% of cash flows</strong> for the largest tech companies — similar to tech spending in the late 1990s — and future spending growth will increasingly rely on debt <a href=\\"#source-32\\">[32]</a>.</p>\\n<p>Apollo's chief economist Torsten Slok has published research showing that <strong>the AI bubble is now bigger than the IT bubble of the 1990s</strong>, with the average P/E ratio of the top 10 S&amp;P 500 companies sitting around 50 and hyperscaler capital expenditure as a share of GDP exceeding the dotcom era <a href=\\"#source-33\\">[33]</a>. His bottom line: investors in the S&amp;P 500 &quot;remain overexposed to AI&quot; <a href=\\"#source-33\\">[33]</a>.</p>\\n<p>Think of it like Cisco in 1999. Cisco had real revenue — they were selling real routers to real companies building out internet infrastructure. The stock price reflected the spending story, not the returns story. The companies buying the routers never built sustainable businesses on top of them. When the spending stopped, Cisco's stock dropped 86% and never recovered its peak. Today, NVIDIA is the Cisco of the AI era — posting real revenue because hyperscalers are writing enormous checks for GPUs. But the companies buying those GPUs can't show a return on the investment. The spending is driving the stock, not the other way around.</p>\\n<hr>\\n<h2 id=\\"the-110-billion-question\\" tabindex=\\"-1\\">The $110 Billion Question <a class=\\"header-anchor\\" href=\\"#the-110-billion-question\\" aria-label=\\"Permalink to &quot;The $110 Billion Question&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>On February 27, 2026, OpenAI announced a <strong>$110 billion funding round</strong> — the largest private fundraise in history — at a $730 billion pre-money valuation. Amazon invested $50 billion, with Nvidia and SoftBank contributing $30 billion each <a href=\\"#source-13\\">[13]</a> <a href=\\"#source-14\\">[14]</a>.</p>\\n<p>These numbers sound impressive until you examine the structure. Amazon invests $50 billion in OpenAI, and OpenAI commits to spending $100 billion on AWS over eight years <a href=\\"#source-13\\">[13]</a>. The money flows out and comes right back. It's not a clean investment — it's a customer acquisition cost disguised as a capital raise. For context, this single round exceeds the <strong>$170 billion in total U.S. venture capital investment for all of 2023</strong> <a href=\\"#source-15\\">[15]</a>.</p>\\n<p>Reporting has revealed that OpenAI's Stargate joint venture involves very little actual collaboration among partners, with most data centers being traditional bilateral deals rather than the unified project that was announced — described by one outlet as better understood as <strong>&quot;a branding exercise than a real entity&quot;</strong> <a href=\\"#source-16\\">[16]</a>.</p>\\n<p>And the investor pool is narrowing. This round came from just three megaplayers who are simultaneously OpenAI's suppliers and customers. That's not a sign of broad market confidence. That's a sign that the only people willing to write checks are those with strategic reasons beyond financial return.</p>\\n<hr>\\n<h2 id=\\"the-subsidized-illusion\\" tabindex=\\"-1\\">The Subsidized Illusion <a class=\\"header-anchor\\" href=\\"#the-subsidized-illusion\\" aria-label=\\"Permalink to &quot;The Subsidized Illusion&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's something most AI users don't realize: <strong>your subscription is being heavily subsidized by investor capital.</strong> Tech journalist <a href=\\"https://www.wheresyoured.at/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron</a> has been documenting this dynamic extensively, and the numbers are damning.</p>\\n<p>As Zitron details, OpenAI spent <strong>50% of its revenue on inference compute costs alone, and 75% on training compute</strong> — numbers that add up to well over 100% of revenue. They spent $9 billion to lose $5 billion <a href=\\"#source-17\\">[17]</a>. And it's not just OpenAI. Perplexity spent <strong>164% of its revenue</strong> on AWS, Anthropic, and OpenAI costs in 2024 <a href=\\"#source-17\\">[17]</a>.</p>\\n<p>Zitron's core observation cuts to the heart of the problem: &quot;Anybody funding an AI startup is effectively sending that money to Anthropic or OpenAI, who then immediately send that money to Amazon, Google or Microsoft, who are yet to show that they make any profit on selling it.&quot; <a href=\\"#source-17\\">[17]</a> The money cascades down and evaporates at every level. Nobody in the chain is profitable.</p>\\n<p>A developer using Claude Code eight hours a day can cost the provider <strong>tens of thousands of dollars per month</strong> in compute — on a $200 subscription <a href=\\"#source-18\\">[18]</a>. OpenAI's CEO Sam Altman has publicly acknowledged that even the <strong>$200/month ChatGPT Pro tier loses money</strong> on power users <a href=\\"#source-19\\">[19]</a>. The true cost of serving a heavy AI user is likely <strong>$1,000 to $2,000+ per month</strong>, not the $20-200 consumers pay.</p>\\n<p>AI companies are running the same playbook as Uber and WeWork — price below cost to capture market share, subsidize the difference with investor billions, and figure out profitability later <a href=\\"#source-20\\">[20]</a>. When investor subsidies dry up — whether through funding fatigue, a market correction, or companies simply running out of runway — prices must rise to reflect reality. And at real prices, the value proposition collapses for the vast majority of users. If most enterprise users don't find AI useful at $0 (the Copilot licenses their companies pay for that go unused), they certainly won't pay $2,000/month.</p>\\n<p>AI-related debt issuance in credit markets crossed <strong>$200 billion in 2025</strong>, representing 30% of all USD credit supply <a href=\\"#source-11\\">[11]</a>. Hyperscalers are projected to spend a cumulative <strong>$4 trillion on AI data centers through 2030</strong> <a href=\\"#source-11\\">[11]</a>. These are staggering bets on a technology that 95% of enterprises can't generate returns from.</p>\\n<hr>\\n<h2 id=\\"but-what-about-anthropic\\" tabindex=\\"-1\\">But What About Anthropic? <a class=\\"header-anchor\\" href=\\"#but-what-about-anthropic\\" aria-label=\\"Permalink to &quot;But What About Anthropic?&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>If OpenAI is the poster child for AI excess, Anthropic is supposed to be the responsible adult — enterprise-focused, safety-conscious, targeting break-even by 2028 <a href=\\"#source-43\\">[43]</a>. But the numbers tell a different story.</p>\\n<p>Ed Zitron obtained Anthropic's AWS billing data and revealed that through September 2025, the company spent <strong>$2.66 billion on Amazon Web Services</strong> on an estimated <strong>$2.55 billion in revenue</strong> <a href=\\"#source-34\\">[34]</a>. Just the AWS bill — one line item from one cloud vendor — consumed every dollar the company earned. And as Zitron observed, the costs scale linearly with revenue, showing no evidence of improving margins at scale <a href=\\"#source-34\\">[34]</a>.</p>\\n<p>And that's before paying for anything else. Here's what sits on top, roughly ordered by magnitude:</p>\\n<ul>\\n<li><strong>Google Cloud compute</strong> (estimated $1.3B+ through Sept 2025) — Anthropic also runs on GCP, committed to a deal worth &quot;tens of billions&quot; for up to one million TPUs <a href=\\"#source-35\\">[35]</a>, and Zitron estimates their Google spend at a minimum of 50% of their AWS bill <a href=\\"#source-34\\">[34]</a>. Inference costs ran 23% over plan in 2025 <a href=\\"#source-36\\">[36]</a></li>\\n<li><strong>Salaries and compensation</strong> (~$500-600M/year) — over 1,200 employees <a href=\\"#source-37\\">[37]</a> with a median total compensation of $472,000; top AI researchers earning up to $759,000 <a href=\\"#source-38\\">[38]</a></li>\\n<li><strong>Revenue sharing with cloud platforms</strong> ($360M in 2025, scaling to $1.9B in 2026 and $6.4B by 2027) — AWS takes up to 50% of gross profits from AI sales on its platform; Google takes 20-30% of net revenue <a href=\\"#source-39\\">[39]</a> <a href=\\"#source-40\\">[40]</a></li>\\n<li><strong>Data center construction</strong> ($50B committed) — partnership with FluidStack to build facilities in Texas and New York, with sites expected online throughout 2026 <a href=\\"#source-41\\">[41]</a></li>\\n<li><strong>Microsoft Azure compute</strong> ($30B committed over time) — announced alongside a $5B Microsoft investment in November <a href=\\"#source-39\\">[39]</a></li>\\n<li><strong>Energy and grid infrastructure</strong> (uncapped commitment) — Anthropic publicly pledged to cover 100% of electricity price increases and grid upgrade costs for every community hosting its data centers <a href=\\"#source-42\\">[42]</a></li>\\n<li><strong>R&amp;D, safety research, and model training</strong> (hundreds of millions/year) — total company cash burn was $5.6B in 2024 and ~$3B in 2025 <a href=\\"#source-43\\">[43]</a>, and the costs above don't account for all of it</li>\\n<li><strong>Sales, marketing, and enterprise support</strong> (rapidly scaling) — serving 300,000+ business customers, with 500+ spending over $1M annually <a href=\\"#source-44\\">[44]</a></li>\\n<li><strong>Legal and IPO preparation</strong> (tens of millions) — retained Wilson Sonsini, the firm behind Google's and LinkedIn's IPOs, to advise on a potential 2026 listing <a href=\\"#source-45\\">[45]</a></li>\\n</ul>\\n<p>Claude Code, the company's breakout coding product, makes the math even worse — subscribers consume <strong>$8-13.50 in actual compute for every $1 they pay</strong>, meaning a $200/month user burns through over $2,700 in real costs <a href=\\"#source-46\\">[46]</a>.</p>\\n<p>So when Anthropic projects &quot;break-even by 2028,&quot; the question is: break-even on what definition? If the most disciplined company in the AI race spends 100% of revenue on a single vendor's cloud bill before touching any other expense, the industry's path to profitability isn't just narrow — it may not exist.</p>\\n<hr>\\n<h2 id=\\"but-inference-costs-are-dropping-exponentially\\" tabindex=\\"-1\\">“But Inference Costs Are Dropping Exponentially!” <a class=\\"header-anchor\\" href=\\"#but-inference-costs-are-dropping-exponentially\\" aria-label=\\"Permalink to &quot;“But Inference Costs Are Dropping Exponentially!”&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>They are. Stanford HAI’s 2025 AI Index Report found that inference costs for GPT-3.5-level performance dropped over <strong>280-fold</strong> between November 2022 and October 2024 <a href=\\"#source-48\\">[48]</a>. Epoch AI’s research measured declines ranging from <strong>9x to 900x per year</strong> depending on the task, with the fastest drops occurring after January 2024 <a href=\\"#source-49\\">[49]</a>. OpenAI’s internal compute margin hit <strong>70%</strong> by October 2025, double its January 2024 level <a href=\\"#source-50\\">[50]</a>. These are real gains. Nobody serious disputes them.</p>\\n<p>The problem is that none of it matters in the way the bulls need it to.</p>\\n<p><strong>The cost drops are happening on yesterday’s models. The frontier is a treadmill.</strong> The 280x improvement Stanford measured is for GPT-3.5-level performance — a model nobody wants anymore. Users now expect GPT-4-level quality and reasoning capabilities of o1-class models, which employ test-time scaling and consume vastly more tokens per query. The cost per query may actually be <em>increasing</em> for frontier models even as cost per token declines <a href=\\"#source-51\\">[51]</a>. Reasoning models require roughly <strong>20x more tokens and 150x more compute per query</strong> than traditional LLMs <a href=\\"#source-52\\">[52]</a>. At maximum reasoning settings, a simple question might consume <strong>10,000 reasoning tokens internally</strong> while returning a 200-token answer <a href=\\"#source-53\\">[53]</a>.</p>\\n<p>This is the trick hiding inside the headline numbers. Every time efficiency catches up to the current frontier, the frontier moves. GPT-3.5 costs collapse — but customers have migrated to GPT-4. GPT-4 costs collapse — but everyone’s running o1-class reasoning chains. It’s like celebrating that a 2019 Toyota got cheaper while your customers all want the 2026 model. The efficiency gains are perpetually arriving for the product the market has already moved past.</p>\\n<p>Anthropic expects its gross profit margin to reach 50% this year and 77% by 2028 — but the inference cost declines are happening on older models. Frontier models are getting more expensive, not cheaper <a href=\\"#source-56\\">[56]</a>. The rise of agentic workflows has caused token consumption per task to jump <strong>10-100x</strong> since December 2023. Every leap in capability resets the economics back to brutal.</p>\\n<p><strong>Jevons Paradox eats the savings.</strong> Even setting aside the frontier treadmill, cheaper inference doesn’t produce cheaper AI bills. It produces <em>more AI bills.</em> Inference costs fell roughly 1,000-fold, but demand rose 10,000-fold — cheaper tokens didn’t reduce spending, they unleashed it <a href=\\"#source-55\\">[55]</a>. Enterprise AI spending surged <strong>320%</strong> in 2025 despite per-token costs dropping 1,000x, because each price drop makes thousands of new use cases suddenly economically viable <a href=\\"#source-54\\">[54]</a>.</p>\\n<p>This isn’t speculation. It’s what happened with coal in the 1860s, bandwidth in the 2000s, and mobile data in the 2010s. Every time you make a resource cheaper, consumption expands to more than compensate. Satya Nadella said it himself the day DeepSeek launched: “Jevons paradox strikes again.” If your per-token cost drops from $0.06 to $0.00006, you don’t get savings — you get AI running on every customer service interaction, personalized content at the individual level, and agents iterating through dozens of reasoning steps per response <a href=\\"#source-54\\">[54]</a>. The volume explosion overwhelms any per-unit improvement.</p>\\n<p>For AI providers, this is actually <em>good</em> for revenue growth but <em>terrible</em> for the profitability thesis. More usage means more infrastructure, more GPUs, more power, more cooling. The denominator scales with the numerator. You’re running faster to stay in the same place.</p>\\n<p><strong>The application-layer margin squeeze is brutal.</strong> Even if you accept that the foundation model providers are improving their margins, the companies actually building products on top of those models are getting crushed. Cursor, the poster child for AI-powered coding tools, was reportedly paying approximately <strong>$650 million annually to Anthropic</strong> while generating only <strong>$500 million in revenue</strong> — a negative 30% gross margin. Their AWS bills doubled in a single month when Anthropic launched new pricing tiers <a href=\\"#source-56\\">[56]</a>.</p>\\n<p>This isn’t an outlier. Bessemer’s 2025 data shows fast-ramping AI startups averaging only <strong>25% gross margins</strong>, with many running negative. The traditional SaaS benchmark for a healthy gross margin is 75%+ <a href=\\"#source-56\\">[56]</a>. If you show up to a Series B with 25% margins, you’re not a software company — you’re a services business subsidizing your customers’ compute.</p>\\n<p>The inference cost curve is real. It’s also irrelevant to the question that actually matters: can these companies turn a profit before they run out of other people’s money? So far, every efficiency gain gets consumed by the next leap in model complexity, the next explosion in usage volume, or the next round of infrastructure buildout. The treadmill doesn’t stop. And yes, a true believer can argue that all of these trends will reverse at exactly the right moment — that costs will plateau just as capital dries up, that margins will appear just as subsidies vanish, that the history of every other capital-intensive bubble will suddenly stop applying. But that’s not an argument. That’s a hope dressed in a spreadsheet.</p>\\n<hr>\\n<h2 id=\\"the-k-shaped-economy-a-house-of-cards\\" tabindex=\\"-1\\">The K-Shaped Economy: A House of Cards <a class=\\"header-anchor\\" href=\\"#the-k-shaped-economy-a-house-of-cards\\" aria-label=\\"Permalink to &quot;The K-Shaped Economy: A House of Cards&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>The AI bubble doesn't exist in isolation. It sits on top of an already fragile economic structure that economists call the <strong>&quot;K-shaped economy&quot;</strong> — where the wealthy are thriving while everyone else falls behind.</p>\\n<p>The numbers are stark. The <strong>top 10% of earners now account for 50% of all consumer spending</strong>, up from 35% in the early 1990s <a href=\\"#source-21\\">[21]</a>. Moody's Analytics found that the top 20% accounts for <strong>59% of total spending</strong> <a href=\\"#source-22\\">[22]</a>. And for the bottom 80%? Their spending hasn't outpaced inflation over the last six years, meaning economic quality of life hasn't improved for the vast majority of Americans <a href=\\"#source-23\\">[23]</a>.</p>\\n<p>As of Q4 2025, the <strong>top 20% of households held nearly 72% of total household wealth</strong> <a href=\\"#source-24\\">[24]</a>. Lower-income households are increasingly relying on debt, with <strong>rising delinquency rates particularly in auto loans</strong> <a href=\\"#source-25\\">[25]</a>. Bank of America's analysis shows the divide is worsening, with some economists suggesting we've moved beyond a K-shape into a <strong>&quot;barbell economy&quot;</strong> heavily weighted at the extremes <a href=\\"#source-26\\">[26]</a>.</p>\\n<p>Much of the wealthy's spending is driven by the <strong>&quot;wealth effect&quot;</strong> — they spend more because their stock portfolios are up. And what's driving stock prices? AI hype. Soaring AI-related valuations alone have created an estimated <strong>$180 billion in additional consumer spending</strong> over the past year <a href=\\"#source-27\\">[27]</a>.</p>\\n<p>This creates a dangerous feedback loop: AI hype drives tech stocks up → rising stocks make wealthy people feel richer → wealthy people spend more → GDP looks healthy → the healthy GDP narrative justifies more AI investment → repeat.</p>\\n<p>Moody's chief economist Mark Zandi captured the fragility perfectly: <strong>&quot;It doesn't feel like the economy's perched on a strong foundation. It's perched on a few poles that are sticking up. If one of those poles gets knocked out, then the whole economy gets knocked down.&quot;</strong> <a href=\\"#source-23\\">[23]</a></p>\\n<p>Fortune published an analysis warning that wealthy consumers' spending is <strong>&quot;psychologically tethered to their portfolio balance&quot;</strong> — when the S&amp;P drops, they freeze discretionary spending. And in 2026, <strong>&quot;there is no one there to catch it&quot;</strong> because the bottom 80% has already depleted their pandemic-era savings <a href=\\"#source-28\\">[28]</a>.</p>\\n<p>U.S. Bank's chief economist Beth Ann Bovino put it plainly: <strong>&quot;We're increasingly dependent on healthier cohorts to keep the economy afloat.&quot;</strong> <a href=\\"#source-25\\">[25]</a> That's a polite way of saying the economy collapses if rich people stop spending — and rich people stop spending when their portfolios drop.</p>\\n<hr>\\n<h2 id=\\"why-public-sector-careers-are-the-smart-play\\" tabindex=\\"-1\\">Why Public Sector Careers Are the Smart Play <a class=\\"header-anchor\\" href=\\"#why-public-sector-careers-are-the-smart-play\\" aria-label=\\"Permalink to &quot;Why Public Sector Careers Are the Smart Play&quot;\\">&ZeroWidthSpace;</a></h2>\\n<h3 id=\\"yes-california-s-budget-will-take-a-hit-that-s-not-the-same-as-losing-your-job\\" tabindex=\\"-1\\"><em>Yes, California's budget will take a hit. That's not the same as losing your job.</em> <a class=\\"header-anchor\\" href=\\"#yes-california-s-budget-will-take-a-hit-that-s-not-the-same-as-losing-your-job\\" aria-label=\\"Permalink to &quot;*Yes, California's budget will take a hit. That's not the same as losing your job.*&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p>California gets 67% of its General Fund from personal income tax, and capital gains alone account for 16% of total tax liability — spiking to 25% in boom years <a href=\\"#source-57\\">[57]</a>. When the dot-com bubble burst, state revenue dropped from $100 billion to $85 billion <a href=\\"#source-58\\">[58]</a>. An AI correction will hit state budgets. This is not a hypothetical.</p>\\n<p>But here's what actually happens to public sector workers when budgets get slashed: <strong>they get furloughs, not layoffs.</strong></p>\\n<p>The private sector lost 8.7 million jobs during the Great Recession <a href=\\"#source-59\\">[59]</a>. Public sector employment <em>increased</em> by 590,000 in the first year <a href=\\"#source-47\\">[47]</a>. When budgets finally tightened, the failure mode was fundamentally different. State and local governments shed just 68,000 jobs — a 0.3% decline — while the private sector hemorrhaged millions <a href=\\"#source-63\\">[63]</a>. In FY2010, the worst budget year, 26 states used layoffs but 22 chose furloughs instead <a href=\\"#source-64\\">[64]</a>. California chose furloughs. It has chosen furloughs in nine of the fiscal years since 1992 <a href=\\"#source-65\\">[65]</a>.</p>\\n<p><strong>And furloughs aren't what most people think they are.</strong> California's 2009 furlough program covered 193,000 workers and imposed 2-3 unpaid days per month — a 13.8% reduction on paper <a href=\\"#source-60\\">[60]</a>. In reality, furlough hours were banked as leave credits and paid out at separation, often at a higher base pay after COLA increases <a href=\\"#source-61\\">[61]</a>. Workers kept their jobs, their health insurance, their pension accrual, and their seniority. The historical pattern is consistent: public sector employment didn't drop during the 1991 recession at all, didn't decline after the dot-com bust until 2004, and barely moved during 2008-2012 <a href=\\"#source-62\\">[62]</a>.</p>\\n<p>This stability isn't accidental — it's structural. <strong>Countercyclical demand</strong> means that when the private sector contracts, public sector workload expands. Safety net caseloads rose from 276 million to 310 million recipients during the Great Recession <a href=\\"#source-66\\">[66]</a>. Someone has to process those claims, maintain those roads, inspect those buildings, and run those programs. The work doesn't disappear when the economy does.</p>\\n<p><strong>Union protection</strong> reinforces the structural advantage. Public sector union density is 32.9% versus 5.9% in the private sector, and local agencies sit at 37.8% <a href=\\"#source-67\\">[67]</a>. That means layoffs happen by seniority, not by manager mood. Furloughs are negotiated, not dictated. You get a grievance process before termination. Civil service rules, merit-based hiring, and progressive discipline create layers of protection that simply don't exist in at-will private employment.</p>\\n<p><strong>And then there's the pension.</strong> Public sector workers earn defined-benefit retirement through CalPERS or CalSTRS — a guaranteed monthly income for life calculated from salary and years of service, not subject to market crashes. Thirty years of service typically yields 60-75% of final salary, guaranteed, regardless of what the stock market does. While private sector 401(k)s crater with every correction, public pensions pay out on schedule.</p>\\n<p>You can't be laid off because your company missed earnings. You can't be &quot;restructured&quot; because a VC pulled funding. Your position exists because the public needs the service — not because an investor believes in the growth story.</p>\\n<p>At <a href=\\"https://penpublic.com\\" target=\\"_blank\\" rel=\\"noreferrer\\">PenPublic</a>, we're building the most comprehensive public sector job platform in the country — aggregating positions across hundreds of agencies at the federal, state, and local level. Local agency jobs are the hardest to find because they're scattered across thousands of individual websites. We bring them together in one place. Whether you're a tech worker thinking about your next move, a recent graduate evaluating career paths, or a current public servant exploring new opportunities, we believe public service represents one of the smartest career investments you can make right now.</p>\\n<p>The AI bubble will pop. The K-shaped economy will correct. The question isn't whether disruption is coming — it's whether you'll be positioned on stable ground when it arrives.</p>\\n<hr>\\n<h2 id=\\"sources\\" tabindex=\\"-1\\">Sources <a class=\\"header-anchor\\" href=\\"#sources\\" aria-label=\\"Permalink to &quot;Sources&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><a id=\\"source-1\\"><strong>1.</strong></a> <a href=\\"https://thefinancialbrand.com/news/artificial-intelligence-banking/why-95-of-enterprises-are-getting-zero-return-on-ai-investment-191950\\" target=\\"_blank\\" rel=\\"noreferrer\\">MIT's The GenAI Divide: State of AI in Business 2025</a> — 95% failure rate for enterprise AI projects; $30-40B in investment with zero measurable return</p>\\n<p><a id=\\"source-2\\"><strong>2.</strong></a> <a href=\\"https://bizzdesign.com/blog/enterprise-ai-adoption-balancing-innovation-and-roi-2026\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bizzdesign — &quot;Enterprise AI Adoption: Balancing Innovation and ROI in 2026&quot;</a> — Only 15% report positive profitability impact; Forrester predicts 25% of 2026 AI spend deferred to 2027</p>\\n<p><a id=\\"source-3\\"><strong>3.</strong></a> <a href=\\"https://www.ibm.com/think/insights/ai-roi\\" target=\\"_blank\\" rel=\\"noreferrer\\">IBM — &quot;How to Maximize AI ROI in 2026&quot;</a> — 5.9% ROI on 10% capital investment; only 25% of AI initiatives deliver expected ROI; only 29% can measure ROI confidently</p>\\n<p><a id=\\"source-4\\"><strong>4.</strong></a> <a href=\\"https://medium.com/origintrail/5-trends-to-drive-the-ai-roi-in-2026-trust-is-capital-372ac5dabc38\\" target=\\"_blank\\" rel=\\"noreferrer\\">OriginTrail / Medium — &quot;5 Trends to Drive AI ROI in 2026&quot;</a> — Only 14% of CFOs report measurable ROI; MIT study confirms 95% failure rate</p>\\n<p><a id=\\"source-5\\"><strong>5.</strong></a> <a href=\\"https://www.consultingmag.com/2026/02/04/why-enterprise-ai-stalled-and-what-is-finally-changing-in-2026/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Consulting Magazine — &quot;Why Enterprise AI Stalled and What Is Finally Changing in 2026&quot;</a> — 90-95% of organizations seeing little to no measurable financial return; Gartner predicts 40% of agentic AI projects cancelled by 2027</p>\\n<p><a id=\\"source-6\\"><strong>6.</strong></a> <a href=\\"https://www.fullstack.com/labs/resources/blog/generative-ai-roi-why-80-of-companies-see-no-results\\" target=\\"_blank\\" rel=\\"noreferrer\\">FullStack Labs — &quot;Generative AI ROI: Why 80% Fail&quot;</a> — 70% of Fortune 500 use Copilot; 78% of companies report no significant bottom-line impact; only 1% view GenAI strategies as mature</p>\\n<p><a id=\\"source-7\\"><strong>7.</strong></a> <a href=\\"https://finance.yahoo.com/news/ai-contributed-basically-zero-us-181419807.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yahoo Finance — &quot;AI Contributed 'Basically Zero' to the US Economy, According to Goldman Sachs&quot;</a> — Goldman Sachs Chief Economist Jan Hatzius interview with Atlantic Council</p>\\n<p><a id=\\"source-8\\"><strong>8.</strong></a> <a href=\\"https://gizmodo.com/ai-added-basically-zero-to-us-economic-growth-last-year-goldman-sachs-says-2000725380\\" target=\\"_blank\\" rel=\\"noreferrer\\">Gizmodo — &quot;AI Added 'Basically Zero' to US Economic Growth Last Year, Goldman Sachs Says&quot;</a> — Hatzius on imported AI equipment boosting Taiwanese and Korean GDP</p>\\n<p><a id=\\"source-9\\"><strong>9.</strong></a> <a href=\\"https://futurism.com/future-society/researchers-economy-ai-narratives\\" target=\\"_blank\\" rel=\\"noreferrer\\">Futurism — &quot;Goldman Sachs Researchers Make Startling Claim About AI's Effects on the US Economy&quot;</a> — Joseph Briggs interview with Washington Post</p>\\n<p><a id=\\"source-10\\"><strong>10.</strong></a> <a href=\\"https://www.tomshardware.com/tech-industry/artificial-intelligence/ai-boosted-us-economy-by-basically-zero-in-2025-says-goldman-sachs-chief-economist-we-think-theres-been-a-lot-of-misreporting-of-the-impact-that-ai-investment-had-on-gdp-growth\\" target=\\"_blank\\" rel=\\"noreferrer\\">Tom's Hardware — &quot;AI Boosted US Economy by 'Basically Zero' in 2025, Says Goldman Sachs Chief Economist&quot;</a> — 0.2% AI contribution to 2.2% GDP growth; $700B projected 2026 spend; J.P. Morgan $600B revenue threshold</p>\\n<p><a id=\\"source-11\\"><strong>11.</strong></a> <a href=\\"https://fortune.com/2025/12/23/us-gdp-alive-by-ai-capex/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;A Huge Chunk of U.S. GDP Growth Is Being Kept Alive by AI Spending 'With No Guaranteed Return'&quot;</a> — Deutsche Bank recession warning; $200B AI-related credit issuance (30% of USD supply); $4 trillion cumulative data center spend projected through 2030</p>\\n<p><a id=\\"source-12\\"><strong>12.</strong></a> <a href=\\"https://www.cnbc.com/2026/01/26/ai-wasnt-the-biggest-engine-of-us-gdp-growth-in-2025.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">CNBC — &quot;AI Spending Wasn't the Biggest Engine of U.S. Economic Growth in 2025&quot;</a> — MRB Partners analysis; 20-25% net AI contribution after import adjustment; consumer spending as true growth driver</p>\\n<p><a id=\\"source-13\\"><strong>13.</strong></a> <a href=\\"https://techcrunch.com/2026/02/27/openai-raises-110b-in-one-of-the-largest-private-funding-rounds-in-history/\\" target=\\"_blank\\" rel=\\"noreferrer\\">TechCrunch — &quot;OpenAI Raises $110B in One of the Largest Private Funding Rounds in History&quot;</a> — $50B Amazon, $30B Nvidia, $30B SoftBank; stateful runtime on AWS Bedrock; $100B AWS commitment expansion</p>\\n<p><a id=\\"source-14\\"><strong>14.</strong></a> <a href=\\"https://www.bloomberg.com/news/articles/2026-02-27/openai-finalizes-110-billion-funding-at-730-billion-valuation\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bloomberg — &quot;OpenAI Finalizes $110 Billion Funding at $730 Billion Value&quot;</a> — $730B pre-money valuation; Amazon's $35B contingent on AGI or IPO</p>\\n<p><a id=\\"source-15\\"><strong>15.</strong></a> <a href=\\"https://www.axios.com/2026/02/27/openai-funding-nvidia-amazon\\" target=\\"_blank\\" rel=\\"noreferrer\\">Axios — &quot;OpenAI Secures $110B Funding Round&quot;</a> — Round exceeds total 2023 U.S. VC investment ($170B); Microsoft did not participate</p>\\n<p><a id=\\"source-16\\"><strong>16.</strong></a> <a href=\\"https://www.newcomer.co/p/openai-raises-110-billion-and-throws\\" target=\\"_blank\\" rel=\\"noreferrer\\">Newcomer — &quot;OpenAI Raises $110 Billion &amp; Throws In With Amazon&quot;</a> — Stargate described as &quot;branding exercise&quot;; little collaboration among partners; complicated financial structures becoming ordinary arrangements</p>\\n<p><a id=\\"source-17\\"><strong>17.</strong></a> <a href=\\"https://www.wheresyoured.at/why-everybody-is-losing-money-on-ai/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron / Where's Your Ed At — &quot;Why Everybody Is Losing Money on AI&quot;</a> — OpenAI: 50% revenue on inference, 75% on training (&gt;100% combined); $9B spent to lose $5B; Perplexity at 164% of revenue on compute; entire value chain unprofitable</p>\\n<p><a id=\\"source-18\\"><strong>18.</strong></a> <a href=\\"https://www.news.aakashg.com/p/how-to-price-ai-products\\" target=\\"_blank\\" rel=\\"noreferrer\\">Product Faculty / AI Pricing Guide 2026</a> — Claude Code heavy users cost &quot;tens of thousands per month&quot;; OpenAI projects $14B cumulative losses by end of 2026; AI SaaS gross margins 20-60% vs traditional 70-90%</p>\\n<p><a id=\\"source-19\\"><strong>19.</strong></a> <a href=\\"https://www.getmonetizely.com/blogs/ai-pricing-how-much-does-ai-cost-in-2025\\" target=\\"_blank\\" rel=\\"noreferrer\\">Monetizely — &quot;AI Pricing in 2025: Strategy for Costing&quot;</a> — Sam Altman admission that $200/mo Pro tier loses money on power users; AI gross margins under pressure industry-wide</p>\\n<p><a id=\\"source-20\\"><strong>20.</strong></a> <a href=\\"https://www.uptechstudio.com/blog/the-true-cost-of-ai-when-the-subsidies-run-out\\" target=\\"_blank\\" rel=\\"noreferrer\\">UpTech Studio — &quot;The True Cost of AI: When the Subsidies Run Out&quot;</a> — Uber/WeWork subsidy model comparison; land-grab pricing strategy; warning that 5x current AI costs would kill most AI startups</p>\\n<p><a id=\\"source-21\\"><strong>21.</strong></a> <a href=\\"https://www.pbs.org/newshour/show/k-shaped-economy-why-the-wealthy-are-thriving-as-most-americans-fall-behind\\" target=\\"_blank\\" rel=\\"noreferrer\\">PBS NewsHour — &quot;K-Shaped Economy: Why the Wealthy Are Thriving as Most Americans Fall Behind&quot;</a> — Top 10% = 50% of spending (up from 35% in early 1990s)</p>\\n<p><a id=\\"source-22\\"><strong>22.</strong></a> <a href=\\"https://finance.yahoo.com/video/wealth-inequality-k-shaped-economy-183000976.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yahoo Finance — Mark Zandi Interview: &quot;Wealth Inequality in K-Shaped Economy Is 'Corrosive'&quot;</a> — Top 20% = 59% of total spending (Moody's Analytics data)</p>\\n<p><a id=\\"source-23\\"><strong>23.</strong></a> <a href=\\"https://www.cnbc.com/2026/01/30/wealth-inequality-k-shaped-economy-united-states-consumer-spending-trump.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">CNBC — &quot;Wealth Inequality and the 'K-Shaped' Economy Are More Striking Than Ever&quot;</a> — Bottom 80% spending hasn't outpaced inflation in 6 years; Mark Zandi &quot;poles&quot; quote; rising auto loan delinquencies</p>\\n<p><a id=\\"source-24\\"><strong>24.</strong></a> <a href=\\"https://economics.td.com/us-k-shaped-consumer-spending\\" target=\\"_blank\\" rel=\\"noreferrer\\">TD Economics — &quot;U.S. Consumer Spending: Still a K, but That's OK&quot;</a> — Top 20% hold 72% of total household wealth as of Q4 2025; K-shape expected to deepen in 2026 due to tax policy</p>\\n<p><a id=\\"source-25\\"><strong>25.</strong></a> <a href=\\"https://www.usbank.com/corporate-and-commercial-banking/insights/economy/macro/k-shaped-economy.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">U.S. Bank — &quot;The K-Shaped Economy in 2026&quot;</a> — Lower-income households relying on debt; rising delinquency rates; Beth Ann Bovino quote on dependence on &quot;healthier cohorts&quot;</p>\\n<p><a id=\\"source-26\\"><strong>26.</strong></a> <a href=\\"https://fortune.com/2026/01/14/when-will-us-enter-recession-middle-class-barbell-k-shaped-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;Forget the K-Shape: We Have a Barbell Economy&quot;</a> — Economy described as &quot;dangerously brittle&quot;; wealthy spending tethered to portfolio balance; bottom 80% financing groceries with &quot;shadow debt&quot;</p>\\n<p><a id=\\"source-27\\"><strong>27.</strong></a> <a href=\\"https://www.empower.com/the-currency/money/life/k-shaped-economy-what-to-know-news\\" target=\\"_blank\\" rel=\\"noreferrer\\">Empower — &quot;The K-Shaped Economy: What Consumers Should Know&quot;</a> — $180B in wealth-effect consumer spending from AI-related stock valuations; Delta premium revenue up 9%, basic economy down 7%</p>\\n<p><a id=\\"source-28\\"><strong>28.</strong></a> <a href=\\"https://fortune.com/2026/01/14/when-will-us-enter-recession-middle-class-barbell-k-shaped-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;Forget the K-Shape: We Have a Barbell Economy&quot;</a> — &quot;No one there to catch it&quot; when wealthy pull back; pandemic savings depleted; economy has &quot;massive engine and insufficient braking mechanisms&quot;</p>\\n<p><a id=\\"source-29\\"><strong>29.</strong></a> <a href=\\"https://insights.som.yale.edu/insights/this-is-how-the-ai-bubble-bursts\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yale Insights / Jeffrey Sonnenfeld — &quot;This Is How the AI Bubble Bursts&quot;</a> — J.P. Morgan's Cembalest: AI stocks = 75% of S&amp;P 500 returns, 80% of earnings growth, 90% of capex growth since ChatGPT launch; two-thirds of U.S. deal value going to AI/ML startups in H1 2025</p>\\n<p><a id=\\"source-30\\"><strong>30.</strong></a> <a href=\\"https://www.statista.com/chart/30318/sector-contributions-to-sp500-return/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Statista — &quot;Wider Tech Sector Led S&amp;P 500 to Another Double-Digit Gain&quot;</a> — Mag 7 = 42% of S&amp;P 500's 17.9% return in 2025; tech and communications = 63.1% of total return; excluding those sectors, S&amp;P 500 returned just 6%</p>\\n<p><a id=\\"source-31\\"><strong>31.</strong></a> <a href=\\"https://www.rbcwealthmanagement.com/en-us/insights/us-equity-returns-in-2025-record-breaking-resilience\\" target=\\"_blank\\" rel=\\"noreferrer\\">RBC Wealth Management — &quot;U.S. Equity Returns in 2025: Record-Breaking Resilience&quot; and &quot;The 'Great Narrowing': S&amp;P 500 Concentration&quot;</a> — Seven AI-exposed stocks = over half of S&amp;P 500 gains; top 10 = 41% of weight but ~32% of earnings; cap-weighted index outperformed equal-weight by 32% over 3 years</p>\\n<p><a id=\\"source-32\\"><strong>32.</strong></a> <a href=\\"https://www.goldmansachs.com/insights/articles/the-sp-500-expected-to-rally-12-this-year\\" target=\\"_blank\\" rel=\\"noreferrer\\">Goldman Sachs — &quot;The S&amp;P 500 Is Expected to Rally 12% This Year&quot;</a> — Top tech stocks = 53% of S&amp;P 500 return in 2025; AI capex reaching 75% of cash flows; &quot;elevated valuations, extreme concentration, and strong recent returns rhymes with overextended equity markets during the last century&quot;</p>\\n<p><a id=\\"source-33\\"><strong>33.</strong></a> <a href=\\"https://www.apolloacademy.com/extreme-ai-concentration-in-the-sp-500/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Apollo Academy / Torsten Slok — &quot;Extreme AI Concentration in the S&amp;P 500&quot;</a> — AI bubble bigger than IT bubble in 1990s; average P/E of top 10 around 50; hyperscaler capex as share of GDP exceeds dotcom era; investors &quot;remain overexposed to AI&quot;</p>\\n<p><a id=\\"source-34\\"><strong>34.</strong></a> <a href=\\"https://www.wheresyoured.at/costs/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron / Where's Your Ed At — &quot;This Is How Much Anthropic and Cursor Spend on Amazon Web Services&quot;</a> — $2.66B AWS spend on $2.55B revenue through September 2025; costs scale linearly with revenue; estimates Google Cloud spend at minimum 50% of AWS</p>\\n<p><a id=\\"source-35\\"><strong>35.</strong></a> <a href=\\"https://www.anthropic.com/news/expanding-our-use-of-google-cloud-tpus-and-services\\" target=\\"_blank\\" rel=\\"noreferrer\\">Anthropic — &quot;Expanding Our Use of Google Cloud TPUs and Services&quot;</a> — Deal worth &quot;tens of billions of dollars&quot; for up to one million TPUs; over a gigawatt of capacity expected online in 2026</p>\\n<p><a id=\\"source-36\\"><strong>36.</strong></a> <a href=\\"https://www.aiplanetx.com/p/cloud-spending-hits-anthropic\\" target=\\"_blank\\" rel=\\"noreferrer\\">AI Planet X — &quot;Cloud Spending Hits Anthropic&quot;</a> — Inference costs on Google and Amazon cloud ran 23% over plan; gross margin pushed toward ~40%; ~$5.2B burn in 2025</p>\\n<p><a id=\\"source-37\\"><strong>37.</strong></a> <a href=\\"https://www.pminsights.com/insights/anthropic-approaches-7b-run-rate-in-2025-outpaces-openai\\" target=\\"_blank\\" rel=\\"noreferrer\\">PM Insights — &quot;Anthropic Approaches $7B Run Rate&quot;</a> — Over 1,200 employees by late 2025; plans to triple international workforce and quintuple applied AI team</p>\\n<p><a id=\\"source-38\\"><strong>38.</strong></a> <a href=\\"https://www.levels.fyi/companies/anthropic/salaries\\" target=\\"_blank\\" rel=\\"noreferrer\\">Levels.fyi — Anthropic Salaries</a> — Median yearly total compensation $471,808; highest reported $759,413 for Lead Software Engineer</p>\\n<p><a id=\\"source-39\\"><strong>39.</strong></a> <a href=\\"https://www.datacenterdynamics.com/en/news/anthropic-cloud-spend-expected-to-reach-80bn-through-2029/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Data Center Dynamics — &quot;Anthropic Cloud Spend Expected to Reach $80B Through 2029&quot;</a> — $80B total cloud spend projected through 2029 across AWS, Google, and Microsoft; AWS takes up to 50% of gross profits; Google takes 20-30% of net revenue; $30B Microsoft Azure commitment</p>\\n<p><a id=\\"source-40\\"><strong>40.</strong></a> <a href=\\"https://www.pymnts.com/artificial-intelligence-2/2026/anthropic-set-to-pay-cloud-partners-80-billion-through-2029/\\" target=\\"_blank\\" rel=\\"noreferrer\\">PYMNTS — &quot;Anthropic Set to Pay Cloud Partners $80 Billion Through 2029&quot;</a> — Revenue sharing payouts: ~$1.3M in 2024, ~$360M in 2025, ~$1.9B in 2026, ~$6.4B in 2027 (The Information data)</p>\\n<p><a id=\\"source-41\\"><strong>41.</strong></a> <a href=\\"https://www.fierce-network.com/cloud/what-does-anthropics-50b-data-center-project-mean-hyperscalers\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fierce Network — &quot;What Does Anthropic's $50B Data Center Project Mean for Hyperscalers?&quot;</a> — $50B data center partnership with FluidStack; facilities in Texas and New York expected online throughout 2026</p>\\n<p><a id=\\"source-42\\"><strong>42.</strong></a> <a href=\\"https://sustainabilitymag.com/news/why-anthropic-pledging-offset-ai-energy-costs\\" target=\\"_blank\\" rel=\\"noreferrer\\">Sustainability Magazine — &quot;Why Is Anthropic Pledging to Offset Its AI Energy Costs?&quot;</a> — Committed to covering 100% of grid upgrade costs and electricity price increases for communities hosting its data centers</p>\\n<p><a id=\\"source-43\\"><strong>43.</strong></a> <a href=\\"https://sacra.com/c/anthropic/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Sacra — Anthropic Revenue, Valuation &amp; Funding</a> — Cash burn of $5.6B in 2024, ~$3B in 2025; projects cash flow positive in 2027, break-even in 2028</p>\\n<p><a id=\\"source-44\\"><strong>44.</strong></a> <a href=\\"https://www.axios.com/2026/02/12/anthropic-raises-30b-at-380b-valuation\\" target=\\"_blank\\" rel=\\"noreferrer\\">Axios — &quot;Anthropic Raises $30B at $380B Valuation&quot;</a> — 300,000+ business customers; run-rate revenue of $14B; customers spending $100K+ annually grown 7x in past year</p>\\n<p><a id=\\"source-45\\"><strong>45.</strong></a> <a href=\\"https://builtin.com/articles/top-tech-ipos-2026\\" target=\\"_blank\\" rel=\\"noreferrer\\">Built In — &quot;2026 IPO Watchlist: OpenAI, SpaceX and Other Tech Giants&quot;</a> — Retained Wilson Sonsini (firm behind Google and LinkedIn IPOs) in December 2025 for IPO preparation</p>\\n<p><a id=\\"source-46\\"><strong>46.</strong></a> <a href=\\"https://www.newsweek.com/ai-skeptic-ed-zitron-says-math-on-data-centers-doesnt-add-up-11594219\\" target=\\"_blank\\" rel=\\"noreferrer\\">Newsweek — &quot;AI Skeptic Ed Zitron Says Math on Data Centers Doesn't Add Up&quot;</a> — Claude Code subscribers consume $8-13.50 in compute per $1 paid; $200/month user burns $2,700+ in real costs; &quot;Everyone using Claude Code right now is in an illusory environment&quot;</p>\\n<p><a id=\\"source-47\\"><strong>47.</strong></a> <a href=\\"https://www.mercatus.org/research/data-visualizations/private-sector-job-losses-dwarf-government-gains\\" target=\\"_blank\\" rel=\\"noreferrer\\">Mercatus Center / George Mason University — &quot;Private Sector Job Losses Dwarf Government Gains&quot;</a> — BLS Current Employment Statistics: government employment increased by 590,000 since January 2008 while private sector lost nearly 8 million jobs; government peaked at ~23 million in May 2010</p>\\n<p><a id=\\"source-48\\"><strong>48.</strong></a> <a href=\\"https://hai.stanford.edu/ai-index/2025-ai-index-report\\" target=\\"_blank\\" rel=\\"noreferrer\\">Stanford HAI — The 2025 AI Index Report</a> — Inference cost for GPT-3.5-level performance dropped over 280-fold between November 2022 and October 2024; driven by increasingly capable small models and open-weight alternatives</p>\\n<p><a id=\\"source-49\\"><strong>49.</strong></a> <a href=\\"https://epoch.ai/data-insights/llm-inference-price-trends\\" target=\\"_blank\\" rel=\\"noreferrer\\">Epoch AI — &quot;LLM Inference Prices Have Fallen Rapidly but Unequally Across Tasks&quot;</a> — Price declines ranging from 9x to 900x per year depending on benchmark; fastest trends (900x/year) start after January 2024; median rate increased from 50x to 200x per year when isolating post-2024 data</p>\\n<p><a id=\\"source-50\\"><strong>50.</strong></a> <a href=\\"https://www.bloomberg.com/news/articles/2025-12-21/openai-sees-better-margins-on-business-sales-report-says\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bloomberg — &quot;OpenAI Sees Better Margins on Business Sales, Report Says&quot;</a> — OpenAI compute margin reached 70% as of October 2025, up from 52% at end of 2024 and double the 35% rate in January 2024 (The Information data)</p>\\n<p><a id=\\"source-51\\"><strong>51.</strong></a> <a href=\\"https://lesbarclays.substack.com/p/who-captures-the-value-when-ai-inference\\" target=\\"_blank\\" rel=\\"noreferrer\\">Les Barclays / Substack — &quot;Who Captures the Value When AI Inference Becomes Cheap?&quot;</a> — Cost per query increasing for frontier models even as cost per token declines; models employing test-time scaling consume multiple tokens per problem; at current pace OpenAI's competitive advantage may dissipate</p>\\n<p><a id=\\"source-52\\"><strong>52.</strong></a> <a href=\\"https://foundationcapital.com/nvidias-ai-factory-bet/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Foundation Capital — &quot;NVIDIA's 'AI Factory' Bet&quot;</a> — Reasoning models require 20x more tokens and 150x more compute per query than traditional LLMs; enterprise applications projected to run hundreds of millions of agentic queries per month</p>\\n<p><a id=\\"source-53\\"><strong>53.</strong></a> <a href=\\"https://www.ikangai.com/the-llm-cost-paradox-how-cheaper-ai-models-are-breaking-budgets/\\" target=\\"_blank\\" rel=\\"noreferrer\\">iKangai — &quot;The LLM Cost Paradox: How 'Cheaper' AI Models Are Breaking Budgets&quot;</a> — At maximum reasoning settings, models consume 10,000+ reasoning tokens internally for a 200-token answer; token consumption explosion leaving AI companies scrambling to stay profitable</p>\\n<p><a id=\\"source-54\\"><strong>54.</strong></a> <a href=\\"https://www.arturmarkus.com/the-inference-cost-paradox-why-generative-ai-spending-surged-320-in-2025-despite-per-token-costs-dropping-1000x-and-what-it-means-for-your-ai-budget-in-2026/\\" target=\\"_blank\\" rel=\\"noreferrer\\">AI Unfiltered — &quot;The Inference Cost Paradox&quot;</a> — Enterprise AI spending surged 320% in 2025 despite per-token costs dropping 1,000x; organizations that budgeted for 20-30% increases found themselves scrambling by Q3; Jevons Paradox makes single-number AI budgets &quot;fantasy&quot;</p>\\n<p><a id=\\"source-55\\"><strong>55.</strong></a> <a href=\\"https://www.leaddigital.com/blog/a-token-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">LeadDigital — &quot;A Token Economy&quot;</a> — Inference costs fell 1,000-fold but demand rose 10,000-fold; Jevons Paradox in action; Gartner predicts 40% of enterprise applications will feature AI agents by end of 2026, up from 5% in 2025</p>\\n<p><a id=\\"source-56\\"><strong>56.</strong></a> <a href=\\"https://www.saastr.com/have-ai-gross-margins-really-turned-the-corner-the-real-math-behind-openais-70-compute-margin-and-why-b2b-startups-are-still-running-on-a-treadmill/\\" target=\\"_blank\\" rel=\\"noreferrer\\">SaaStr — &quot;Have AI Gross Margins Really Turned the Corner?&quot;</a> — Anthropic expects gross margin of 50% in 2025 and 77% by 2028; Cursor paying ~$650M/year to Anthropic on ~$500M revenue (negative 30% margin); Bessemer 2025 data shows AI startups averaging 25% gross margins; frontier models getting more expensive, not cheaper</p>\\n<p><a id=\\"source-57\\"><strong>57.</strong></a> <a href=\\"https://ebudget.ca.gov/2025-26/pdf/BudgetSummary/RevenueEstimates.pdf\\" target=\\"_blank\\" rel=\\"noreferrer\\">California 2025-26 Budget Revenue Estimates</a> — 67% of General Fund from personal income tax; capital gains = 16% of total tax liability (25% in boom years)</p>\\n<p><a id=\\"source-58\\"><strong>58.</strong></a> <a href=\\"https://en.wikipedia.org/wiki/2008%E2%80%932012_California_budget_crisis\\" target=\\"_blank\\" rel=\\"noreferrer\\">Wikipedia — &quot;2008-2012 California Budget Crisis&quot;</a> — State revenue dropped from ~$100B to ~$85B during dot-com bust and again during Great Recession</p>\\n<p><a id=\\"source-59\\"><strong>59.</strong></a> <a href=\\"https://www.cbpp.org/research/economy/the-legacy-of-the-great-recession\\" target=\\"_blank\\" rel=\\"noreferrer\\">Center on Budget and Policy Priorities — &quot;Legacy of the Great Recession&quot;</a> — 8.7 million jobs lost in private sector during Great Recession</p>\\n<p><a id=\\"source-60\\"><strong>60.</strong></a> <a href=\\"https://laborcenter.berkeley.edu/\\" target=\\"_blank\\" rel=\\"noreferrer\\">UC Berkeley Labor Center — &quot;California Furloughs 2009&quot;</a> — 193,000 state workers furloughed; 2-3 unpaid days per month; 13.8% effective pay reduction</p>\\n<p><a id=\\"source-61\\"><strong>61.</strong></a> <a href=\\"https://www.calhr.ca.gov/\\" target=\\"_blank\\" rel=\\"noreferrer\\">CalHR — Furlough Program Manual</a> — Furlough hours banked as leave credits; paid out at separation at current base pay rate after COLA increases</p>\\n<p><a id=\\"source-62\\"><strong>62.</strong></a> <a href=\\"https://www.csmonitor.com/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Christian Science Monitor — &quot;Government Jobs: A Recession Refuge?&quot; (2009)</a> — Public sector employment didn't drop during 1991 recession; didn't decline after dot-com bust until 2004; lagged private sector contractions by years</p>\\n<p><a id=\\"source-63\\"><strong>63.</strong></a> <a href=\\"https://www.bls.gov/opub/mlr/2011/\\" target=\\"_blank\\" rel=\\"noreferrer\\">BLS Monthly Labor Review (2011) — &quot;The Recession of 2007-2009&quot;</a> — State and local governments shed 68,000 jobs (0.3% decline) vs. millions in private sector</p>\\n<p><a id=\\"source-64\\"><strong>64.</strong></a> <a href=\\"https://www.governing.com/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Governing — &quot;State Budget Actions in Recessions&quot; (2024)</a> — FY2010: 26 states used layoffs, 22 states used furloughs as primary budget-balancing tool</p>\\n<p><a id=\\"source-65\\"><strong>65.</strong></a> <a href=\\"https://lao.ca.gov/\\" target=\\"_blank\\" rel=\\"noreferrer\\">California Legislative Analyst's Office — 2025-26 Budget Analysis</a> — California has used furloughs in 9 fiscal years since 1992</p>\\n<p><a id=\\"source-66\\"><strong>66.</strong></a> <a href=\\"https://www.ncbi.nlm.nih.gov/pmc/\\" target=\\"_blank\\" rel=\\"noreferrer\\">PMC / Annals of the American Academy of Political and Social Science — &quot;Safety Net Programs in the Great Recession&quot;</a> — Safety net caseloads rose from 276 million to 310 million recipients during the Great Recession; countercyclical demand expanded public sector workload</p>\\n<p><a id=\\"source-67\\"><strong>67.</strong></a> <a href=\\"https://www.bls.gov/news.release/union2.nr0.htm\\" target=\\"_blank\\" rel=\\"noreferrer\\">BLS — &quot;Union Members — 2025&quot;</a> — Public sector union membership rate 32.9% vs. private sector 5.9%; local government workers at 37.8%</p>\\n<hr>\\n<p><em>This analysis reflects the views of PenPublic and is informed by publicly available economic research and reporting. We encourage readers to review the cited sources and draw their own conclusions.</em></p>\\n<p><em><a href=\\"https://penpublic.com\\" target=\\"_blank\\" rel=\\"noreferrer\\">PenPublic</a> — Your guide to public sector careers.</em></p>\\n","frontmatter":{"title":"The AI Bubble Won't Take Your Job — But Its Collapse Might","date":"2026-03-01T12:00:00.000Z","description":"Why the coming AI reckoning makes public sector careers the smartest move you can make","author":"Penny","tags":["AI","Economy","Public Sector Jobs"]},"excerpt":"<h1 id=\\"the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" tabindex=\\"-1\\">The AI Bubble Won't Take Your Job — But Its Collapse Might <a class=\\"header-anchor\\" href=\\"#the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" aria-label=\\"Permalink to &quot;The AI Bubble Won't Take Your Job — But Its Collapse Might&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p><em>Why the coming AI reckoning makes public sector careers the smartest move you can make</em></p>\\n<p><em>By Penny | March 1, 2026 (updated Mar 3, 2026)</em></p>\\n","url":"/blog/2026-03-01_ai-bubble-government-jobs.html"}],"Economy":[{"html":"<h1 id=\\"the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" tabindex=\\"-1\\">The AI Bubble Won't Take Your Job — But Its Collapse Might <a class=\\"header-anchor\\" href=\\"#the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" aria-label=\\"Permalink to &quot;The AI Bubble Won't Take Your Job — But Its Collapse Might&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p><em>Why the coming AI reckoning makes public sector careers the smartest move you can make</em></p>\\n<p><em>By Penny | March 1, 2026 (updated Mar 3, 2026)</em></p>\\n<hr>\\n<h2 id=\\"key-takeaways\\" tabindex=\\"-1\\">Key Takeaways <a class=\\"header-anchor\\" href=\\"#key-takeaways\\" aria-label=\\"Permalink to &quot;Key Takeaways&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Thesis: The AI bubble will collapse — and when it does, the layoffs won't be because AI took your job. They'll be because of the recession it causes.</strong></p>\\n<ul>\\n<li><strong><a href=\\"#the-real-threat-ai-layoffs-that-aren-t-about-ai\\">The real threat: AI layoffs that aren't about AI</a></strong> — the bubble's collapse will tank the economy and trigger mass layoffs misattributed to &quot;AI disruption&quot;</li>\\n<li><strong><a href=\\"#the-ai-investment-that-isn-t-working\\">AI doesn't work for most businesses</a></strong> — MIT found a 95% failure rate for enterprise AI projects <a href=\\"#source-1\\">[1]</a>, and only 14% of CFOs report measurable ROI <a href=\\"#source-4\\">[4]</a>\\n<ul>\\n<li>IBM found AI initiatives return 5.9% ROI on a 10% capital investment — companies are losing money <a href=\\"#source-3\\">[3]</a></li>\\n<li>Forrester predicts 25% of planned 2026 AI spending will be deferred to 2027 <a href=\\"#source-2\\">[2]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\">Goldman Sachs says AI contributed &quot;basically zero&quot; to U.S. GDP growth</a></strong> — most AI spending flows to Taiwan and South Korea for imported chips <a href=\\"#source-7\\">[7]</a> <a href=\\"#source-8\\">[8]</a>\\n<ul>\\n<li>Only 0.2% of the U.S. economy's 2.2% growth in 2025 came from AI investment <a href=\\"#source-10\\">[10]</a></li>\\n<li>Tech companies plan to spend $700B on AI in 2026; J.P. Morgan says AI needs $600B/year in revenue just to break even <a href=\\"#source-10\\">[10]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-stock-market-is-built-on-spending-not-returns\\">The stock market rally is built on AI spending, not AI returns</a></strong> — AI stocks account for 75% of all S&amp;P 500 returns since ChatGPT launched <a href=\\"#source-29\\">[29]</a>, but generate only 32% of index earnings <a href=\\"#source-31\\">[31]</a>\\n<ul>\\n<li>Strip out tech and communications, and the S&amp;P 500 returned just 6% in 2025 <a href=\\"#source-30\\">[30]</a></li>\\n<li>Apollo's chief economist says the AI bubble is now bigger than the 1990s IT bubble <a href=\\"#source-33\\">[33]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-110-billion-question\\">OpenAI's $110B round is a house of cards</a></strong> — Amazon invests $50B, OpenAI commits to spending $100B on AWS; money just circulates <a href=\\"#source-13\\">[13]</a>\\n<ul>\\n<li>OpenAI spent $9B to lose $5B in 2025 <a href=\\"#source-17\\">[17]</a></li>\\n<li>AI-related debt issuance crossed $200B, representing 30% of all USD credit supply <a href=\\"#source-11\\">[11]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-subsidized-illusion\\">AI subscriptions are subsidized below true cost</a></strong> — your $20/mo plan likely costs $1,000-2,000+/mo to serve <a href=\\"#source-18\\">[18]</a>\\n<ul>\\n<li>Even the $200/mo ChatGPT Pro loses money on power users (per Sam Altman) <a href=\\"#source-19\\">[19]</a></li>\\n<li>As Ed Zitron documents, every level of the AI value chain is unprofitable <a href=\\"#source-17\\">[17]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#but-what-about-anthropic\\">Even &quot;responsible&quot; Anthropic can't make the math work</a></strong> — its AWS bill alone consumed 100% of revenue through September 2025 <a href=\\"#source-34\\">[34]</a>, before paying for Google Cloud, salaries, data centers, or anything else\\n<ul>\\n<li>Claude Code subscribers consume $8-13.50 in compute for every $1 they pay <a href=\\"#source-46\\">[46]</a></li>\\n<li>Anthropic projects $80B in total cloud spend through 2029 <a href=\\"#source-39\\">[39]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#but-inference-costs-are-dropping-exponentially\\">Falling inference costs won't save them</a></strong> — the 280x cost drop is for GPT-3.5-level performance, a model nobody wants anymore <a href=\\"#source-48\\">[48]</a>; reasoning models consume 20x more compute per query <a href=\\"#source-52\\">[52]</a>\\n<ul>\\n<li>Jevons Paradox: inference costs fell 1,000x but demand rose 10,000x — total enterprise AI spending surged 320% in 2025 <a href=\\"#source-55\\">[55]</a></li>\\n<li>Cursor paid ~$650M/year to Anthropic while earning ~$500M — a negative 30% gross margin <a href=\\"#source-54\\">[54]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-k-shaped-economy-a-house-of-cards\\">The economy is a K-shape propped up by the wealthy</a></strong> — top 10% accounts for 50% of all consumer spending, driven by inflated stock portfolios <a href=\\"#source-21\\">[21]</a>\\n<ul>\\n<li>Bottom 80% hasn't outpaced inflation in 6 years <a href=\\"#source-23\\">[23]</a></li>\\n<li>$180B in consumer spending is driven by AI-inflated stock wealth effect alone <a href=\\"#source-27\\">[27]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#why-public-sector-careers-are-the-smart-play\\">Public sector careers are the smart play</a></strong> — California's budget will take a hit, but public sector workers get furloughs, not layoffs — and keep their pensions, health insurance, and union protection through every recession <a href=\\"#source-57\\">[57]</a> <a href=\\"#source-60\\">[60]</a> <a href=\\"#source-66\\">[66]</a></li>\\n</ul>\\n<hr>\\n<h2 id=\\"the-real-threat-ai-layoffs-that-aren-t-about-ai\\" tabindex=\\"-1\\">The Real Threat: AI Layoffs That Aren't About AI <a class=\\"header-anchor\\" href=\\"#the-real-threat-ai-layoffs-that-aren-t-about-ai\\" aria-label=\\"Permalink to &quot;The Real Threat: AI Layoffs That Aren't About AI&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's the thesis that ties it all together, and the reason you should be thinking about career stability right now.</p>\\n<p><strong>AI will cause mass layoffs — not because the technology replaced workers, but because the financial bubble built around it will collapse and drag the broader economy down.</strong></p>\\n<p>The causal chain looks like this:</p>\\n<ol>\\n<li>AI spending inflates tech valuations and GDP numbers</li>\\n<li>Inflated stocks create a wealth effect that drives consumer spending among the top 10%</li>\\n<li>The bottom 80% is already stretched thin, running on debt</li>\\n<li>Enterprise AI fails to deliver ROI — 95% of projects show no measurable returns</li>\\n<li>Companies begin cutting AI budgets (already happening — Forrester projects 25% deferrals)</li>\\n<li>Tech stocks correct as the narrative shifts</li>\\n<li>The wealth effect reverses — wealthy consumers pull back</li>\\n<li>Nobody else can pick up the slack because they were already tapped out</li>\\n<li>GDP contracts from multiple directions simultaneously</li>\\n<li>Companies execute mass layoffs to protect margins</li>\\n</ol>\\n<p>And here's the cruelest irony: <strong>the headlines will say &quot;AI replaced these workers.&quot;</strong> CEOs will frame layoffs as &quot;AI-driven transformation&quot; because it sounds strategic. Media will repeat the narrative because it's a clean story. But the reality is that the jobs disappeared because the financial infrastructure collapsed, not because a chatbot learned to do them.</p>\\n<p>We've seen this exact pattern before. Dot-com bust workers didn't lose jobs because websites replaced them — they lost jobs because companies had hired against inflated revenue projections that evaporated overnight. The 2008 financial crisis didn't eliminate construction jobs because buildings got smarter — it eliminated them because the financing structure collapsed.</p>\\n<hr>\\n<h2 id=\\"the-ai-investment-that-isn-t-working\\" tabindex=\\"-1\\">The AI Investment That Isn't Working <a class=\\"header-anchor\\" href=\\"#the-ai-investment-that-isn-t-working\\" aria-label=\\"Permalink to &quot;The AI Investment That Isn't Working&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Let's start with the most inconvenient fact in technology right now: <strong>AI doesn't work for most businesses.</strong></p>\\n<p>A landmark study from MIT found a staggering <strong>95% failure rate for enterprise generative AI projects</strong>, defined as not having shown measurable financial returns within six months <a href=\\"#source-1\\">[1]</a>. This isn't a fringe finding. Forrester Research reports that only 15% of AI decision-makers saw a positive impact on profitability, and predicts that enterprises will <strong>defer 25% of planned 2026 AI spending into 2027</strong> because the returns simply aren't there <a href=\\"#source-2\\">[2]</a>.</p>\\n<p>IBM's own research found that enterprise-wide AI initiatives achieved an <strong>ROI of just 5.9% despite requiring a 10% capital investment</strong> — meaning companies are literally losing money on AI <a href=\\"#source-3\\">[3]</a>. And only 14% of CFOs report measurable ROI from AI to date <a href=\\"#source-4\\">[4]</a>. Recent enterprise surveys confirm that <strong>90-95% of organizations are seeing little to no measurable financial return</strong> on their AI investments <a href=\\"#source-5\\">[5]</a>.</p>\\n<p>If you work in the public sector and your agency rolled out Microsoft Copilot, ask yourself: does anyone actually use it? The answer, overwhelmingly across both public and private sectors, is no. Nearly 70% of Fortune 500 companies are paying for Copilot, but the productivity benefits are so diffuse they don't move the needle on actual business results <a href=\\"#source-6\\">[6]</a>.</p>\\n<hr>\\n<h2 id=\\"goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\" tabindex=\\"-1\\">Goldman Sachs Says AI Contributed &quot;Basically Zero&quot; to the Economy <a class=\\"header-anchor\\" href=\\"#goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\" aria-label=\\"Permalink to &quot;Goldman Sachs Says AI Contributed &quot;Basically Zero&quot; to the Economy&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>In late February 2026, Goldman Sachs Chief Economist Jan Hatzius dropped a bombshell in an interview with the Atlantic Council. AI investment spending, he said, has had <strong>&quot;basically zero&quot;</strong> contribution to U.S. GDP growth <a href=\\"#source-7\\">[7]</a>.</p>\\n<p>&quot;We don't actually view AI investment as strongly growth positive,&quot; Hatzius stated. &quot;I think there's a lot of misreporting, actually, of the impact AI investment had on U.S. GDP growth in 2025, and it's much smaller than is often perceived.&quot; <a href=\\"#source-7\\">[7]</a></p>\\n<p>The reason is straightforward: most AI equipment is imported. The chips come from Taiwan. The hardware comes from South Korea. As Hatzius put it: &quot;A lot of the AI investment that we're seeing in the U.S. adds to Taiwanese GDP, and it adds to Korean GDP but not really that much to U.S. GDP.&quot; <a href=\\"#source-8\\">[8]</a></p>\\n<p>His colleague Joseph Briggs made the same case to the Washington Post, calling the AI-as-growth-engine story &quot;very intuitive&quot; but ultimately misleading — it &quot;maybe prevented or limited the need to actually dig deeper into what was happening.&quot; <a href=\\"#source-9\\">[9]</a></p>\\n<p>Of the U.S. economy's 2.2% growth in 2025, analyst Joseph Politano calculates that only <strong>0.2% was attributable to AI investment</strong> after accounting for imports <a href=\\"#source-10\\">[10]</a>. Meanwhile, tech companies are expected to spend <strong>$700 billion on AI infrastructure in 2026</strong> <a href=\\"#source-10\\">[10]</a>. J.P. Morgan has calculated that AI would need to generate over <strong>$600 billion in annual revenue</strong> just to achieve a 10% return on infrastructure expenditures <a href=\\"#source-10\\">[10]</a>. Current total AI industry revenue is a fraction of that.</p>\\n<p>Deutsche Bank has warned that the <strong>U.S. would be close to recession without tech-related spending</strong> <a href=\\"#source-11\\">[11]</a> — which sounds like AI is saving the economy until you realize the money mostly flows overseas. An analysis from MRB Partners found that after adjusting for high-tech imports, AI's net contribution to GDP growth was only <strong>20-25%</strong>, not the 40-92% figures that dominated headlines <a href=\\"#source-12\\">[12]</a>.</p>\\n<hr>\\n<h2 id=\\"the-stock-market-is-built-on-spending-not-returns\\" tabindex=\\"-1\\">The Stock Market Is Built on Spending, Not Returns <a class=\\"header-anchor\\" href=\\"#the-stock-market-is-built-on-spending-not-returns\\" aria-label=\\"Permalink to &quot;The Stock Market Is Built on Spending, Not Returns&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's the critical distinction most analysts gloss over: <strong>AI is driving stock prices. It is not driving profits.</strong></p>\\n<p>Since ChatGPT launched in November 2022, AI-related stocks have accounted for <strong>75% of all S&amp;P 500 returns, 80% of earnings growth, and 90% of capital spending growth</strong>, according to J.P. Morgan Asset Management's Michael Cembalest <a href=\\"#source-29\\">[29]</a>. In 2025 alone, the Magnificent Seven were responsible for <strong>42% of the S&amp;P 500's 17.9% return</strong> for the year <a href=\\"#source-30\\">[30]</a>. If you strip out the tech and communications sectors entirely, the S&amp;P 500 would have returned just <strong>6%</strong> in 2025 <a href=\\"#source-30\\">[30]</a>. Seven companies with AI exposure — NVIDIA, Alphabet, Microsoft, Broadcom, JPMorgan Chase, Palantir, and Meta — delivered over <strong>half</strong> of the entire index's gains <a href=\\"#source-31\\">[31]</a>.</p>\\n<p>This means the entire stock market rally — the one powering the wealth effect, driving consumer spending, and propping up GDP — is built on one bet: that AI spending will eventually produce returns. But as we've just seen, Goldman Sachs says it's contributed &quot;basically zero&quot; to the economy. MIT says 95% of enterprise projects fail. Only 14% of CFOs can point to measurable ROI.</p>\\n<p><strong>The money is real. The spending is real. The returns aren't.</strong></p>\\n<p>And the gap between market hype and economic reality is widening. The top 10 stocks now represent <strong>41% of the S&amp;P 500's total weight but generate only about 32% of its earnings</strong> — a gap that has widened meaningfully since 2015, when weight and earnings contribution were closely aligned <a href=\\"#source-31\\">[31]</a>. Goldman Sachs' own equity research team acknowledges that the &quot;combination of elevated valuations, extreme concentration, and strong recent returns rhymes with a handful of overextended equity markets during the last century&quot; <a href=\\"#source-32\\">[32]</a>. AI capex is on track to reach <strong>75% of cash flows</strong> for the largest tech companies — similar to tech spending in the late 1990s — and future spending growth will increasingly rely on debt <a href=\\"#source-32\\">[32]</a>.</p>\\n<p>Apollo's chief economist Torsten Slok has published research showing that <strong>the AI bubble is now bigger than the IT bubble of the 1990s</strong>, with the average P/E ratio of the top 10 S&amp;P 500 companies sitting around 50 and hyperscaler capital expenditure as a share of GDP exceeding the dotcom era <a href=\\"#source-33\\">[33]</a>. His bottom line: investors in the S&amp;P 500 &quot;remain overexposed to AI&quot; <a href=\\"#source-33\\">[33]</a>.</p>\\n<p>Think of it like Cisco in 1999. Cisco had real revenue — they were selling real routers to real companies building out internet infrastructure. The stock price reflected the spending story, not the returns story. The companies buying the routers never built sustainable businesses on top of them. When the spending stopped, Cisco's stock dropped 86% and never recovered its peak. Today, NVIDIA is the Cisco of the AI era — posting real revenue because hyperscalers are writing enormous checks for GPUs. But the companies buying those GPUs can't show a return on the investment. The spending is driving the stock, not the other way around.</p>\\n<hr>\\n<h2 id=\\"the-110-billion-question\\" tabindex=\\"-1\\">The $110 Billion Question <a class=\\"header-anchor\\" href=\\"#the-110-billion-question\\" aria-label=\\"Permalink to &quot;The $110 Billion Question&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>On February 27, 2026, OpenAI announced a <strong>$110 billion funding round</strong> — the largest private fundraise in history — at a $730 billion pre-money valuation. Amazon invested $50 billion, with Nvidia and SoftBank contributing $30 billion each <a href=\\"#source-13\\">[13]</a> <a href=\\"#source-14\\">[14]</a>.</p>\\n<p>These numbers sound impressive until you examine the structure. Amazon invests $50 billion in OpenAI, and OpenAI commits to spending $100 billion on AWS over eight years <a href=\\"#source-13\\">[13]</a>. The money flows out and comes right back. It's not a clean investment — it's a customer acquisition cost disguised as a capital raise. For context, this single round exceeds the <strong>$170 billion in total U.S. venture capital investment for all of 2023</strong> <a href=\\"#source-15\\">[15]</a>.</p>\\n<p>Reporting has revealed that OpenAI's Stargate joint venture involves very little actual collaboration among partners, with most data centers being traditional bilateral deals rather than the unified project that was announced — described by one outlet as better understood as <strong>&quot;a branding exercise than a real entity&quot;</strong> <a href=\\"#source-16\\">[16]</a>.</p>\\n<p>And the investor pool is narrowing. This round came from just three megaplayers who are simultaneously OpenAI's suppliers and customers. That's not a sign of broad market confidence. That's a sign that the only people willing to write checks are those with strategic reasons beyond financial return.</p>\\n<hr>\\n<h2 id=\\"the-subsidized-illusion\\" tabindex=\\"-1\\">The Subsidized Illusion <a class=\\"header-anchor\\" href=\\"#the-subsidized-illusion\\" aria-label=\\"Permalink to &quot;The Subsidized Illusion&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's something most AI users don't realize: <strong>your subscription is being heavily subsidized by investor capital.</strong> Tech journalist <a href=\\"https://www.wheresyoured.at/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron</a> has been documenting this dynamic extensively, and the numbers are damning.</p>\\n<p>As Zitron details, OpenAI spent <strong>50% of its revenue on inference compute costs alone, and 75% on training compute</strong> — numbers that add up to well over 100% of revenue. They spent $9 billion to lose $5 billion <a href=\\"#source-17\\">[17]</a>. And it's not just OpenAI. Perplexity spent <strong>164% of its revenue</strong> on AWS, Anthropic, and OpenAI costs in 2024 <a href=\\"#source-17\\">[17]</a>.</p>\\n<p>Zitron's core observation cuts to the heart of the problem: &quot;Anybody funding an AI startup is effectively sending that money to Anthropic or OpenAI, who then immediately send that money to Amazon, Google or Microsoft, who are yet to show that they make any profit on selling it.&quot; <a href=\\"#source-17\\">[17]</a> The money cascades down and evaporates at every level. Nobody in the chain is profitable.</p>\\n<p>A developer using Claude Code eight hours a day can cost the provider <strong>tens of thousands of dollars per month</strong> in compute — on a $200 subscription <a href=\\"#source-18\\">[18]</a>. OpenAI's CEO Sam Altman has publicly acknowledged that even the <strong>$200/month ChatGPT Pro tier loses money</strong> on power users <a href=\\"#source-19\\">[19]</a>. The true cost of serving a heavy AI user is likely <strong>$1,000 to $2,000+ per month</strong>, not the $20-200 consumers pay.</p>\\n<p>AI companies are running the same playbook as Uber and WeWork — price below cost to capture market share, subsidize the difference with investor billions, and figure out profitability later <a href=\\"#source-20\\">[20]</a>. When investor subsidies dry up — whether through funding fatigue, a market correction, or companies simply running out of runway — prices must rise to reflect reality. And at real prices, the value proposition collapses for the vast majority of users. If most enterprise users don't find AI useful at $0 (the Copilot licenses their companies pay for that go unused), they certainly won't pay $2,000/month.</p>\\n<p>AI-related debt issuance in credit markets crossed <strong>$200 billion in 2025</strong>, representing 30% of all USD credit supply <a href=\\"#source-11\\">[11]</a>. Hyperscalers are projected to spend a cumulative <strong>$4 trillion on AI data centers through 2030</strong> <a href=\\"#source-11\\">[11]</a>. These are staggering bets on a technology that 95% of enterprises can't generate returns from.</p>\\n<hr>\\n<h2 id=\\"but-what-about-anthropic\\" tabindex=\\"-1\\">But What About Anthropic? <a class=\\"header-anchor\\" href=\\"#but-what-about-anthropic\\" aria-label=\\"Permalink to &quot;But What About Anthropic?&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>If OpenAI is the poster child for AI excess, Anthropic is supposed to be the responsible adult — enterprise-focused, safety-conscious, targeting break-even by 2028 <a href=\\"#source-43\\">[43]</a>. But the numbers tell a different story.</p>\\n<p>Ed Zitron obtained Anthropic's AWS billing data and revealed that through September 2025, the company spent <strong>$2.66 billion on Amazon Web Services</strong> on an estimated <strong>$2.55 billion in revenue</strong> <a href=\\"#source-34\\">[34]</a>. Just the AWS bill — one line item from one cloud vendor — consumed every dollar the company earned. And as Zitron observed, the costs scale linearly with revenue, showing no evidence of improving margins at scale <a href=\\"#source-34\\">[34]</a>.</p>\\n<p>And that's before paying for anything else. Here's what sits on top, roughly ordered by magnitude:</p>\\n<ul>\\n<li><strong>Google Cloud compute</strong> (estimated $1.3B+ through Sept 2025) — Anthropic also runs on GCP, committed to a deal worth &quot;tens of billions&quot; for up to one million TPUs <a href=\\"#source-35\\">[35]</a>, and Zitron estimates their Google spend at a minimum of 50% of their AWS bill <a href=\\"#source-34\\">[34]</a>. Inference costs ran 23% over plan in 2025 <a href=\\"#source-36\\">[36]</a></li>\\n<li><strong>Salaries and compensation</strong> (~$500-600M/year) — over 1,200 employees <a href=\\"#source-37\\">[37]</a> with a median total compensation of $472,000; top AI researchers earning up to $759,000 <a href=\\"#source-38\\">[38]</a></li>\\n<li><strong>Revenue sharing with cloud platforms</strong> ($360M in 2025, scaling to $1.9B in 2026 and $6.4B by 2027) — AWS takes up to 50% of gross profits from AI sales on its platform; Google takes 20-30% of net revenue <a href=\\"#source-39\\">[39]</a> <a href=\\"#source-40\\">[40]</a></li>\\n<li><strong>Data center construction</strong> ($50B committed) — partnership with FluidStack to build facilities in Texas and New York, with sites expected online throughout 2026 <a href=\\"#source-41\\">[41]</a></li>\\n<li><strong>Microsoft Azure compute</strong> ($30B committed over time) — announced alongside a $5B Microsoft investment in November <a href=\\"#source-39\\">[39]</a></li>\\n<li><strong>Energy and grid infrastructure</strong> (uncapped commitment) — Anthropic publicly pledged to cover 100% of electricity price increases and grid upgrade costs for every community hosting its data centers <a href=\\"#source-42\\">[42]</a></li>\\n<li><strong>R&amp;D, safety research, and model training</strong> (hundreds of millions/year) — total company cash burn was $5.6B in 2024 and ~$3B in 2025 <a href=\\"#source-43\\">[43]</a>, and the costs above don't account for all of it</li>\\n<li><strong>Sales, marketing, and enterprise support</strong> (rapidly scaling) — serving 300,000+ business customers, with 500+ spending over $1M annually <a href=\\"#source-44\\">[44]</a></li>\\n<li><strong>Legal and IPO preparation</strong> (tens of millions) — retained Wilson Sonsini, the firm behind Google's and LinkedIn's IPOs, to advise on a potential 2026 listing <a href=\\"#source-45\\">[45]</a></li>\\n</ul>\\n<p>Claude Code, the company's breakout coding product, makes the math even worse — subscribers consume <strong>$8-13.50 in actual compute for every $1 they pay</strong>, meaning a $200/month user burns through over $2,700 in real costs <a href=\\"#source-46\\">[46]</a>.</p>\\n<p>So when Anthropic projects &quot;break-even by 2028,&quot; the question is: break-even on what definition? If the most disciplined company in the AI race spends 100% of revenue on a single vendor's cloud bill before touching any other expense, the industry's path to profitability isn't just narrow — it may not exist.</p>\\n<hr>\\n<h2 id=\\"but-inference-costs-are-dropping-exponentially\\" tabindex=\\"-1\\">“But Inference Costs Are Dropping Exponentially!” <a class=\\"header-anchor\\" href=\\"#but-inference-costs-are-dropping-exponentially\\" aria-label=\\"Permalink to &quot;“But Inference Costs Are Dropping Exponentially!”&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>They are. Stanford HAI’s 2025 AI Index Report found that inference costs for GPT-3.5-level performance dropped over <strong>280-fold</strong> between November 2022 and October 2024 <a href=\\"#source-48\\">[48]</a>. Epoch AI’s research measured declines ranging from <strong>9x to 900x per year</strong> depending on the task, with the fastest drops occurring after January 2024 <a href=\\"#source-49\\">[49]</a>. OpenAI’s internal compute margin hit <strong>70%</strong> by October 2025, double its January 2024 level <a href=\\"#source-50\\">[50]</a>. These are real gains. Nobody serious disputes them.</p>\\n<p>The problem is that none of it matters in the way the bulls need it to.</p>\\n<p><strong>The cost drops are happening on yesterday’s models. The frontier is a treadmill.</strong> The 280x improvement Stanford measured is for GPT-3.5-level performance — a model nobody wants anymore. Users now expect GPT-4-level quality and reasoning capabilities of o1-class models, which employ test-time scaling and consume vastly more tokens per query. The cost per query may actually be <em>increasing</em> for frontier models even as cost per token declines <a href=\\"#source-51\\">[51]</a>. Reasoning models require roughly <strong>20x more tokens and 150x more compute per query</strong> than traditional LLMs <a href=\\"#source-52\\">[52]</a>. At maximum reasoning settings, a simple question might consume <strong>10,000 reasoning tokens internally</strong> while returning a 200-token answer <a href=\\"#source-53\\">[53]</a>.</p>\\n<p>This is the trick hiding inside the headline numbers. Every time efficiency catches up to the current frontier, the frontier moves. GPT-3.5 costs collapse — but customers have migrated to GPT-4. GPT-4 costs collapse — but everyone’s running o1-class reasoning chains. It’s like celebrating that a 2019 Toyota got cheaper while your customers all want the 2026 model. The efficiency gains are perpetually arriving for the product the market has already moved past.</p>\\n<p>Anthropic expects its gross profit margin to reach 50% this year and 77% by 2028 — but the inference cost declines are happening on older models. Frontier models are getting more expensive, not cheaper <a href=\\"#source-56\\">[56]</a>. The rise of agentic workflows has caused token consumption per task to jump <strong>10-100x</strong> since December 2023. Every leap in capability resets the economics back to brutal.</p>\\n<p><strong>Jevons Paradox eats the savings.</strong> Even setting aside the frontier treadmill, cheaper inference doesn’t produce cheaper AI bills. It produces <em>more AI bills.</em> Inference costs fell roughly 1,000-fold, but demand rose 10,000-fold — cheaper tokens didn’t reduce spending, they unleashed it <a href=\\"#source-55\\">[55]</a>. Enterprise AI spending surged <strong>320%</strong> in 2025 despite per-token costs dropping 1,000x, because each price drop makes thousands of new use cases suddenly economically viable <a href=\\"#source-54\\">[54]</a>.</p>\\n<p>This isn’t speculation. It’s what happened with coal in the 1860s, bandwidth in the 2000s, and mobile data in the 2010s. Every time you make a resource cheaper, consumption expands to more than compensate. Satya Nadella said it himself the day DeepSeek launched: “Jevons paradox strikes again.” If your per-token cost drops from $0.06 to $0.00006, you don’t get savings — you get AI running on every customer service interaction, personalized content at the individual level, and agents iterating through dozens of reasoning steps per response <a href=\\"#source-54\\">[54]</a>. The volume explosion overwhelms any per-unit improvement.</p>\\n<p>For AI providers, this is actually <em>good</em> for revenue growth but <em>terrible</em> for the profitability thesis. More usage means more infrastructure, more GPUs, more power, more cooling. The denominator scales with the numerator. You’re running faster to stay in the same place.</p>\\n<p><strong>The application-layer margin squeeze is brutal.</strong> Even if you accept that the foundation model providers are improving their margins, the companies actually building products on top of those models are getting crushed. Cursor, the poster child for AI-powered coding tools, was reportedly paying approximately <strong>$650 million annually to Anthropic</strong> while generating only <strong>$500 million in revenue</strong> — a negative 30% gross margin. Their AWS bills doubled in a single month when Anthropic launched new pricing tiers <a href=\\"#source-56\\">[56]</a>.</p>\\n<p>This isn’t an outlier. Bessemer’s 2025 data shows fast-ramping AI startups averaging only <strong>25% gross margins</strong>, with many running negative. The traditional SaaS benchmark for a healthy gross margin is 75%+ <a href=\\"#source-56\\">[56]</a>. If you show up to a Series B with 25% margins, you’re not a software company — you’re a services business subsidizing your customers’ compute.</p>\\n<p>The inference cost curve is real. It’s also irrelevant to the question that actually matters: can these companies turn a profit before they run out of other people’s money? So far, every efficiency gain gets consumed by the next leap in model complexity, the next explosion in usage volume, or the next round of infrastructure buildout. The treadmill doesn’t stop. And yes, a true believer can argue that all of these trends will reverse at exactly the right moment — that costs will plateau just as capital dries up, that margins will appear just as subsidies vanish, that the history of every other capital-intensive bubble will suddenly stop applying. But that’s not an argument. That’s a hope dressed in a spreadsheet.</p>\\n<hr>\\n<h2 id=\\"the-k-shaped-economy-a-house-of-cards\\" tabindex=\\"-1\\">The K-Shaped Economy: A House of Cards <a class=\\"header-anchor\\" href=\\"#the-k-shaped-economy-a-house-of-cards\\" aria-label=\\"Permalink to &quot;The K-Shaped Economy: A House of Cards&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>The AI bubble doesn't exist in isolation. It sits on top of an already fragile economic structure that economists call the <strong>&quot;K-shaped economy&quot;</strong> — where the wealthy are thriving while everyone else falls behind.</p>\\n<p>The numbers are stark. The <strong>top 10% of earners now account for 50% of all consumer spending</strong>, up from 35% in the early 1990s <a href=\\"#source-21\\">[21]</a>. Moody's Analytics found that the top 20% accounts for <strong>59% of total spending</strong> <a href=\\"#source-22\\">[22]</a>. And for the bottom 80%? Their spending hasn't outpaced inflation over the last six years, meaning economic quality of life hasn't improved for the vast majority of Americans <a href=\\"#source-23\\">[23]</a>.</p>\\n<p>As of Q4 2025, the <strong>top 20% of households held nearly 72% of total household wealth</strong> <a href=\\"#source-24\\">[24]</a>. Lower-income households are increasingly relying on debt, with <strong>rising delinquency rates particularly in auto loans</strong> <a href=\\"#source-25\\">[25]</a>. Bank of America's analysis shows the divide is worsening, with some economists suggesting we've moved beyond a K-shape into a <strong>&quot;barbell economy&quot;</strong> heavily weighted at the extremes <a href=\\"#source-26\\">[26]</a>.</p>\\n<p>Much of the wealthy's spending is driven by the <strong>&quot;wealth effect&quot;</strong> — they spend more because their stock portfolios are up. And what's driving stock prices? AI hype. Soaring AI-related valuations alone have created an estimated <strong>$180 billion in additional consumer spending</strong> over the past year <a href=\\"#source-27\\">[27]</a>.</p>\\n<p>This creates a dangerous feedback loop: AI hype drives tech stocks up → rising stocks make wealthy people feel richer → wealthy people spend more → GDP looks healthy → the healthy GDP narrative justifies more AI investment → repeat.</p>\\n<p>Moody's chief economist Mark Zandi captured the fragility perfectly: <strong>&quot;It doesn't feel like the economy's perched on a strong foundation. It's perched on a few poles that are sticking up. If one of those poles gets knocked out, then the whole economy gets knocked down.&quot;</strong> <a href=\\"#source-23\\">[23]</a></p>\\n<p>Fortune published an analysis warning that wealthy consumers' spending is <strong>&quot;psychologically tethered to their portfolio balance&quot;</strong> — when the S&amp;P drops, they freeze discretionary spending. And in 2026, <strong>&quot;there is no one there to catch it&quot;</strong> because the bottom 80% has already depleted their pandemic-era savings <a href=\\"#source-28\\">[28]</a>.</p>\\n<p>U.S. Bank's chief economist Beth Ann Bovino put it plainly: <strong>&quot;We're increasingly dependent on healthier cohorts to keep the economy afloat.&quot;</strong> <a href=\\"#source-25\\">[25]</a> That's a polite way of saying the economy collapses if rich people stop spending — and rich people stop spending when their portfolios drop.</p>\\n<hr>\\n<h2 id=\\"why-public-sector-careers-are-the-smart-play\\" tabindex=\\"-1\\">Why Public Sector Careers Are the Smart Play <a class=\\"header-anchor\\" href=\\"#why-public-sector-careers-are-the-smart-play\\" aria-label=\\"Permalink to &quot;Why Public Sector Careers Are the Smart Play&quot;\\">&ZeroWidthSpace;</a></h2>\\n<h3 id=\\"yes-california-s-budget-will-take-a-hit-that-s-not-the-same-as-losing-your-job\\" tabindex=\\"-1\\"><em>Yes, California's budget will take a hit. That's not the same as losing your job.</em> <a class=\\"header-anchor\\" href=\\"#yes-california-s-budget-will-take-a-hit-that-s-not-the-same-as-losing-your-job\\" aria-label=\\"Permalink to &quot;*Yes, California's budget will take a hit. That's not the same as losing your job.*&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p>California gets 67% of its General Fund from personal income tax, and capital gains alone account for 16% of total tax liability — spiking to 25% in boom years <a href=\\"#source-57\\">[57]</a>. When the dot-com bubble burst, state revenue dropped from $100 billion to $85 billion <a href=\\"#source-58\\">[58]</a>. An AI correction will hit state budgets. This is not a hypothetical.</p>\\n<p>But here's what actually happens to public sector workers when budgets get slashed: <strong>they get furloughs, not layoffs.</strong></p>\\n<p>The private sector lost 8.7 million jobs during the Great Recession <a href=\\"#source-59\\">[59]</a>. Public sector employment <em>increased</em> by 590,000 in the first year <a href=\\"#source-47\\">[47]</a>. When budgets finally tightened, the failure mode was fundamentally different. State and local governments shed just 68,000 jobs — a 0.3% decline — while the private sector hemorrhaged millions <a href=\\"#source-63\\">[63]</a>. In FY2010, the worst budget year, 26 states used layoffs but 22 chose furloughs instead <a href=\\"#source-64\\">[64]</a>. California chose furloughs. It has chosen furloughs in nine of the fiscal years since 1992 <a href=\\"#source-65\\">[65]</a>.</p>\\n<p><strong>And furloughs aren't what most people think they are.</strong> California's 2009 furlough program covered 193,000 workers and imposed 2-3 unpaid days per month — a 13.8% reduction on paper <a href=\\"#source-60\\">[60]</a>. In reality, furlough hours were banked as leave credits and paid out at separation, often at a higher base pay after COLA increases <a href=\\"#source-61\\">[61]</a>. Workers kept their jobs, their health insurance, their pension accrual, and their seniority. The historical pattern is consistent: public sector employment didn't drop during the 1991 recession at all, didn't decline after the dot-com bust until 2004, and barely moved during 2008-2012 <a href=\\"#source-62\\">[62]</a>.</p>\\n<p>This stability isn't accidental — it's structural. <strong>Countercyclical demand</strong> means that when the private sector contracts, public sector workload expands. Safety net caseloads rose from 276 million to 310 million recipients during the Great Recession <a href=\\"#source-66\\">[66]</a>. Someone has to process those claims, maintain those roads, inspect those buildings, and run those programs. The work doesn't disappear when the economy does.</p>\\n<p><strong>Union protection</strong> reinforces the structural advantage. Public sector union density is 32.9% versus 5.9% in the private sector, and local agencies sit at 37.8% <a href=\\"#source-67\\">[67]</a>. That means layoffs happen by seniority, not by manager mood. Furloughs are negotiated, not dictated. You get a grievance process before termination. Civil service rules, merit-based hiring, and progressive discipline create layers of protection that simply don't exist in at-will private employment.</p>\\n<p><strong>And then there's the pension.</strong> Public sector workers earn defined-benefit retirement through CalPERS or CalSTRS — a guaranteed monthly income for life calculated from salary and years of service, not subject to market crashes. Thirty years of service typically yields 60-75% of final salary, guaranteed, regardless of what the stock market does. While private sector 401(k)s crater with every correction, public pensions pay out on schedule.</p>\\n<p>You can't be laid off because your company missed earnings. You can't be &quot;restructured&quot; because a VC pulled funding. Your position exists because the public needs the service — not because an investor believes in the growth story.</p>\\n<p>At <a href=\\"https://penpublic.com\\" target=\\"_blank\\" rel=\\"noreferrer\\">PenPublic</a>, we're building the most comprehensive public sector job platform in the country — aggregating positions across hundreds of agencies at the federal, state, and local level. Local agency jobs are the hardest to find because they're scattered across thousands of individual websites. We bring them together in one place. Whether you're a tech worker thinking about your next move, a recent graduate evaluating career paths, or a current public servant exploring new opportunities, we believe public service represents one of the smartest career investments you can make right now.</p>\\n<p>The AI bubble will pop. The K-shaped economy will correct. The question isn't whether disruption is coming — it's whether you'll be positioned on stable ground when it arrives.</p>\\n<hr>\\n<h2 id=\\"sources\\" tabindex=\\"-1\\">Sources <a class=\\"header-anchor\\" href=\\"#sources\\" aria-label=\\"Permalink to &quot;Sources&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><a id=\\"source-1\\"><strong>1.</strong></a> <a href=\\"https://thefinancialbrand.com/news/artificial-intelligence-banking/why-95-of-enterprises-are-getting-zero-return-on-ai-investment-191950\\" target=\\"_blank\\" rel=\\"noreferrer\\">MIT's The GenAI Divide: State of AI in Business 2025</a> — 95% failure rate for enterprise AI projects; $30-40B in investment with zero measurable return</p>\\n<p><a id=\\"source-2\\"><strong>2.</strong></a> <a href=\\"https://bizzdesign.com/blog/enterprise-ai-adoption-balancing-innovation-and-roi-2026\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bizzdesign — &quot;Enterprise AI Adoption: Balancing Innovation and ROI in 2026&quot;</a> — Only 15% report positive profitability impact; Forrester predicts 25% of 2026 AI spend deferred to 2027</p>\\n<p><a id=\\"source-3\\"><strong>3.</strong></a> <a href=\\"https://www.ibm.com/think/insights/ai-roi\\" target=\\"_blank\\" rel=\\"noreferrer\\">IBM — &quot;How to Maximize AI ROI in 2026&quot;</a> — 5.9% ROI on 10% capital investment; only 25% of AI initiatives deliver expected ROI; only 29% can measure ROI confidently</p>\\n<p><a id=\\"source-4\\"><strong>4.</strong></a> <a href=\\"https://medium.com/origintrail/5-trends-to-drive-the-ai-roi-in-2026-trust-is-capital-372ac5dabc38\\" target=\\"_blank\\" rel=\\"noreferrer\\">OriginTrail / Medium — &quot;5 Trends to Drive AI ROI in 2026&quot;</a> — Only 14% of CFOs report measurable ROI; MIT study confirms 95% failure rate</p>\\n<p><a id=\\"source-5\\"><strong>5.</strong></a> <a href=\\"https://www.consultingmag.com/2026/02/04/why-enterprise-ai-stalled-and-what-is-finally-changing-in-2026/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Consulting Magazine — &quot;Why Enterprise AI Stalled and What Is Finally Changing in 2026&quot;</a> — 90-95% of organizations seeing little to no measurable financial return; Gartner predicts 40% of agentic AI projects cancelled by 2027</p>\\n<p><a id=\\"source-6\\"><strong>6.</strong></a> <a href=\\"https://www.fullstack.com/labs/resources/blog/generative-ai-roi-why-80-of-companies-see-no-results\\" target=\\"_blank\\" rel=\\"noreferrer\\">FullStack Labs — &quot;Generative AI ROI: Why 80% Fail&quot;</a> — 70% of Fortune 500 use Copilot; 78% of companies report no significant bottom-line impact; only 1% view GenAI strategies as mature</p>\\n<p><a id=\\"source-7\\"><strong>7.</strong></a> <a href=\\"https://finance.yahoo.com/news/ai-contributed-basically-zero-us-181419807.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yahoo Finance — &quot;AI Contributed 'Basically Zero' to the US Economy, According to Goldman Sachs&quot;</a> — Goldman Sachs Chief Economist Jan Hatzius interview with Atlantic Council</p>\\n<p><a id=\\"source-8\\"><strong>8.</strong></a> <a href=\\"https://gizmodo.com/ai-added-basically-zero-to-us-economic-growth-last-year-goldman-sachs-says-2000725380\\" target=\\"_blank\\" rel=\\"noreferrer\\">Gizmodo — &quot;AI Added 'Basically Zero' to US Economic Growth Last Year, Goldman Sachs Says&quot;</a> — Hatzius on imported AI equipment boosting Taiwanese and Korean GDP</p>\\n<p><a id=\\"source-9\\"><strong>9.</strong></a> <a href=\\"https://futurism.com/future-society/researchers-economy-ai-narratives\\" target=\\"_blank\\" rel=\\"noreferrer\\">Futurism — &quot;Goldman Sachs Researchers Make Startling Claim About AI's Effects on the US Economy&quot;</a> — Joseph Briggs interview with Washington Post</p>\\n<p><a id=\\"source-10\\"><strong>10.</strong></a> <a href=\\"https://www.tomshardware.com/tech-industry/artificial-intelligence/ai-boosted-us-economy-by-basically-zero-in-2025-says-goldman-sachs-chief-economist-we-think-theres-been-a-lot-of-misreporting-of-the-impact-that-ai-investment-had-on-gdp-growth\\" target=\\"_blank\\" rel=\\"noreferrer\\">Tom's Hardware — &quot;AI Boosted US Economy by 'Basically Zero' in 2025, Says Goldman Sachs Chief Economist&quot;</a> — 0.2% AI contribution to 2.2% GDP growth; $700B projected 2026 spend; J.P. Morgan $600B revenue threshold</p>\\n<p><a id=\\"source-11\\"><strong>11.</strong></a> <a href=\\"https://fortune.com/2025/12/23/us-gdp-alive-by-ai-capex/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;A Huge Chunk of U.S. GDP Growth Is Being Kept Alive by AI Spending 'With No Guaranteed Return'&quot;</a> — Deutsche Bank recession warning; $200B AI-related credit issuance (30% of USD supply); $4 trillion cumulative data center spend projected through 2030</p>\\n<p><a id=\\"source-12\\"><strong>12.</strong></a> <a href=\\"https://www.cnbc.com/2026/01/26/ai-wasnt-the-biggest-engine-of-us-gdp-growth-in-2025.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">CNBC — &quot;AI Spending Wasn't the Biggest Engine of U.S. Economic Growth in 2025&quot;</a> — MRB Partners analysis; 20-25% net AI contribution after import adjustment; consumer spending as true growth driver</p>\\n<p><a id=\\"source-13\\"><strong>13.</strong></a> <a href=\\"https://techcrunch.com/2026/02/27/openai-raises-110b-in-one-of-the-largest-private-funding-rounds-in-history/\\" target=\\"_blank\\" rel=\\"noreferrer\\">TechCrunch — &quot;OpenAI Raises $110B in One of the Largest Private Funding Rounds in History&quot;</a> — $50B Amazon, $30B Nvidia, $30B SoftBank; stateful runtime on AWS Bedrock; $100B AWS commitment expansion</p>\\n<p><a id=\\"source-14\\"><strong>14.</strong></a> <a href=\\"https://www.bloomberg.com/news/articles/2026-02-27/openai-finalizes-110-billion-funding-at-730-billion-valuation\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bloomberg — &quot;OpenAI Finalizes $110 Billion Funding at $730 Billion Value&quot;</a> — $730B pre-money valuation; Amazon's $35B contingent on AGI or IPO</p>\\n<p><a id=\\"source-15\\"><strong>15.</strong></a> <a href=\\"https://www.axios.com/2026/02/27/openai-funding-nvidia-amazon\\" target=\\"_blank\\" rel=\\"noreferrer\\">Axios — &quot;OpenAI Secures $110B Funding Round&quot;</a> — Round exceeds total 2023 U.S. VC investment ($170B); Microsoft did not participate</p>\\n<p><a id=\\"source-16\\"><strong>16.</strong></a> <a href=\\"https://www.newcomer.co/p/openai-raises-110-billion-and-throws\\" target=\\"_blank\\" rel=\\"noreferrer\\">Newcomer — &quot;OpenAI Raises $110 Billion &amp; Throws In With Amazon&quot;</a> — Stargate described as &quot;branding exercise&quot;; little collaboration among partners; complicated financial structures becoming ordinary arrangements</p>\\n<p><a id=\\"source-17\\"><strong>17.</strong></a> <a href=\\"https://www.wheresyoured.at/why-everybody-is-losing-money-on-ai/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron / Where's Your Ed At — &quot;Why Everybody Is Losing Money on AI&quot;</a> — OpenAI: 50% revenue on inference, 75% on training (&gt;100% combined); $9B spent to lose $5B; Perplexity at 164% of revenue on compute; entire value chain unprofitable</p>\\n<p><a id=\\"source-18\\"><strong>18.</strong></a> <a href=\\"https://www.news.aakashg.com/p/how-to-price-ai-products\\" target=\\"_blank\\" rel=\\"noreferrer\\">Product Faculty / AI Pricing Guide 2026</a> — Claude Code heavy users cost &quot;tens of thousands per month&quot;; OpenAI projects $14B cumulative losses by end of 2026; AI SaaS gross margins 20-60% vs traditional 70-90%</p>\\n<p><a id=\\"source-19\\"><strong>19.</strong></a> <a href=\\"https://www.getmonetizely.com/blogs/ai-pricing-how-much-does-ai-cost-in-2025\\" target=\\"_blank\\" rel=\\"noreferrer\\">Monetizely — &quot;AI Pricing in 2025: Strategy for Costing&quot;</a> — Sam Altman admission that $200/mo Pro tier loses money on power users; AI gross margins under pressure industry-wide</p>\\n<p><a id=\\"source-20\\"><strong>20.</strong></a> <a href=\\"https://www.uptechstudio.com/blog/the-true-cost-of-ai-when-the-subsidies-run-out\\" target=\\"_blank\\" rel=\\"noreferrer\\">UpTech Studio — &quot;The True Cost of AI: When the Subsidies Run Out&quot;</a> — Uber/WeWork subsidy model comparison; land-grab pricing strategy; warning that 5x current AI costs would kill most AI startups</p>\\n<p><a id=\\"source-21\\"><strong>21.</strong></a> <a href=\\"https://www.pbs.org/newshour/show/k-shaped-economy-why-the-wealthy-are-thriving-as-most-americans-fall-behind\\" target=\\"_blank\\" rel=\\"noreferrer\\">PBS NewsHour — &quot;K-Shaped Economy: Why the Wealthy Are Thriving as Most Americans Fall Behind&quot;</a> — Top 10% = 50% of spending (up from 35% in early 1990s)</p>\\n<p><a id=\\"source-22\\"><strong>22.</strong></a> <a href=\\"https://finance.yahoo.com/video/wealth-inequality-k-shaped-economy-183000976.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yahoo Finance — Mark Zandi Interview: &quot;Wealth Inequality in K-Shaped Economy Is 'Corrosive'&quot;</a> — Top 20% = 59% of total spending (Moody's Analytics data)</p>\\n<p><a id=\\"source-23\\"><strong>23.</strong></a> <a href=\\"https://www.cnbc.com/2026/01/30/wealth-inequality-k-shaped-economy-united-states-consumer-spending-trump.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">CNBC — &quot;Wealth Inequality and the 'K-Shaped' Economy Are More Striking Than Ever&quot;</a> — Bottom 80% spending hasn't outpaced inflation in 6 years; Mark Zandi &quot;poles&quot; quote; rising auto loan delinquencies</p>\\n<p><a id=\\"source-24\\"><strong>24.</strong></a> <a href=\\"https://economics.td.com/us-k-shaped-consumer-spending\\" target=\\"_blank\\" rel=\\"noreferrer\\">TD Economics — &quot;U.S. Consumer Spending: Still a K, but That's OK&quot;</a> — Top 20% hold 72% of total household wealth as of Q4 2025; K-shape expected to deepen in 2026 due to tax policy</p>\\n<p><a id=\\"source-25\\"><strong>25.</strong></a> <a href=\\"https://www.usbank.com/corporate-and-commercial-banking/insights/economy/macro/k-shaped-economy.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">U.S. Bank — &quot;The K-Shaped Economy in 2026&quot;</a> — Lower-income households relying on debt; rising delinquency rates; Beth Ann Bovino quote on dependence on &quot;healthier cohorts&quot;</p>\\n<p><a id=\\"source-26\\"><strong>26.</strong></a> <a href=\\"https://fortune.com/2026/01/14/when-will-us-enter-recession-middle-class-barbell-k-shaped-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;Forget the K-Shape: We Have a Barbell Economy&quot;</a> — Economy described as &quot;dangerously brittle&quot;; wealthy spending tethered to portfolio balance; bottom 80% financing groceries with &quot;shadow debt&quot;</p>\\n<p><a id=\\"source-27\\"><strong>27.</strong></a> <a href=\\"https://www.empower.com/the-currency/money/life/k-shaped-economy-what-to-know-news\\" target=\\"_blank\\" rel=\\"noreferrer\\">Empower — &quot;The K-Shaped Economy: What Consumers Should Know&quot;</a> — $180B in wealth-effect consumer spending from AI-related stock valuations; Delta premium revenue up 9%, basic economy down 7%</p>\\n<p><a id=\\"source-28\\"><strong>28.</strong></a> <a href=\\"https://fortune.com/2026/01/14/when-will-us-enter-recession-middle-class-barbell-k-shaped-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;Forget the K-Shape: We Have a Barbell Economy&quot;</a> — &quot;No one there to catch it&quot; when wealthy pull back; pandemic savings depleted; economy has &quot;massive engine and insufficient braking mechanisms&quot;</p>\\n<p><a id=\\"source-29\\"><strong>29.</strong></a> <a href=\\"https://insights.som.yale.edu/insights/this-is-how-the-ai-bubble-bursts\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yale Insights / Jeffrey Sonnenfeld — &quot;This Is How the AI Bubble Bursts&quot;</a> — J.P. Morgan's Cembalest: AI stocks = 75% of S&amp;P 500 returns, 80% of earnings growth, 90% of capex growth since ChatGPT launch; two-thirds of U.S. deal value going to AI/ML startups in H1 2025</p>\\n<p><a id=\\"source-30\\"><strong>30.</strong></a> <a href=\\"https://www.statista.com/chart/30318/sector-contributions-to-sp500-return/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Statista — &quot;Wider Tech Sector Led S&amp;P 500 to Another Double-Digit Gain&quot;</a> — Mag 7 = 42% of S&amp;P 500's 17.9% return in 2025; tech and communications = 63.1% of total return; excluding those sectors, S&amp;P 500 returned just 6%</p>\\n<p><a id=\\"source-31\\"><strong>31.</strong></a> <a href=\\"https://www.rbcwealthmanagement.com/en-us/insights/us-equity-returns-in-2025-record-breaking-resilience\\" target=\\"_blank\\" rel=\\"noreferrer\\">RBC Wealth Management — &quot;U.S. Equity Returns in 2025: Record-Breaking Resilience&quot; and &quot;The 'Great Narrowing': S&amp;P 500 Concentration&quot;</a> — Seven AI-exposed stocks = over half of S&amp;P 500 gains; top 10 = 41% of weight but ~32% of earnings; cap-weighted index outperformed equal-weight by 32% over 3 years</p>\\n<p><a id=\\"source-32\\"><strong>32.</strong></a> <a href=\\"https://www.goldmansachs.com/insights/articles/the-sp-500-expected-to-rally-12-this-year\\" target=\\"_blank\\" rel=\\"noreferrer\\">Goldman Sachs — &quot;The S&amp;P 500 Is Expected to Rally 12% This Year&quot;</a> — Top tech stocks = 53% of S&amp;P 500 return in 2025; AI capex reaching 75% of cash flows; &quot;elevated valuations, extreme concentration, and strong recent returns rhymes with overextended equity markets during the last century&quot;</p>\\n<p><a id=\\"source-33\\"><strong>33.</strong></a> <a href=\\"https://www.apolloacademy.com/extreme-ai-concentration-in-the-sp-500/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Apollo Academy / Torsten Slok — &quot;Extreme AI Concentration in the S&amp;P 500&quot;</a> — AI bubble bigger than IT bubble in 1990s; average P/E of top 10 around 50; hyperscaler capex as share of GDP exceeds dotcom era; investors &quot;remain overexposed to AI&quot;</p>\\n<p><a id=\\"source-34\\"><strong>34.</strong></a> <a href=\\"https://www.wheresyoured.at/costs/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron / Where's Your Ed At — &quot;This Is How Much Anthropic and Cursor Spend on Amazon Web Services&quot;</a> — $2.66B AWS spend on $2.55B revenue through September 2025; costs scale linearly with revenue; estimates Google Cloud spend at minimum 50% of AWS</p>\\n<p><a id=\\"source-35\\"><strong>35.</strong></a> <a href=\\"https://www.anthropic.com/news/expanding-our-use-of-google-cloud-tpus-and-services\\" target=\\"_blank\\" rel=\\"noreferrer\\">Anthropic — &quot;Expanding Our Use of Google Cloud TPUs and Services&quot;</a> — Deal worth &quot;tens of billions of dollars&quot; for up to one million TPUs; over a gigawatt of capacity expected online in 2026</p>\\n<p><a id=\\"source-36\\"><strong>36.</strong></a> <a href=\\"https://www.aiplanetx.com/p/cloud-spending-hits-anthropic\\" target=\\"_blank\\" rel=\\"noreferrer\\">AI Planet X — &quot;Cloud Spending Hits Anthropic&quot;</a> — Inference costs on Google and Amazon cloud ran 23% over plan; gross margin pushed toward ~40%; ~$5.2B burn in 2025</p>\\n<p><a id=\\"source-37\\"><strong>37.</strong></a> <a href=\\"https://www.pminsights.com/insights/anthropic-approaches-7b-run-rate-in-2025-outpaces-openai\\" target=\\"_blank\\" rel=\\"noreferrer\\">PM Insights — &quot;Anthropic Approaches $7B Run Rate&quot;</a> — Over 1,200 employees by late 2025; plans to triple international workforce and quintuple applied AI team</p>\\n<p><a id=\\"source-38\\"><strong>38.</strong></a> <a href=\\"https://www.levels.fyi/companies/anthropic/salaries\\" target=\\"_blank\\" rel=\\"noreferrer\\">Levels.fyi — Anthropic Salaries</a> — Median yearly total compensation $471,808; highest reported $759,413 for Lead Software Engineer</p>\\n<p><a id=\\"source-39\\"><strong>39.</strong></a> <a href=\\"https://www.datacenterdynamics.com/en/news/anthropic-cloud-spend-expected-to-reach-80bn-through-2029/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Data Center Dynamics — &quot;Anthropic Cloud Spend Expected to Reach $80B Through 2029&quot;</a> — $80B total cloud spend projected through 2029 across AWS, Google, and Microsoft; AWS takes up to 50% of gross profits; Google takes 20-30% of net revenue; $30B Microsoft Azure commitment</p>\\n<p><a id=\\"source-40\\"><strong>40.</strong></a> <a href=\\"https://www.pymnts.com/artificial-intelligence-2/2026/anthropic-set-to-pay-cloud-partners-80-billion-through-2029/\\" target=\\"_blank\\" rel=\\"noreferrer\\">PYMNTS — &quot;Anthropic Set to Pay Cloud Partners $80 Billion Through 2029&quot;</a> — Revenue sharing payouts: ~$1.3M in 2024, ~$360M in 2025, ~$1.9B in 2026, ~$6.4B in 2027 (The Information data)</p>\\n<p><a id=\\"source-41\\"><strong>41.</strong></a> <a href=\\"https://www.fierce-network.com/cloud/what-does-anthropics-50b-data-center-project-mean-hyperscalers\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fierce Network — &quot;What Does Anthropic's $50B Data Center Project Mean for Hyperscalers?&quot;</a> — $50B data center partnership with FluidStack; facilities in Texas and New York expected online throughout 2026</p>\\n<p><a id=\\"source-42\\"><strong>42.</strong></a> <a href=\\"https://sustainabilitymag.com/news/why-anthropic-pledging-offset-ai-energy-costs\\" target=\\"_blank\\" rel=\\"noreferrer\\">Sustainability Magazine — &quot;Why Is Anthropic Pledging to Offset Its AI Energy Costs?&quot;</a> — Committed to covering 100% of grid upgrade costs and electricity price increases for communities hosting its data centers</p>\\n<p><a id=\\"source-43\\"><strong>43.</strong></a> <a href=\\"https://sacra.com/c/anthropic/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Sacra — Anthropic Revenue, Valuation &amp; Funding</a> — Cash burn of $5.6B in 2024, ~$3B in 2025; projects cash flow positive in 2027, break-even in 2028</p>\\n<p><a id=\\"source-44\\"><strong>44.</strong></a> <a href=\\"https://www.axios.com/2026/02/12/anthropic-raises-30b-at-380b-valuation\\" target=\\"_blank\\" rel=\\"noreferrer\\">Axios — &quot;Anthropic Raises $30B at $380B Valuation&quot;</a> — 300,000+ business customers; run-rate revenue of $14B; customers spending $100K+ annually grown 7x in past year</p>\\n<p><a id=\\"source-45\\"><strong>45.</strong></a> <a href=\\"https://builtin.com/articles/top-tech-ipos-2026\\" target=\\"_blank\\" rel=\\"noreferrer\\">Built In — &quot;2026 IPO Watchlist: OpenAI, SpaceX and Other Tech Giants&quot;</a> — Retained Wilson Sonsini (firm behind Google and LinkedIn IPOs) in December 2025 for IPO preparation</p>\\n<p><a id=\\"source-46\\"><strong>46.</strong></a> <a href=\\"https://www.newsweek.com/ai-skeptic-ed-zitron-says-math-on-data-centers-doesnt-add-up-11594219\\" target=\\"_blank\\" rel=\\"noreferrer\\">Newsweek — &quot;AI Skeptic Ed Zitron Says Math on Data Centers Doesn't Add Up&quot;</a> — Claude Code subscribers consume $8-13.50 in compute per $1 paid; $200/month user burns $2,700+ in real costs; &quot;Everyone using Claude Code right now is in an illusory environment&quot;</p>\\n<p><a id=\\"source-47\\"><strong>47.</strong></a> <a href=\\"https://www.mercatus.org/research/data-visualizations/private-sector-job-losses-dwarf-government-gains\\" target=\\"_blank\\" rel=\\"noreferrer\\">Mercatus Center / George Mason University — &quot;Private Sector Job Losses Dwarf Government Gains&quot;</a> — BLS Current Employment Statistics: government employment increased by 590,000 since January 2008 while private sector lost nearly 8 million jobs; government peaked at ~23 million in May 2010</p>\\n<p><a id=\\"source-48\\"><strong>48.</strong></a> <a href=\\"https://hai.stanford.edu/ai-index/2025-ai-index-report\\" target=\\"_blank\\" rel=\\"noreferrer\\">Stanford HAI — The 2025 AI Index Report</a> — Inference cost for GPT-3.5-level performance dropped over 280-fold between November 2022 and October 2024; driven by increasingly capable small models and open-weight alternatives</p>\\n<p><a id=\\"source-49\\"><strong>49.</strong></a> <a href=\\"https://epoch.ai/data-insights/llm-inference-price-trends\\" target=\\"_blank\\" rel=\\"noreferrer\\">Epoch AI — &quot;LLM Inference Prices Have Fallen Rapidly but Unequally Across Tasks&quot;</a> — Price declines ranging from 9x to 900x per year depending on benchmark; fastest trends (900x/year) start after January 2024; median rate increased from 50x to 200x per year when isolating post-2024 data</p>\\n<p><a id=\\"source-50\\"><strong>50.</strong></a> <a href=\\"https://www.bloomberg.com/news/articles/2025-12-21/openai-sees-better-margins-on-business-sales-report-says\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bloomberg — &quot;OpenAI Sees Better Margins on Business Sales, Report Says&quot;</a> — OpenAI compute margin reached 70% as of October 2025, up from 52% at end of 2024 and double the 35% rate in January 2024 (The Information data)</p>\\n<p><a id=\\"source-51\\"><strong>51.</strong></a> <a href=\\"https://lesbarclays.substack.com/p/who-captures-the-value-when-ai-inference\\" target=\\"_blank\\" rel=\\"noreferrer\\">Les Barclays / Substack — &quot;Who Captures the Value When AI Inference Becomes Cheap?&quot;</a> — Cost per query increasing for frontier models even as cost per token declines; models employing test-time scaling consume multiple tokens per problem; at current pace OpenAI's competitive advantage may dissipate</p>\\n<p><a id=\\"source-52\\"><strong>52.</strong></a> <a href=\\"https://foundationcapital.com/nvidias-ai-factory-bet/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Foundation Capital — &quot;NVIDIA's 'AI Factory' Bet&quot;</a> — Reasoning models require 20x more tokens and 150x more compute per query than traditional LLMs; enterprise applications projected to run hundreds of millions of agentic queries per month</p>\\n<p><a id=\\"source-53\\"><strong>53.</strong></a> <a href=\\"https://www.ikangai.com/the-llm-cost-paradox-how-cheaper-ai-models-are-breaking-budgets/\\" target=\\"_blank\\" rel=\\"noreferrer\\">iKangai — &quot;The LLM Cost Paradox: How 'Cheaper' AI Models Are Breaking Budgets&quot;</a> — At maximum reasoning settings, models consume 10,000+ reasoning tokens internally for a 200-token answer; token consumption explosion leaving AI companies scrambling to stay profitable</p>\\n<p><a id=\\"source-54\\"><strong>54.</strong></a> <a href=\\"https://www.arturmarkus.com/the-inference-cost-paradox-why-generative-ai-spending-surged-320-in-2025-despite-per-token-costs-dropping-1000x-and-what-it-means-for-your-ai-budget-in-2026/\\" target=\\"_blank\\" rel=\\"noreferrer\\">AI Unfiltered — &quot;The Inference Cost Paradox&quot;</a> — Enterprise AI spending surged 320% in 2025 despite per-token costs dropping 1,000x; organizations that budgeted for 20-30% increases found themselves scrambling by Q3; Jevons Paradox makes single-number AI budgets &quot;fantasy&quot;</p>\\n<p><a id=\\"source-55\\"><strong>55.</strong></a> <a href=\\"https://www.leaddigital.com/blog/a-token-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">LeadDigital — &quot;A Token Economy&quot;</a> — Inference costs fell 1,000-fold but demand rose 10,000-fold; Jevons Paradox in action; Gartner predicts 40% of enterprise applications will feature AI agents by end of 2026, up from 5% in 2025</p>\\n<p><a id=\\"source-56\\"><strong>56.</strong></a> <a href=\\"https://www.saastr.com/have-ai-gross-margins-really-turned-the-corner-the-real-math-behind-openais-70-compute-margin-and-why-b2b-startups-are-still-running-on-a-treadmill/\\" target=\\"_blank\\" rel=\\"noreferrer\\">SaaStr — &quot;Have AI Gross Margins Really Turned the Corner?&quot;</a> — Anthropic expects gross margin of 50% in 2025 and 77% by 2028; Cursor paying ~$650M/year to Anthropic on ~$500M revenue (negative 30% margin); Bessemer 2025 data shows AI startups averaging 25% gross margins; frontier models getting more expensive, not cheaper</p>\\n<p><a id=\\"source-57\\"><strong>57.</strong></a> <a href=\\"https://ebudget.ca.gov/2025-26/pdf/BudgetSummary/RevenueEstimates.pdf\\" target=\\"_blank\\" rel=\\"noreferrer\\">California 2025-26 Budget Revenue Estimates</a> — 67% of General Fund from personal income tax; capital gains = 16% of total tax liability (25% in boom years)</p>\\n<p><a id=\\"source-58\\"><strong>58.</strong></a> <a href=\\"https://en.wikipedia.org/wiki/2008%E2%80%932012_California_budget_crisis\\" target=\\"_blank\\" rel=\\"noreferrer\\">Wikipedia — &quot;2008-2012 California Budget Crisis&quot;</a> — State revenue dropped from ~$100B to ~$85B during dot-com bust and again during Great Recession</p>\\n<p><a id=\\"source-59\\"><strong>59.</strong></a> <a href=\\"https://www.cbpp.org/research/economy/the-legacy-of-the-great-recession\\" target=\\"_blank\\" rel=\\"noreferrer\\">Center on Budget and Policy Priorities — &quot;Legacy of the Great Recession&quot;</a> — 8.7 million jobs lost in private sector during Great Recession</p>\\n<p><a id=\\"source-60\\"><strong>60.</strong></a> <a href=\\"https://laborcenter.berkeley.edu/\\" target=\\"_blank\\" rel=\\"noreferrer\\">UC Berkeley Labor Center — &quot;California Furloughs 2009&quot;</a> — 193,000 state workers furloughed; 2-3 unpaid days per month; 13.8% effective pay reduction</p>\\n<p><a id=\\"source-61\\"><strong>61.</strong></a> <a href=\\"https://www.calhr.ca.gov/\\" target=\\"_blank\\" rel=\\"noreferrer\\">CalHR — Furlough Program Manual</a> — Furlough hours banked as leave credits; paid out at separation at current base pay rate after COLA increases</p>\\n<p><a id=\\"source-62\\"><strong>62.</strong></a> <a href=\\"https://www.csmonitor.com/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Christian Science Monitor — &quot;Government Jobs: A Recession Refuge?&quot; (2009)</a> — Public sector employment didn't drop during 1991 recession; didn't decline after dot-com bust until 2004; lagged private sector contractions by years</p>\\n<p><a id=\\"source-63\\"><strong>63.</strong></a> <a href=\\"https://www.bls.gov/opub/mlr/2011/\\" target=\\"_blank\\" rel=\\"noreferrer\\">BLS Monthly Labor Review (2011) — &quot;The Recession of 2007-2009&quot;</a> — State and local governments shed 68,000 jobs (0.3% decline) vs. millions in private sector</p>\\n<p><a id=\\"source-64\\"><strong>64.</strong></a> <a href=\\"https://www.governing.com/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Governing — &quot;State Budget Actions in Recessions&quot; (2024)</a> — FY2010: 26 states used layoffs, 22 states used furloughs as primary budget-balancing tool</p>\\n<p><a id=\\"source-65\\"><strong>65.</strong></a> <a href=\\"https://lao.ca.gov/\\" target=\\"_blank\\" rel=\\"noreferrer\\">California Legislative Analyst's Office — 2025-26 Budget Analysis</a> — California has used furloughs in 9 fiscal years since 1992</p>\\n<p><a id=\\"source-66\\"><strong>66.</strong></a> <a href=\\"https://www.ncbi.nlm.nih.gov/pmc/\\" target=\\"_blank\\" rel=\\"noreferrer\\">PMC / Annals of the American Academy of Political and Social Science — &quot;Safety Net Programs in the Great Recession&quot;</a> — Safety net caseloads rose from 276 million to 310 million recipients during the Great Recession; countercyclical demand expanded public sector workload</p>\\n<p><a id=\\"source-67\\"><strong>67.</strong></a> <a href=\\"https://www.bls.gov/news.release/union2.nr0.htm\\" target=\\"_blank\\" rel=\\"noreferrer\\">BLS — &quot;Union Members — 2025&quot;</a> — Public sector union membership rate 32.9% vs. private sector 5.9%; local government workers at 37.8%</p>\\n<hr>\\n<p><em>This analysis reflects the views of PenPublic and is informed by publicly available economic research and reporting. We encourage readers to review the cited sources and draw their own conclusions.</em></p>\\n<p><em><a href=\\"https://penpublic.com\\" target=\\"_blank\\" rel=\\"noreferrer\\">PenPublic</a> — Your guide to public sector careers.</em></p>\\n","frontmatter":{"title":"The AI Bubble Won't Take Your Job — But Its Collapse Might","date":"2026-03-01T12:00:00.000Z","description":"Why the coming AI reckoning makes public sector careers the smartest move you can make","author":"Penny","tags":["AI","Economy","Public Sector Jobs"]},"excerpt":"<h1 id=\\"the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" tabindex=\\"-1\\">The AI Bubble Won't Take Your Job — But Its Collapse Might <a class=\\"header-anchor\\" href=\\"#the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" aria-label=\\"Permalink to &quot;The AI Bubble Won't Take Your Job — But Its Collapse Might&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p><em>Why the coming AI reckoning makes public sector careers the smartest move you can make</em></p>\\n<p><em>By Penny | March 1, 2026 (updated Mar 3, 2026)</em></p>\\n","url":"/blog/2026-03-01_ai-bubble-government-jobs.html"}],"Public Sector Jobs":[{"html":"<h1 id=\\"the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" tabindex=\\"-1\\">The AI Bubble Won't Take Your Job — But Its Collapse Might <a class=\\"header-anchor\\" href=\\"#the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" aria-label=\\"Permalink to &quot;The AI Bubble Won't Take Your Job — But Its Collapse Might&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p><em>Why the coming AI reckoning makes public sector careers the smartest move you can make</em></p>\\n<p><em>By Penny | March 1, 2026 (updated Mar 3, 2026)</em></p>\\n<hr>\\n<h2 id=\\"key-takeaways\\" tabindex=\\"-1\\">Key Takeaways <a class=\\"header-anchor\\" href=\\"#key-takeaways\\" aria-label=\\"Permalink to &quot;Key Takeaways&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><strong>Thesis: The AI bubble will collapse — and when it does, the layoffs won't be because AI took your job. They'll be because of the recession it causes.</strong></p>\\n<ul>\\n<li><strong><a href=\\"#the-real-threat-ai-layoffs-that-aren-t-about-ai\\">The real threat: AI layoffs that aren't about AI</a></strong> — the bubble's collapse will tank the economy and trigger mass layoffs misattributed to &quot;AI disruption&quot;</li>\\n<li><strong><a href=\\"#the-ai-investment-that-isn-t-working\\">AI doesn't work for most businesses</a></strong> — MIT found a 95% failure rate for enterprise AI projects <a href=\\"#source-1\\">[1]</a>, and only 14% of CFOs report measurable ROI <a href=\\"#source-4\\">[4]</a>\\n<ul>\\n<li>IBM found AI initiatives return 5.9% ROI on a 10% capital investment — companies are losing money <a href=\\"#source-3\\">[3]</a></li>\\n<li>Forrester predicts 25% of planned 2026 AI spending will be deferred to 2027 <a href=\\"#source-2\\">[2]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\">Goldman Sachs says AI contributed &quot;basically zero&quot; to U.S. GDP growth</a></strong> — most AI spending flows to Taiwan and South Korea for imported chips <a href=\\"#source-7\\">[7]</a> <a href=\\"#source-8\\">[8]</a>\\n<ul>\\n<li>Only 0.2% of the U.S. economy's 2.2% growth in 2025 came from AI investment <a href=\\"#source-10\\">[10]</a></li>\\n<li>Tech companies plan to spend $700B on AI in 2026; J.P. Morgan says AI needs $600B/year in revenue just to break even <a href=\\"#source-10\\">[10]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-stock-market-is-built-on-spending-not-returns\\">The stock market rally is built on AI spending, not AI returns</a></strong> — AI stocks account for 75% of all S&amp;P 500 returns since ChatGPT launched <a href=\\"#source-29\\">[29]</a>, but generate only 32% of index earnings <a href=\\"#source-31\\">[31]</a>\\n<ul>\\n<li>Strip out tech and communications, and the S&amp;P 500 returned just 6% in 2025 <a href=\\"#source-30\\">[30]</a></li>\\n<li>Apollo's chief economist says the AI bubble is now bigger than the 1990s IT bubble <a href=\\"#source-33\\">[33]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-110-billion-question\\">OpenAI's $110B round is a house of cards</a></strong> — Amazon invests $50B, OpenAI commits to spending $100B on AWS; money just circulates <a href=\\"#source-13\\">[13]</a>\\n<ul>\\n<li>OpenAI spent $9B to lose $5B in 2025 <a href=\\"#source-17\\">[17]</a></li>\\n<li>AI-related debt issuance crossed $200B, representing 30% of all USD credit supply <a href=\\"#source-11\\">[11]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-subsidized-illusion\\">AI subscriptions are subsidized below true cost</a></strong> — your $20/mo plan likely costs $1,000-2,000+/mo to serve <a href=\\"#source-18\\">[18]</a>\\n<ul>\\n<li>Even the $200/mo ChatGPT Pro loses money on power users (per Sam Altman) <a href=\\"#source-19\\">[19]</a></li>\\n<li>As Ed Zitron documents, every level of the AI value chain is unprofitable <a href=\\"#source-17\\">[17]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#but-what-about-anthropic\\">Even &quot;responsible&quot; Anthropic can't make the math work</a></strong> — its AWS bill alone consumed 100% of revenue through September 2025 <a href=\\"#source-34\\">[34]</a>, before paying for Google Cloud, salaries, data centers, or anything else\\n<ul>\\n<li>Claude Code subscribers consume $8-13.50 in compute for every $1 they pay <a href=\\"#source-46\\">[46]</a></li>\\n<li>Anthropic projects $80B in total cloud spend through 2029 <a href=\\"#source-39\\">[39]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#but-inference-costs-are-dropping-exponentially\\">Falling inference costs won't save them</a></strong> — the 280x cost drop is for GPT-3.5-level performance, a model nobody wants anymore <a href=\\"#source-48\\">[48]</a>; reasoning models consume 20x more compute per query <a href=\\"#source-52\\">[52]</a>\\n<ul>\\n<li>Jevons Paradox: inference costs fell 1,000x but demand rose 10,000x — total enterprise AI spending surged 320% in 2025 <a href=\\"#source-55\\">[55]</a></li>\\n<li>Cursor paid ~$650M/year to Anthropic while earning ~$500M — a negative 30% gross margin <a href=\\"#source-54\\">[54]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#the-k-shaped-economy-a-house-of-cards\\">The economy is a K-shape propped up by the wealthy</a></strong> — top 10% accounts for 50% of all consumer spending, driven by inflated stock portfolios <a href=\\"#source-21\\">[21]</a>\\n<ul>\\n<li>Bottom 80% hasn't outpaced inflation in 6 years <a href=\\"#source-23\\">[23]</a></li>\\n<li>$180B in consumer spending is driven by AI-inflated stock wealth effect alone <a href=\\"#source-27\\">[27]</a></li>\\n</ul>\\n</li>\\n<li><strong><a href=\\"#why-public-sector-careers-are-the-smart-play\\">Public sector careers are the smart play</a></strong> — California's budget will take a hit, but public sector workers get furloughs, not layoffs — and keep their pensions, health insurance, and union protection through every recession <a href=\\"#source-57\\">[57]</a> <a href=\\"#source-60\\">[60]</a> <a href=\\"#source-66\\">[66]</a></li>\\n</ul>\\n<hr>\\n<h2 id=\\"the-real-threat-ai-layoffs-that-aren-t-about-ai\\" tabindex=\\"-1\\">The Real Threat: AI Layoffs That Aren't About AI <a class=\\"header-anchor\\" href=\\"#the-real-threat-ai-layoffs-that-aren-t-about-ai\\" aria-label=\\"Permalink to &quot;The Real Threat: AI Layoffs That Aren't About AI&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's the thesis that ties it all together, and the reason you should be thinking about career stability right now.</p>\\n<p><strong>AI will cause mass layoffs — not because the technology replaced workers, but because the financial bubble built around it will collapse and drag the broader economy down.</strong></p>\\n<p>The causal chain looks like this:</p>\\n<ol>\\n<li>AI spending inflates tech valuations and GDP numbers</li>\\n<li>Inflated stocks create a wealth effect that drives consumer spending among the top 10%</li>\\n<li>The bottom 80% is already stretched thin, running on debt</li>\\n<li>Enterprise AI fails to deliver ROI — 95% of projects show no measurable returns</li>\\n<li>Companies begin cutting AI budgets (already happening — Forrester projects 25% deferrals)</li>\\n<li>Tech stocks correct as the narrative shifts</li>\\n<li>The wealth effect reverses — wealthy consumers pull back</li>\\n<li>Nobody else can pick up the slack because they were already tapped out</li>\\n<li>GDP contracts from multiple directions simultaneously</li>\\n<li>Companies execute mass layoffs to protect margins</li>\\n</ol>\\n<p>And here's the cruelest irony: <strong>the headlines will say &quot;AI replaced these workers.&quot;</strong> CEOs will frame layoffs as &quot;AI-driven transformation&quot; because it sounds strategic. Media will repeat the narrative because it's a clean story. But the reality is that the jobs disappeared because the financial infrastructure collapsed, not because a chatbot learned to do them.</p>\\n<p>We've seen this exact pattern before. Dot-com bust workers didn't lose jobs because websites replaced them — they lost jobs because companies had hired against inflated revenue projections that evaporated overnight. The 2008 financial crisis didn't eliminate construction jobs because buildings got smarter — it eliminated them because the financing structure collapsed.</p>\\n<hr>\\n<h2 id=\\"the-ai-investment-that-isn-t-working\\" tabindex=\\"-1\\">The AI Investment That Isn't Working <a class=\\"header-anchor\\" href=\\"#the-ai-investment-that-isn-t-working\\" aria-label=\\"Permalink to &quot;The AI Investment That Isn't Working&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Let's start with the most inconvenient fact in technology right now: <strong>AI doesn't work for most businesses.</strong></p>\\n<p>A landmark study from MIT found a staggering <strong>95% failure rate for enterprise generative AI projects</strong>, defined as not having shown measurable financial returns within six months <a href=\\"#source-1\\">[1]</a>. This isn't a fringe finding. Forrester Research reports that only 15% of AI decision-makers saw a positive impact on profitability, and predicts that enterprises will <strong>defer 25% of planned 2026 AI spending into 2027</strong> because the returns simply aren't there <a href=\\"#source-2\\">[2]</a>.</p>\\n<p>IBM's own research found that enterprise-wide AI initiatives achieved an <strong>ROI of just 5.9% despite requiring a 10% capital investment</strong> — meaning companies are literally losing money on AI <a href=\\"#source-3\\">[3]</a>. And only 14% of CFOs report measurable ROI from AI to date <a href=\\"#source-4\\">[4]</a>. Recent enterprise surveys confirm that <strong>90-95% of organizations are seeing little to no measurable financial return</strong> on their AI investments <a href=\\"#source-5\\">[5]</a>.</p>\\n<p>If you work in the public sector and your agency rolled out Microsoft Copilot, ask yourself: does anyone actually use it? The answer, overwhelmingly across both public and private sectors, is no. Nearly 70% of Fortune 500 companies are paying for Copilot, but the productivity benefits are so diffuse they don't move the needle on actual business results <a href=\\"#source-6\\">[6]</a>.</p>\\n<hr>\\n<h2 id=\\"goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\" tabindex=\\"-1\\">Goldman Sachs Says AI Contributed &quot;Basically Zero&quot; to the Economy <a class=\\"header-anchor\\" href=\\"#goldman-sachs-says-ai-contributed-basically-zero-to-the-economy\\" aria-label=\\"Permalink to &quot;Goldman Sachs Says AI Contributed &quot;Basically Zero&quot; to the Economy&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>In late February 2026, Goldman Sachs Chief Economist Jan Hatzius dropped a bombshell in an interview with the Atlantic Council. AI investment spending, he said, has had <strong>&quot;basically zero&quot;</strong> contribution to U.S. GDP growth <a href=\\"#source-7\\">[7]</a>.</p>\\n<p>&quot;We don't actually view AI investment as strongly growth positive,&quot; Hatzius stated. &quot;I think there's a lot of misreporting, actually, of the impact AI investment had on U.S. GDP growth in 2025, and it's much smaller than is often perceived.&quot; <a href=\\"#source-7\\">[7]</a></p>\\n<p>The reason is straightforward: most AI equipment is imported. The chips come from Taiwan. The hardware comes from South Korea. As Hatzius put it: &quot;A lot of the AI investment that we're seeing in the U.S. adds to Taiwanese GDP, and it adds to Korean GDP but not really that much to U.S. GDP.&quot; <a href=\\"#source-8\\">[8]</a></p>\\n<p>His colleague Joseph Briggs made the same case to the Washington Post, calling the AI-as-growth-engine story &quot;very intuitive&quot; but ultimately misleading — it &quot;maybe prevented or limited the need to actually dig deeper into what was happening.&quot; <a href=\\"#source-9\\">[9]</a></p>\\n<p>Of the U.S. economy's 2.2% growth in 2025, analyst Joseph Politano calculates that only <strong>0.2% was attributable to AI investment</strong> after accounting for imports <a href=\\"#source-10\\">[10]</a>. Meanwhile, tech companies are expected to spend <strong>$700 billion on AI infrastructure in 2026</strong> <a href=\\"#source-10\\">[10]</a>. J.P. Morgan has calculated that AI would need to generate over <strong>$600 billion in annual revenue</strong> just to achieve a 10% return on infrastructure expenditures <a href=\\"#source-10\\">[10]</a>. Current total AI industry revenue is a fraction of that.</p>\\n<p>Deutsche Bank has warned that the <strong>U.S. would be close to recession without tech-related spending</strong> <a href=\\"#source-11\\">[11]</a> — which sounds like AI is saving the economy until you realize the money mostly flows overseas. An analysis from MRB Partners found that after adjusting for high-tech imports, AI's net contribution to GDP growth was only <strong>20-25%</strong>, not the 40-92% figures that dominated headlines <a href=\\"#source-12\\">[12]</a>.</p>\\n<hr>\\n<h2 id=\\"the-stock-market-is-built-on-spending-not-returns\\" tabindex=\\"-1\\">The Stock Market Is Built on Spending, Not Returns <a class=\\"header-anchor\\" href=\\"#the-stock-market-is-built-on-spending-not-returns\\" aria-label=\\"Permalink to &quot;The Stock Market Is Built on Spending, Not Returns&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's the critical distinction most analysts gloss over: <strong>AI is driving stock prices. It is not driving profits.</strong></p>\\n<p>Since ChatGPT launched in November 2022, AI-related stocks have accounted for <strong>75% of all S&amp;P 500 returns, 80% of earnings growth, and 90% of capital spending growth</strong>, according to J.P. Morgan Asset Management's Michael Cembalest <a href=\\"#source-29\\">[29]</a>. In 2025 alone, the Magnificent Seven were responsible for <strong>42% of the S&amp;P 500's 17.9% return</strong> for the year <a href=\\"#source-30\\">[30]</a>. If you strip out the tech and communications sectors entirely, the S&amp;P 500 would have returned just <strong>6%</strong> in 2025 <a href=\\"#source-30\\">[30]</a>. Seven companies with AI exposure — NVIDIA, Alphabet, Microsoft, Broadcom, JPMorgan Chase, Palantir, and Meta — delivered over <strong>half</strong> of the entire index's gains <a href=\\"#source-31\\">[31]</a>.</p>\\n<p>This means the entire stock market rally — the one powering the wealth effect, driving consumer spending, and propping up GDP — is built on one bet: that AI spending will eventually produce returns. But as we've just seen, Goldman Sachs says it's contributed &quot;basically zero&quot; to the economy. MIT says 95% of enterprise projects fail. Only 14% of CFOs can point to measurable ROI.</p>\\n<p><strong>The money is real. The spending is real. The returns aren't.</strong></p>\\n<p>And the gap between market hype and economic reality is widening. The top 10 stocks now represent <strong>41% of the S&amp;P 500's total weight but generate only about 32% of its earnings</strong> — a gap that has widened meaningfully since 2015, when weight and earnings contribution were closely aligned <a href=\\"#source-31\\">[31]</a>. Goldman Sachs' own equity research team acknowledges that the &quot;combination of elevated valuations, extreme concentration, and strong recent returns rhymes with a handful of overextended equity markets during the last century&quot; <a href=\\"#source-32\\">[32]</a>. AI capex is on track to reach <strong>75% of cash flows</strong> for the largest tech companies — similar to tech spending in the late 1990s — and future spending growth will increasingly rely on debt <a href=\\"#source-32\\">[32]</a>.</p>\\n<p>Apollo's chief economist Torsten Slok has published research showing that <strong>the AI bubble is now bigger than the IT bubble of the 1990s</strong>, with the average P/E ratio of the top 10 S&amp;P 500 companies sitting around 50 and hyperscaler capital expenditure as a share of GDP exceeding the dotcom era <a href=\\"#source-33\\">[33]</a>. His bottom line: investors in the S&amp;P 500 &quot;remain overexposed to AI&quot; <a href=\\"#source-33\\">[33]</a>.</p>\\n<p>Think of it like Cisco in 1999. Cisco had real revenue — they were selling real routers to real companies building out internet infrastructure. The stock price reflected the spending story, not the returns story. The companies buying the routers never built sustainable businesses on top of them. When the spending stopped, Cisco's stock dropped 86% and never recovered its peak. Today, NVIDIA is the Cisco of the AI era — posting real revenue because hyperscalers are writing enormous checks for GPUs. But the companies buying those GPUs can't show a return on the investment. The spending is driving the stock, not the other way around.</p>\\n<hr>\\n<h2 id=\\"the-110-billion-question\\" tabindex=\\"-1\\">The $110 Billion Question <a class=\\"header-anchor\\" href=\\"#the-110-billion-question\\" aria-label=\\"Permalink to &quot;The $110 Billion Question&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>On February 27, 2026, OpenAI announced a <strong>$110 billion funding round</strong> — the largest private fundraise in history — at a $730 billion pre-money valuation. Amazon invested $50 billion, with Nvidia and SoftBank contributing $30 billion each <a href=\\"#source-13\\">[13]</a> <a href=\\"#source-14\\">[14]</a>.</p>\\n<p>These numbers sound impressive until you examine the structure. Amazon invests $50 billion in OpenAI, and OpenAI commits to spending $100 billion on AWS over eight years <a href=\\"#source-13\\">[13]</a>. The money flows out and comes right back. It's not a clean investment — it's a customer acquisition cost disguised as a capital raise. For context, this single round exceeds the <strong>$170 billion in total U.S. venture capital investment for all of 2023</strong> <a href=\\"#source-15\\">[15]</a>.</p>\\n<p>Reporting has revealed that OpenAI's Stargate joint venture involves very little actual collaboration among partners, with most data centers being traditional bilateral deals rather than the unified project that was announced — described by one outlet as better understood as <strong>&quot;a branding exercise than a real entity&quot;</strong> <a href=\\"#source-16\\">[16]</a>.</p>\\n<p>And the investor pool is narrowing. This round came from just three megaplayers who are simultaneously OpenAI's suppliers and customers. That's not a sign of broad market confidence. That's a sign that the only people willing to write checks are those with strategic reasons beyond financial return.</p>\\n<hr>\\n<h2 id=\\"the-subsidized-illusion\\" tabindex=\\"-1\\">The Subsidized Illusion <a class=\\"header-anchor\\" href=\\"#the-subsidized-illusion\\" aria-label=\\"Permalink to &quot;The Subsidized Illusion&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>Here's something most AI users don't realize: <strong>your subscription is being heavily subsidized by investor capital.</strong> Tech journalist <a href=\\"https://www.wheresyoured.at/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron</a> has been documenting this dynamic extensively, and the numbers are damning.</p>\\n<p>As Zitron details, OpenAI spent <strong>50% of its revenue on inference compute costs alone, and 75% on training compute</strong> — numbers that add up to well over 100% of revenue. They spent $9 billion to lose $5 billion <a href=\\"#source-17\\">[17]</a>. And it's not just OpenAI. Perplexity spent <strong>164% of its revenue</strong> on AWS, Anthropic, and OpenAI costs in 2024 <a href=\\"#source-17\\">[17]</a>.</p>\\n<p>Zitron's core observation cuts to the heart of the problem: &quot;Anybody funding an AI startup is effectively sending that money to Anthropic or OpenAI, who then immediately send that money to Amazon, Google or Microsoft, who are yet to show that they make any profit on selling it.&quot; <a href=\\"#source-17\\">[17]</a> The money cascades down and evaporates at every level. Nobody in the chain is profitable.</p>\\n<p>A developer using Claude Code eight hours a day can cost the provider <strong>tens of thousands of dollars per month</strong> in compute — on a $200 subscription <a href=\\"#source-18\\">[18]</a>. OpenAI's CEO Sam Altman has publicly acknowledged that even the <strong>$200/month ChatGPT Pro tier loses money</strong> on power users <a href=\\"#source-19\\">[19]</a>. The true cost of serving a heavy AI user is likely <strong>$1,000 to $2,000+ per month</strong>, not the $20-200 consumers pay.</p>\\n<p>AI companies are running the same playbook as Uber and WeWork — price below cost to capture market share, subsidize the difference with investor billions, and figure out profitability later <a href=\\"#source-20\\">[20]</a>. When investor subsidies dry up — whether through funding fatigue, a market correction, or companies simply running out of runway — prices must rise to reflect reality. And at real prices, the value proposition collapses for the vast majority of users. If most enterprise users don't find AI useful at $0 (the Copilot licenses their companies pay for that go unused), they certainly won't pay $2,000/month.</p>\\n<p>AI-related debt issuance in credit markets crossed <strong>$200 billion in 2025</strong>, representing 30% of all USD credit supply <a href=\\"#source-11\\">[11]</a>. Hyperscalers are projected to spend a cumulative <strong>$4 trillion on AI data centers through 2030</strong> <a href=\\"#source-11\\">[11]</a>. These are staggering bets on a technology that 95% of enterprises can't generate returns from.</p>\\n<hr>\\n<h2 id=\\"but-what-about-anthropic\\" tabindex=\\"-1\\">But What About Anthropic? <a class=\\"header-anchor\\" href=\\"#but-what-about-anthropic\\" aria-label=\\"Permalink to &quot;But What About Anthropic?&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>If OpenAI is the poster child for AI excess, Anthropic is supposed to be the responsible adult — enterprise-focused, safety-conscious, targeting break-even by 2028 <a href=\\"#source-43\\">[43]</a>. But the numbers tell a different story.</p>\\n<p>Ed Zitron obtained Anthropic's AWS billing data and revealed that through September 2025, the company spent <strong>$2.66 billion on Amazon Web Services</strong> on an estimated <strong>$2.55 billion in revenue</strong> <a href=\\"#source-34\\">[34]</a>. Just the AWS bill — one line item from one cloud vendor — consumed every dollar the company earned. And as Zitron observed, the costs scale linearly with revenue, showing no evidence of improving margins at scale <a href=\\"#source-34\\">[34]</a>.</p>\\n<p>And that's before paying for anything else. Here's what sits on top, roughly ordered by magnitude:</p>\\n<ul>\\n<li><strong>Google Cloud compute</strong> (estimated $1.3B+ through Sept 2025) — Anthropic also runs on GCP, committed to a deal worth &quot;tens of billions&quot; for up to one million TPUs <a href=\\"#source-35\\">[35]</a>, and Zitron estimates their Google spend at a minimum of 50% of their AWS bill <a href=\\"#source-34\\">[34]</a>. Inference costs ran 23% over plan in 2025 <a href=\\"#source-36\\">[36]</a></li>\\n<li><strong>Salaries and compensation</strong> (~$500-600M/year) — over 1,200 employees <a href=\\"#source-37\\">[37]</a> with a median total compensation of $472,000; top AI researchers earning up to $759,000 <a href=\\"#source-38\\">[38]</a></li>\\n<li><strong>Revenue sharing with cloud platforms</strong> ($360M in 2025, scaling to $1.9B in 2026 and $6.4B by 2027) — AWS takes up to 50% of gross profits from AI sales on its platform; Google takes 20-30% of net revenue <a href=\\"#source-39\\">[39]</a> <a href=\\"#source-40\\">[40]</a></li>\\n<li><strong>Data center construction</strong> ($50B committed) — partnership with FluidStack to build facilities in Texas and New York, with sites expected online throughout 2026 <a href=\\"#source-41\\">[41]</a></li>\\n<li><strong>Microsoft Azure compute</strong> ($30B committed over time) — announced alongside a $5B Microsoft investment in November <a href=\\"#source-39\\">[39]</a></li>\\n<li><strong>Energy and grid infrastructure</strong> (uncapped commitment) — Anthropic publicly pledged to cover 100% of electricity price increases and grid upgrade costs for every community hosting its data centers <a href=\\"#source-42\\">[42]</a></li>\\n<li><strong>R&amp;D, safety research, and model training</strong> (hundreds of millions/year) — total company cash burn was $5.6B in 2024 and ~$3B in 2025 <a href=\\"#source-43\\">[43]</a>, and the costs above don't account for all of it</li>\\n<li><strong>Sales, marketing, and enterprise support</strong> (rapidly scaling) — serving 300,000+ business customers, with 500+ spending over $1M annually <a href=\\"#source-44\\">[44]</a></li>\\n<li><strong>Legal and IPO preparation</strong> (tens of millions) — retained Wilson Sonsini, the firm behind Google's and LinkedIn's IPOs, to advise on a potential 2026 listing <a href=\\"#source-45\\">[45]</a></li>\\n</ul>\\n<p>Claude Code, the company's breakout coding product, makes the math even worse — subscribers consume <strong>$8-13.50 in actual compute for every $1 they pay</strong>, meaning a $200/month user burns through over $2,700 in real costs <a href=\\"#source-46\\">[46]</a>.</p>\\n<p>So when Anthropic projects &quot;break-even by 2028,&quot; the question is: break-even on what definition? If the most disciplined company in the AI race spends 100% of revenue on a single vendor's cloud bill before touching any other expense, the industry's path to profitability isn't just narrow — it may not exist.</p>\\n<hr>\\n<h2 id=\\"but-inference-costs-are-dropping-exponentially\\" tabindex=\\"-1\\">“But Inference Costs Are Dropping Exponentially!” <a class=\\"header-anchor\\" href=\\"#but-inference-costs-are-dropping-exponentially\\" aria-label=\\"Permalink to &quot;“But Inference Costs Are Dropping Exponentially!”&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>They are. Stanford HAI’s 2025 AI Index Report found that inference costs for GPT-3.5-level performance dropped over <strong>280-fold</strong> between November 2022 and October 2024 <a href=\\"#source-48\\">[48]</a>. Epoch AI’s research measured declines ranging from <strong>9x to 900x per year</strong> depending on the task, with the fastest drops occurring after January 2024 <a href=\\"#source-49\\">[49]</a>. OpenAI’s internal compute margin hit <strong>70%</strong> by October 2025, double its January 2024 level <a href=\\"#source-50\\">[50]</a>. These are real gains. Nobody serious disputes them.</p>\\n<p>The problem is that none of it matters in the way the bulls need it to.</p>\\n<p><strong>The cost drops are happening on yesterday’s models. The frontier is a treadmill.</strong> The 280x improvement Stanford measured is for GPT-3.5-level performance — a model nobody wants anymore. Users now expect GPT-4-level quality and reasoning capabilities of o1-class models, which employ test-time scaling and consume vastly more tokens per query. The cost per query may actually be <em>increasing</em> for frontier models even as cost per token declines <a href=\\"#source-51\\">[51]</a>. Reasoning models require roughly <strong>20x more tokens and 150x more compute per query</strong> than traditional LLMs <a href=\\"#source-52\\">[52]</a>. At maximum reasoning settings, a simple question might consume <strong>10,000 reasoning tokens internally</strong> while returning a 200-token answer <a href=\\"#source-53\\">[53]</a>.</p>\\n<p>This is the trick hiding inside the headline numbers. Every time efficiency catches up to the current frontier, the frontier moves. GPT-3.5 costs collapse — but customers have migrated to GPT-4. GPT-4 costs collapse — but everyone’s running o1-class reasoning chains. It’s like celebrating that a 2019 Toyota got cheaper while your customers all want the 2026 model. The efficiency gains are perpetually arriving for the product the market has already moved past.</p>\\n<p>Anthropic expects its gross profit margin to reach 50% this year and 77% by 2028 — but the inference cost declines are happening on older models. Frontier models are getting more expensive, not cheaper <a href=\\"#source-56\\">[56]</a>. The rise of agentic workflows has caused token consumption per task to jump <strong>10-100x</strong> since December 2023. Every leap in capability resets the economics back to brutal.</p>\\n<p><strong>Jevons Paradox eats the savings.</strong> Even setting aside the frontier treadmill, cheaper inference doesn’t produce cheaper AI bills. It produces <em>more AI bills.</em> Inference costs fell roughly 1,000-fold, but demand rose 10,000-fold — cheaper tokens didn’t reduce spending, they unleashed it <a href=\\"#source-55\\">[55]</a>. Enterprise AI spending surged <strong>320%</strong> in 2025 despite per-token costs dropping 1,000x, because each price drop makes thousands of new use cases suddenly economically viable <a href=\\"#source-54\\">[54]</a>.</p>\\n<p>This isn’t speculation. It’s what happened with coal in the 1860s, bandwidth in the 2000s, and mobile data in the 2010s. Every time you make a resource cheaper, consumption expands to more than compensate. Satya Nadella said it himself the day DeepSeek launched: “Jevons paradox strikes again.” If your per-token cost drops from $0.06 to $0.00006, you don’t get savings — you get AI running on every customer service interaction, personalized content at the individual level, and agents iterating through dozens of reasoning steps per response <a href=\\"#source-54\\">[54]</a>. The volume explosion overwhelms any per-unit improvement.</p>\\n<p>For AI providers, this is actually <em>good</em> for revenue growth but <em>terrible</em> for the profitability thesis. More usage means more infrastructure, more GPUs, more power, more cooling. The denominator scales with the numerator. You’re running faster to stay in the same place.</p>\\n<p><strong>The application-layer margin squeeze is brutal.</strong> Even if you accept that the foundation model providers are improving their margins, the companies actually building products on top of those models are getting crushed. Cursor, the poster child for AI-powered coding tools, was reportedly paying approximately <strong>$650 million annually to Anthropic</strong> while generating only <strong>$500 million in revenue</strong> — a negative 30% gross margin. Their AWS bills doubled in a single month when Anthropic launched new pricing tiers <a href=\\"#source-56\\">[56]</a>.</p>\\n<p>This isn’t an outlier. Bessemer’s 2025 data shows fast-ramping AI startups averaging only <strong>25% gross margins</strong>, with many running negative. The traditional SaaS benchmark for a healthy gross margin is 75%+ <a href=\\"#source-56\\">[56]</a>. If you show up to a Series B with 25% margins, you’re not a software company — you’re a services business subsidizing your customers’ compute.</p>\\n<p>The inference cost curve is real. It’s also irrelevant to the question that actually matters: can these companies turn a profit before they run out of other people’s money? So far, every efficiency gain gets consumed by the next leap in model complexity, the next explosion in usage volume, or the next round of infrastructure buildout. The treadmill doesn’t stop. And yes, a true believer can argue that all of these trends will reverse at exactly the right moment — that costs will plateau just as capital dries up, that margins will appear just as subsidies vanish, that the history of every other capital-intensive bubble will suddenly stop applying. But that’s not an argument. That’s a hope dressed in a spreadsheet.</p>\\n<hr>\\n<h2 id=\\"the-k-shaped-economy-a-house-of-cards\\" tabindex=\\"-1\\">The K-Shaped Economy: A House of Cards <a class=\\"header-anchor\\" href=\\"#the-k-shaped-economy-a-house-of-cards\\" aria-label=\\"Permalink to &quot;The K-Shaped Economy: A House of Cards&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p>The AI bubble doesn't exist in isolation. It sits on top of an already fragile economic structure that economists call the <strong>&quot;K-shaped economy&quot;</strong> — where the wealthy are thriving while everyone else falls behind.</p>\\n<p>The numbers are stark. The <strong>top 10% of earners now account for 50% of all consumer spending</strong>, up from 35% in the early 1990s <a href=\\"#source-21\\">[21]</a>. Moody's Analytics found that the top 20% accounts for <strong>59% of total spending</strong> <a href=\\"#source-22\\">[22]</a>. And for the bottom 80%? Their spending hasn't outpaced inflation over the last six years, meaning economic quality of life hasn't improved for the vast majority of Americans <a href=\\"#source-23\\">[23]</a>.</p>\\n<p>As of Q4 2025, the <strong>top 20% of households held nearly 72% of total household wealth</strong> <a href=\\"#source-24\\">[24]</a>. Lower-income households are increasingly relying on debt, with <strong>rising delinquency rates particularly in auto loans</strong> <a href=\\"#source-25\\">[25]</a>. Bank of America's analysis shows the divide is worsening, with some economists suggesting we've moved beyond a K-shape into a <strong>&quot;barbell economy&quot;</strong> heavily weighted at the extremes <a href=\\"#source-26\\">[26]</a>.</p>\\n<p>Much of the wealthy's spending is driven by the <strong>&quot;wealth effect&quot;</strong> — they spend more because their stock portfolios are up. And what's driving stock prices? AI hype. Soaring AI-related valuations alone have created an estimated <strong>$180 billion in additional consumer spending</strong> over the past year <a href=\\"#source-27\\">[27]</a>.</p>\\n<p>This creates a dangerous feedback loop: AI hype drives tech stocks up → rising stocks make wealthy people feel richer → wealthy people spend more → GDP looks healthy → the healthy GDP narrative justifies more AI investment → repeat.</p>\\n<p>Moody's chief economist Mark Zandi captured the fragility perfectly: <strong>&quot;It doesn't feel like the economy's perched on a strong foundation. It's perched on a few poles that are sticking up. If one of those poles gets knocked out, then the whole economy gets knocked down.&quot;</strong> <a href=\\"#source-23\\">[23]</a></p>\\n<p>Fortune published an analysis warning that wealthy consumers' spending is <strong>&quot;psychologically tethered to their portfolio balance&quot;</strong> — when the S&amp;P drops, they freeze discretionary spending. And in 2026, <strong>&quot;there is no one there to catch it&quot;</strong> because the bottom 80% has already depleted their pandemic-era savings <a href=\\"#source-28\\">[28]</a>.</p>\\n<p>U.S. Bank's chief economist Beth Ann Bovino put it plainly: <strong>&quot;We're increasingly dependent on healthier cohorts to keep the economy afloat.&quot;</strong> <a href=\\"#source-25\\">[25]</a> That's a polite way of saying the economy collapses if rich people stop spending — and rich people stop spending when their portfolios drop.</p>\\n<hr>\\n<h2 id=\\"why-public-sector-careers-are-the-smart-play\\" tabindex=\\"-1\\">Why Public Sector Careers Are the Smart Play <a class=\\"header-anchor\\" href=\\"#why-public-sector-careers-are-the-smart-play\\" aria-label=\\"Permalink to &quot;Why Public Sector Careers Are the Smart Play&quot;\\">&ZeroWidthSpace;</a></h2>\\n<h3 id=\\"yes-california-s-budget-will-take-a-hit-that-s-not-the-same-as-losing-your-job\\" tabindex=\\"-1\\"><em>Yes, California's budget will take a hit. That's not the same as losing your job.</em> <a class=\\"header-anchor\\" href=\\"#yes-california-s-budget-will-take-a-hit-that-s-not-the-same-as-losing-your-job\\" aria-label=\\"Permalink to &quot;*Yes, California's budget will take a hit. That's not the same as losing your job.*&quot;\\">&ZeroWidthSpace;</a></h3>\\n<p>California gets 67% of its General Fund from personal income tax, and capital gains alone account for 16% of total tax liability — spiking to 25% in boom years <a href=\\"#source-57\\">[57]</a>. When the dot-com bubble burst, state revenue dropped from $100 billion to $85 billion <a href=\\"#source-58\\">[58]</a>. An AI correction will hit state budgets. This is not a hypothetical.</p>\\n<p>But here's what actually happens to public sector workers when budgets get slashed: <strong>they get furloughs, not layoffs.</strong></p>\\n<p>The private sector lost 8.7 million jobs during the Great Recession <a href=\\"#source-59\\">[59]</a>. Public sector employment <em>increased</em> by 590,000 in the first year <a href=\\"#source-47\\">[47]</a>. When budgets finally tightened, the failure mode was fundamentally different. State and local governments shed just 68,000 jobs — a 0.3% decline — while the private sector hemorrhaged millions <a href=\\"#source-63\\">[63]</a>. In FY2010, the worst budget year, 26 states used layoffs but 22 chose furloughs instead <a href=\\"#source-64\\">[64]</a>. California chose furloughs. It has chosen furloughs in nine of the fiscal years since 1992 <a href=\\"#source-65\\">[65]</a>.</p>\\n<p><strong>And furloughs aren't what most people think they are.</strong> California's 2009 furlough program covered 193,000 workers and imposed 2-3 unpaid days per month — a 13.8% reduction on paper <a href=\\"#source-60\\">[60]</a>. In reality, furlough hours were banked as leave credits and paid out at separation, often at a higher base pay after COLA increases <a href=\\"#source-61\\">[61]</a>. Workers kept their jobs, their health insurance, their pension accrual, and their seniority. The historical pattern is consistent: public sector employment didn't drop during the 1991 recession at all, didn't decline after the dot-com bust until 2004, and barely moved during 2008-2012 <a href=\\"#source-62\\">[62]</a>.</p>\\n<p>This stability isn't accidental — it's structural. <strong>Countercyclical demand</strong> means that when the private sector contracts, public sector workload expands. Safety net caseloads rose from 276 million to 310 million recipients during the Great Recession <a href=\\"#source-66\\">[66]</a>. Someone has to process those claims, maintain those roads, inspect those buildings, and run those programs. The work doesn't disappear when the economy does.</p>\\n<p><strong>Union protection</strong> reinforces the structural advantage. Public sector union density is 32.9% versus 5.9% in the private sector, and local agencies sit at 37.8% <a href=\\"#source-67\\">[67]</a>. That means layoffs happen by seniority, not by manager mood. Furloughs are negotiated, not dictated. You get a grievance process before termination. Civil service rules, merit-based hiring, and progressive discipline create layers of protection that simply don't exist in at-will private employment.</p>\\n<p><strong>And then there's the pension.</strong> Public sector workers earn defined-benefit retirement through CalPERS or CalSTRS — a guaranteed monthly income for life calculated from salary and years of service, not subject to market crashes. Thirty years of service typically yields 60-75% of final salary, guaranteed, regardless of what the stock market does. While private sector 401(k)s crater with every correction, public pensions pay out on schedule.</p>\\n<p>You can't be laid off because your company missed earnings. You can't be &quot;restructured&quot; because a VC pulled funding. Your position exists because the public needs the service — not because an investor believes in the growth story.</p>\\n<p>At <a href=\\"https://penpublic.com\\" target=\\"_blank\\" rel=\\"noreferrer\\">PenPublic</a>, we're building the most comprehensive public sector job platform in the country — aggregating positions across hundreds of agencies at the federal, state, and local level. Local agency jobs are the hardest to find because they're scattered across thousands of individual websites. We bring them together in one place. Whether you're a tech worker thinking about your next move, a recent graduate evaluating career paths, or a current public servant exploring new opportunities, we believe public service represents one of the smartest career investments you can make right now.</p>\\n<p>The AI bubble will pop. The K-shaped economy will correct. The question isn't whether disruption is coming — it's whether you'll be positioned on stable ground when it arrives.</p>\\n<hr>\\n<h2 id=\\"sources\\" tabindex=\\"-1\\">Sources <a class=\\"header-anchor\\" href=\\"#sources\\" aria-label=\\"Permalink to &quot;Sources&quot;\\">&ZeroWidthSpace;</a></h2>\\n<p><a id=\\"source-1\\"><strong>1.</strong></a> <a href=\\"https://thefinancialbrand.com/news/artificial-intelligence-banking/why-95-of-enterprises-are-getting-zero-return-on-ai-investment-191950\\" target=\\"_blank\\" rel=\\"noreferrer\\">MIT's The GenAI Divide: State of AI in Business 2025</a> — 95% failure rate for enterprise AI projects; $30-40B in investment with zero measurable return</p>\\n<p><a id=\\"source-2\\"><strong>2.</strong></a> <a href=\\"https://bizzdesign.com/blog/enterprise-ai-adoption-balancing-innovation-and-roi-2026\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bizzdesign — &quot;Enterprise AI Adoption: Balancing Innovation and ROI in 2026&quot;</a> — Only 15% report positive profitability impact; Forrester predicts 25% of 2026 AI spend deferred to 2027</p>\\n<p><a id=\\"source-3\\"><strong>3.</strong></a> <a href=\\"https://www.ibm.com/think/insights/ai-roi\\" target=\\"_blank\\" rel=\\"noreferrer\\">IBM — &quot;How to Maximize AI ROI in 2026&quot;</a> — 5.9% ROI on 10% capital investment; only 25% of AI initiatives deliver expected ROI; only 29% can measure ROI confidently</p>\\n<p><a id=\\"source-4\\"><strong>4.</strong></a> <a href=\\"https://medium.com/origintrail/5-trends-to-drive-the-ai-roi-in-2026-trust-is-capital-372ac5dabc38\\" target=\\"_blank\\" rel=\\"noreferrer\\">OriginTrail / Medium — &quot;5 Trends to Drive AI ROI in 2026&quot;</a> — Only 14% of CFOs report measurable ROI; MIT study confirms 95% failure rate</p>\\n<p><a id=\\"source-5\\"><strong>5.</strong></a> <a href=\\"https://www.consultingmag.com/2026/02/04/why-enterprise-ai-stalled-and-what-is-finally-changing-in-2026/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Consulting Magazine — &quot;Why Enterprise AI Stalled and What Is Finally Changing in 2026&quot;</a> — 90-95% of organizations seeing little to no measurable financial return; Gartner predicts 40% of agentic AI projects cancelled by 2027</p>\\n<p><a id=\\"source-6\\"><strong>6.</strong></a> <a href=\\"https://www.fullstack.com/labs/resources/blog/generative-ai-roi-why-80-of-companies-see-no-results\\" target=\\"_blank\\" rel=\\"noreferrer\\">FullStack Labs — &quot;Generative AI ROI: Why 80% Fail&quot;</a> — 70% of Fortune 500 use Copilot; 78% of companies report no significant bottom-line impact; only 1% view GenAI strategies as mature</p>\\n<p><a id=\\"source-7\\"><strong>7.</strong></a> <a href=\\"https://finance.yahoo.com/news/ai-contributed-basically-zero-us-181419807.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yahoo Finance — &quot;AI Contributed 'Basically Zero' to the US Economy, According to Goldman Sachs&quot;</a> — Goldman Sachs Chief Economist Jan Hatzius interview with Atlantic Council</p>\\n<p><a id=\\"source-8\\"><strong>8.</strong></a> <a href=\\"https://gizmodo.com/ai-added-basically-zero-to-us-economic-growth-last-year-goldman-sachs-says-2000725380\\" target=\\"_blank\\" rel=\\"noreferrer\\">Gizmodo — &quot;AI Added 'Basically Zero' to US Economic Growth Last Year, Goldman Sachs Says&quot;</a> — Hatzius on imported AI equipment boosting Taiwanese and Korean GDP</p>\\n<p><a id=\\"source-9\\"><strong>9.</strong></a> <a href=\\"https://futurism.com/future-society/researchers-economy-ai-narratives\\" target=\\"_blank\\" rel=\\"noreferrer\\">Futurism — &quot;Goldman Sachs Researchers Make Startling Claim About AI's Effects on the US Economy&quot;</a> — Joseph Briggs interview with Washington Post</p>\\n<p><a id=\\"source-10\\"><strong>10.</strong></a> <a href=\\"https://www.tomshardware.com/tech-industry/artificial-intelligence/ai-boosted-us-economy-by-basically-zero-in-2025-says-goldman-sachs-chief-economist-we-think-theres-been-a-lot-of-misreporting-of-the-impact-that-ai-investment-had-on-gdp-growth\\" target=\\"_blank\\" rel=\\"noreferrer\\">Tom's Hardware — &quot;AI Boosted US Economy by 'Basically Zero' in 2025, Says Goldman Sachs Chief Economist&quot;</a> — 0.2% AI contribution to 2.2% GDP growth; $700B projected 2026 spend; J.P. Morgan $600B revenue threshold</p>\\n<p><a id=\\"source-11\\"><strong>11.</strong></a> <a href=\\"https://fortune.com/2025/12/23/us-gdp-alive-by-ai-capex/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;A Huge Chunk of U.S. GDP Growth Is Being Kept Alive by AI Spending 'With No Guaranteed Return'&quot;</a> — Deutsche Bank recession warning; $200B AI-related credit issuance (30% of USD supply); $4 trillion cumulative data center spend projected through 2030</p>\\n<p><a id=\\"source-12\\"><strong>12.</strong></a> <a href=\\"https://www.cnbc.com/2026/01/26/ai-wasnt-the-biggest-engine-of-us-gdp-growth-in-2025.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">CNBC — &quot;AI Spending Wasn't the Biggest Engine of U.S. Economic Growth in 2025&quot;</a> — MRB Partners analysis; 20-25% net AI contribution after import adjustment; consumer spending as true growth driver</p>\\n<p><a id=\\"source-13\\"><strong>13.</strong></a> <a href=\\"https://techcrunch.com/2026/02/27/openai-raises-110b-in-one-of-the-largest-private-funding-rounds-in-history/\\" target=\\"_blank\\" rel=\\"noreferrer\\">TechCrunch — &quot;OpenAI Raises $110B in One of the Largest Private Funding Rounds in History&quot;</a> — $50B Amazon, $30B Nvidia, $30B SoftBank; stateful runtime on AWS Bedrock; $100B AWS commitment expansion</p>\\n<p><a id=\\"source-14\\"><strong>14.</strong></a> <a href=\\"https://www.bloomberg.com/news/articles/2026-02-27/openai-finalizes-110-billion-funding-at-730-billion-valuation\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bloomberg — &quot;OpenAI Finalizes $110 Billion Funding at $730 Billion Value&quot;</a> — $730B pre-money valuation; Amazon's $35B contingent on AGI or IPO</p>\\n<p><a id=\\"source-15\\"><strong>15.</strong></a> <a href=\\"https://www.axios.com/2026/02/27/openai-funding-nvidia-amazon\\" target=\\"_blank\\" rel=\\"noreferrer\\">Axios — &quot;OpenAI Secures $110B Funding Round&quot;</a> — Round exceeds total 2023 U.S. VC investment ($170B); Microsoft did not participate</p>\\n<p><a id=\\"source-16\\"><strong>16.</strong></a> <a href=\\"https://www.newcomer.co/p/openai-raises-110-billion-and-throws\\" target=\\"_blank\\" rel=\\"noreferrer\\">Newcomer — &quot;OpenAI Raises $110 Billion &amp; Throws In With Amazon&quot;</a> — Stargate described as &quot;branding exercise&quot;; little collaboration among partners; complicated financial structures becoming ordinary arrangements</p>\\n<p><a id=\\"source-17\\"><strong>17.</strong></a> <a href=\\"https://www.wheresyoured.at/why-everybody-is-losing-money-on-ai/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron / Where's Your Ed At — &quot;Why Everybody Is Losing Money on AI&quot;</a> — OpenAI: 50% revenue on inference, 75% on training (&gt;100% combined); $9B spent to lose $5B; Perplexity at 164% of revenue on compute; entire value chain unprofitable</p>\\n<p><a id=\\"source-18\\"><strong>18.</strong></a> <a href=\\"https://www.news.aakashg.com/p/how-to-price-ai-products\\" target=\\"_blank\\" rel=\\"noreferrer\\">Product Faculty / AI Pricing Guide 2026</a> — Claude Code heavy users cost &quot;tens of thousands per month&quot;; OpenAI projects $14B cumulative losses by end of 2026; AI SaaS gross margins 20-60% vs traditional 70-90%</p>\\n<p><a id=\\"source-19\\"><strong>19.</strong></a> <a href=\\"https://www.getmonetizely.com/blogs/ai-pricing-how-much-does-ai-cost-in-2025\\" target=\\"_blank\\" rel=\\"noreferrer\\">Monetizely — &quot;AI Pricing in 2025: Strategy for Costing&quot;</a> — Sam Altman admission that $200/mo Pro tier loses money on power users; AI gross margins under pressure industry-wide</p>\\n<p><a id=\\"source-20\\"><strong>20.</strong></a> <a href=\\"https://www.uptechstudio.com/blog/the-true-cost-of-ai-when-the-subsidies-run-out\\" target=\\"_blank\\" rel=\\"noreferrer\\">UpTech Studio — &quot;The True Cost of AI: When the Subsidies Run Out&quot;</a> — Uber/WeWork subsidy model comparison; land-grab pricing strategy; warning that 5x current AI costs would kill most AI startups</p>\\n<p><a id=\\"source-21\\"><strong>21.</strong></a> <a href=\\"https://www.pbs.org/newshour/show/k-shaped-economy-why-the-wealthy-are-thriving-as-most-americans-fall-behind\\" target=\\"_blank\\" rel=\\"noreferrer\\">PBS NewsHour — &quot;K-Shaped Economy: Why the Wealthy Are Thriving as Most Americans Fall Behind&quot;</a> — Top 10% = 50% of spending (up from 35% in early 1990s)</p>\\n<p><a id=\\"source-22\\"><strong>22.</strong></a> <a href=\\"https://finance.yahoo.com/video/wealth-inequality-k-shaped-economy-183000976.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yahoo Finance — Mark Zandi Interview: &quot;Wealth Inequality in K-Shaped Economy Is 'Corrosive'&quot;</a> — Top 20% = 59% of total spending (Moody's Analytics data)</p>\\n<p><a id=\\"source-23\\"><strong>23.</strong></a> <a href=\\"https://www.cnbc.com/2026/01/30/wealth-inequality-k-shaped-economy-united-states-consumer-spending-trump.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">CNBC — &quot;Wealth Inequality and the 'K-Shaped' Economy Are More Striking Than Ever&quot;</a> — Bottom 80% spending hasn't outpaced inflation in 6 years; Mark Zandi &quot;poles&quot; quote; rising auto loan delinquencies</p>\\n<p><a id=\\"source-24\\"><strong>24.</strong></a> <a href=\\"https://economics.td.com/us-k-shaped-consumer-spending\\" target=\\"_blank\\" rel=\\"noreferrer\\">TD Economics — &quot;U.S. Consumer Spending: Still a K, but That's OK&quot;</a> — Top 20% hold 72% of total household wealth as of Q4 2025; K-shape expected to deepen in 2026 due to tax policy</p>\\n<p><a id=\\"source-25\\"><strong>25.</strong></a> <a href=\\"https://www.usbank.com/corporate-and-commercial-banking/insights/economy/macro/k-shaped-economy.html\\" target=\\"_blank\\" rel=\\"noreferrer\\">U.S. Bank — &quot;The K-Shaped Economy in 2026&quot;</a> — Lower-income households relying on debt; rising delinquency rates; Beth Ann Bovino quote on dependence on &quot;healthier cohorts&quot;</p>\\n<p><a id=\\"source-26\\"><strong>26.</strong></a> <a href=\\"https://fortune.com/2026/01/14/when-will-us-enter-recession-middle-class-barbell-k-shaped-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;Forget the K-Shape: We Have a Barbell Economy&quot;</a> — Economy described as &quot;dangerously brittle&quot;; wealthy spending tethered to portfolio balance; bottom 80% financing groceries with &quot;shadow debt&quot;</p>\\n<p><a id=\\"source-27\\"><strong>27.</strong></a> <a href=\\"https://www.empower.com/the-currency/money/life/k-shaped-economy-what-to-know-news\\" target=\\"_blank\\" rel=\\"noreferrer\\">Empower — &quot;The K-Shaped Economy: What Consumers Should Know&quot;</a> — $180B in wealth-effect consumer spending from AI-related stock valuations; Delta premium revenue up 9%, basic economy down 7%</p>\\n<p><a id=\\"source-28\\"><strong>28.</strong></a> <a href=\\"https://fortune.com/2026/01/14/when-will-us-enter-recession-middle-class-barbell-k-shaped-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fortune — &quot;Forget the K-Shape: We Have a Barbell Economy&quot;</a> — &quot;No one there to catch it&quot; when wealthy pull back; pandemic savings depleted; economy has &quot;massive engine and insufficient braking mechanisms&quot;</p>\\n<p><a id=\\"source-29\\"><strong>29.</strong></a> <a href=\\"https://insights.som.yale.edu/insights/this-is-how-the-ai-bubble-bursts\\" target=\\"_blank\\" rel=\\"noreferrer\\">Yale Insights / Jeffrey Sonnenfeld — &quot;This Is How the AI Bubble Bursts&quot;</a> — J.P. Morgan's Cembalest: AI stocks = 75% of S&amp;P 500 returns, 80% of earnings growth, 90% of capex growth since ChatGPT launch; two-thirds of U.S. deal value going to AI/ML startups in H1 2025</p>\\n<p><a id=\\"source-30\\"><strong>30.</strong></a> <a href=\\"https://www.statista.com/chart/30318/sector-contributions-to-sp500-return/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Statista — &quot;Wider Tech Sector Led S&amp;P 500 to Another Double-Digit Gain&quot;</a> — Mag 7 = 42% of S&amp;P 500's 17.9% return in 2025; tech and communications = 63.1% of total return; excluding those sectors, S&amp;P 500 returned just 6%</p>\\n<p><a id=\\"source-31\\"><strong>31.</strong></a> <a href=\\"https://www.rbcwealthmanagement.com/en-us/insights/us-equity-returns-in-2025-record-breaking-resilience\\" target=\\"_blank\\" rel=\\"noreferrer\\">RBC Wealth Management — &quot;U.S. Equity Returns in 2025: Record-Breaking Resilience&quot; and &quot;The 'Great Narrowing': S&amp;P 500 Concentration&quot;</a> — Seven AI-exposed stocks = over half of S&amp;P 500 gains; top 10 = 41% of weight but ~32% of earnings; cap-weighted index outperformed equal-weight by 32% over 3 years</p>\\n<p><a id=\\"source-32\\"><strong>32.</strong></a> <a href=\\"https://www.goldmansachs.com/insights/articles/the-sp-500-expected-to-rally-12-this-year\\" target=\\"_blank\\" rel=\\"noreferrer\\">Goldman Sachs — &quot;The S&amp;P 500 Is Expected to Rally 12% This Year&quot;</a> — Top tech stocks = 53% of S&amp;P 500 return in 2025; AI capex reaching 75% of cash flows; &quot;elevated valuations, extreme concentration, and strong recent returns rhymes with overextended equity markets during the last century&quot;</p>\\n<p><a id=\\"source-33\\"><strong>33.</strong></a> <a href=\\"https://www.apolloacademy.com/extreme-ai-concentration-in-the-sp-500/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Apollo Academy / Torsten Slok — &quot;Extreme AI Concentration in the S&amp;P 500&quot;</a> — AI bubble bigger than IT bubble in 1990s; average P/E of top 10 around 50; hyperscaler capex as share of GDP exceeds dotcom era; investors &quot;remain overexposed to AI&quot;</p>\\n<p><a id=\\"source-34\\"><strong>34.</strong></a> <a href=\\"https://www.wheresyoured.at/costs/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Ed Zitron / Where's Your Ed At — &quot;This Is How Much Anthropic and Cursor Spend on Amazon Web Services&quot;</a> — $2.66B AWS spend on $2.55B revenue through September 2025; costs scale linearly with revenue; estimates Google Cloud spend at minimum 50% of AWS</p>\\n<p><a id=\\"source-35\\"><strong>35.</strong></a> <a href=\\"https://www.anthropic.com/news/expanding-our-use-of-google-cloud-tpus-and-services\\" target=\\"_blank\\" rel=\\"noreferrer\\">Anthropic — &quot;Expanding Our Use of Google Cloud TPUs and Services&quot;</a> — Deal worth &quot;tens of billions of dollars&quot; for up to one million TPUs; over a gigawatt of capacity expected online in 2026</p>\\n<p><a id=\\"source-36\\"><strong>36.</strong></a> <a href=\\"https://www.aiplanetx.com/p/cloud-spending-hits-anthropic\\" target=\\"_blank\\" rel=\\"noreferrer\\">AI Planet X — &quot;Cloud Spending Hits Anthropic&quot;</a> — Inference costs on Google and Amazon cloud ran 23% over plan; gross margin pushed toward ~40%; ~$5.2B burn in 2025</p>\\n<p><a id=\\"source-37\\"><strong>37.</strong></a> <a href=\\"https://www.pminsights.com/insights/anthropic-approaches-7b-run-rate-in-2025-outpaces-openai\\" target=\\"_blank\\" rel=\\"noreferrer\\">PM Insights — &quot;Anthropic Approaches $7B Run Rate&quot;</a> — Over 1,200 employees by late 2025; plans to triple international workforce and quintuple applied AI team</p>\\n<p><a id=\\"source-38\\"><strong>38.</strong></a> <a href=\\"https://www.levels.fyi/companies/anthropic/salaries\\" target=\\"_blank\\" rel=\\"noreferrer\\">Levels.fyi — Anthropic Salaries</a> — Median yearly total compensation $471,808; highest reported $759,413 for Lead Software Engineer</p>\\n<p><a id=\\"source-39\\"><strong>39.</strong></a> <a href=\\"https://www.datacenterdynamics.com/en/news/anthropic-cloud-spend-expected-to-reach-80bn-through-2029/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Data Center Dynamics — &quot;Anthropic Cloud Spend Expected to Reach $80B Through 2029&quot;</a> — $80B total cloud spend projected through 2029 across AWS, Google, and Microsoft; AWS takes up to 50% of gross profits; Google takes 20-30% of net revenue; $30B Microsoft Azure commitment</p>\\n<p><a id=\\"source-40\\"><strong>40.</strong></a> <a href=\\"https://www.pymnts.com/artificial-intelligence-2/2026/anthropic-set-to-pay-cloud-partners-80-billion-through-2029/\\" target=\\"_blank\\" rel=\\"noreferrer\\">PYMNTS — &quot;Anthropic Set to Pay Cloud Partners $80 Billion Through 2029&quot;</a> — Revenue sharing payouts: ~$1.3M in 2024, ~$360M in 2025, ~$1.9B in 2026, ~$6.4B in 2027 (The Information data)</p>\\n<p><a id=\\"source-41\\"><strong>41.</strong></a> <a href=\\"https://www.fierce-network.com/cloud/what-does-anthropics-50b-data-center-project-mean-hyperscalers\\" target=\\"_blank\\" rel=\\"noreferrer\\">Fierce Network — &quot;What Does Anthropic's $50B Data Center Project Mean for Hyperscalers?&quot;</a> — $50B data center partnership with FluidStack; facilities in Texas and New York expected online throughout 2026</p>\\n<p><a id=\\"source-42\\"><strong>42.</strong></a> <a href=\\"https://sustainabilitymag.com/news/why-anthropic-pledging-offset-ai-energy-costs\\" target=\\"_blank\\" rel=\\"noreferrer\\">Sustainability Magazine — &quot;Why Is Anthropic Pledging to Offset Its AI Energy Costs?&quot;</a> — Committed to covering 100% of grid upgrade costs and electricity price increases for communities hosting its data centers</p>\\n<p><a id=\\"source-43\\"><strong>43.</strong></a> <a href=\\"https://sacra.com/c/anthropic/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Sacra — Anthropic Revenue, Valuation &amp; Funding</a> — Cash burn of $5.6B in 2024, ~$3B in 2025; projects cash flow positive in 2027, break-even in 2028</p>\\n<p><a id=\\"source-44\\"><strong>44.</strong></a> <a href=\\"https://www.axios.com/2026/02/12/anthropic-raises-30b-at-380b-valuation\\" target=\\"_blank\\" rel=\\"noreferrer\\">Axios — &quot;Anthropic Raises $30B at $380B Valuation&quot;</a> — 300,000+ business customers; run-rate revenue of $14B; customers spending $100K+ annually grown 7x in past year</p>\\n<p><a id=\\"source-45\\"><strong>45.</strong></a> <a href=\\"https://builtin.com/articles/top-tech-ipos-2026\\" target=\\"_blank\\" rel=\\"noreferrer\\">Built In — &quot;2026 IPO Watchlist: OpenAI, SpaceX and Other Tech Giants&quot;</a> — Retained Wilson Sonsini (firm behind Google and LinkedIn IPOs) in December 2025 for IPO preparation</p>\\n<p><a id=\\"source-46\\"><strong>46.</strong></a> <a href=\\"https://www.newsweek.com/ai-skeptic-ed-zitron-says-math-on-data-centers-doesnt-add-up-11594219\\" target=\\"_blank\\" rel=\\"noreferrer\\">Newsweek — &quot;AI Skeptic Ed Zitron Says Math on Data Centers Doesn't Add Up&quot;</a> — Claude Code subscribers consume $8-13.50 in compute per $1 paid; $200/month user burns $2,700+ in real costs; &quot;Everyone using Claude Code right now is in an illusory environment&quot;</p>\\n<p><a id=\\"source-47\\"><strong>47.</strong></a> <a href=\\"https://www.mercatus.org/research/data-visualizations/private-sector-job-losses-dwarf-government-gains\\" target=\\"_blank\\" rel=\\"noreferrer\\">Mercatus Center / George Mason University — &quot;Private Sector Job Losses Dwarf Government Gains&quot;</a> — BLS Current Employment Statistics: government employment increased by 590,000 since January 2008 while private sector lost nearly 8 million jobs; government peaked at ~23 million in May 2010</p>\\n<p><a id=\\"source-48\\"><strong>48.</strong></a> <a href=\\"https://hai.stanford.edu/ai-index/2025-ai-index-report\\" target=\\"_blank\\" rel=\\"noreferrer\\">Stanford HAI — The 2025 AI Index Report</a> — Inference cost for GPT-3.5-level performance dropped over 280-fold between November 2022 and October 2024; driven by increasingly capable small models and open-weight alternatives</p>\\n<p><a id=\\"source-49\\"><strong>49.</strong></a> <a href=\\"https://epoch.ai/data-insights/llm-inference-price-trends\\" target=\\"_blank\\" rel=\\"noreferrer\\">Epoch AI — &quot;LLM Inference Prices Have Fallen Rapidly but Unequally Across Tasks&quot;</a> — Price declines ranging from 9x to 900x per year depending on benchmark; fastest trends (900x/year) start after January 2024; median rate increased from 50x to 200x per year when isolating post-2024 data</p>\\n<p><a id=\\"source-50\\"><strong>50.</strong></a> <a href=\\"https://www.bloomberg.com/news/articles/2025-12-21/openai-sees-better-margins-on-business-sales-report-says\\" target=\\"_blank\\" rel=\\"noreferrer\\">Bloomberg — &quot;OpenAI Sees Better Margins on Business Sales, Report Says&quot;</a> — OpenAI compute margin reached 70% as of October 2025, up from 52% at end of 2024 and double the 35% rate in January 2024 (The Information data)</p>\\n<p><a id=\\"source-51\\"><strong>51.</strong></a> <a href=\\"https://lesbarclays.substack.com/p/who-captures-the-value-when-ai-inference\\" target=\\"_blank\\" rel=\\"noreferrer\\">Les Barclays / Substack — &quot;Who Captures the Value When AI Inference Becomes Cheap?&quot;</a> — Cost per query increasing for frontier models even as cost per token declines; models employing test-time scaling consume multiple tokens per problem; at current pace OpenAI's competitive advantage may dissipate</p>\\n<p><a id=\\"source-52\\"><strong>52.</strong></a> <a href=\\"https://foundationcapital.com/nvidias-ai-factory-bet/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Foundation Capital — &quot;NVIDIA's 'AI Factory' Bet&quot;</a> — Reasoning models require 20x more tokens and 150x more compute per query than traditional LLMs; enterprise applications projected to run hundreds of millions of agentic queries per month</p>\\n<p><a id=\\"source-53\\"><strong>53.</strong></a> <a href=\\"https://www.ikangai.com/the-llm-cost-paradox-how-cheaper-ai-models-are-breaking-budgets/\\" target=\\"_blank\\" rel=\\"noreferrer\\">iKangai — &quot;The LLM Cost Paradox: How 'Cheaper' AI Models Are Breaking Budgets&quot;</a> — At maximum reasoning settings, models consume 10,000+ reasoning tokens internally for a 200-token answer; token consumption explosion leaving AI companies scrambling to stay profitable</p>\\n<p><a id=\\"source-54\\"><strong>54.</strong></a> <a href=\\"https://www.arturmarkus.com/the-inference-cost-paradox-why-generative-ai-spending-surged-320-in-2025-despite-per-token-costs-dropping-1000x-and-what-it-means-for-your-ai-budget-in-2026/\\" target=\\"_blank\\" rel=\\"noreferrer\\">AI Unfiltered — &quot;The Inference Cost Paradox&quot;</a> — Enterprise AI spending surged 320% in 2025 despite per-token costs dropping 1,000x; organizations that budgeted for 20-30% increases found themselves scrambling by Q3; Jevons Paradox makes single-number AI budgets &quot;fantasy&quot;</p>\\n<p><a id=\\"source-55\\"><strong>55.</strong></a> <a href=\\"https://www.leaddigital.com/blog/a-token-economy/\\" target=\\"_blank\\" rel=\\"noreferrer\\">LeadDigital — &quot;A Token Economy&quot;</a> — Inference costs fell 1,000-fold but demand rose 10,000-fold; Jevons Paradox in action; Gartner predicts 40% of enterprise applications will feature AI agents by end of 2026, up from 5% in 2025</p>\\n<p><a id=\\"source-56\\"><strong>56.</strong></a> <a href=\\"https://www.saastr.com/have-ai-gross-margins-really-turned-the-corner-the-real-math-behind-openais-70-compute-margin-and-why-b2b-startups-are-still-running-on-a-treadmill/\\" target=\\"_blank\\" rel=\\"noreferrer\\">SaaStr — &quot;Have AI Gross Margins Really Turned the Corner?&quot;</a> — Anthropic expects gross margin of 50% in 2025 and 77% by 2028; Cursor paying ~$650M/year to Anthropic on ~$500M revenue (negative 30% margin); Bessemer 2025 data shows AI startups averaging 25% gross margins; frontier models getting more expensive, not cheaper</p>\\n<p><a id=\\"source-57\\"><strong>57.</strong></a> <a href=\\"https://ebudget.ca.gov/2025-26/pdf/BudgetSummary/RevenueEstimates.pdf\\" target=\\"_blank\\" rel=\\"noreferrer\\">California 2025-26 Budget Revenue Estimates</a> — 67% of General Fund from personal income tax; capital gains = 16% of total tax liability (25% in boom years)</p>\\n<p><a id=\\"source-58\\"><strong>58.</strong></a> <a href=\\"https://en.wikipedia.org/wiki/2008%E2%80%932012_California_budget_crisis\\" target=\\"_blank\\" rel=\\"noreferrer\\">Wikipedia — &quot;2008-2012 California Budget Crisis&quot;</a> — State revenue dropped from ~$100B to ~$85B during dot-com bust and again during Great Recession</p>\\n<p><a id=\\"source-59\\"><strong>59.</strong></a> <a href=\\"https://www.cbpp.org/research/economy/the-legacy-of-the-great-recession\\" target=\\"_blank\\" rel=\\"noreferrer\\">Center on Budget and Policy Priorities — &quot;Legacy of the Great Recession&quot;</a> — 8.7 million jobs lost in private sector during Great Recession</p>\\n<p><a id=\\"source-60\\"><strong>60.</strong></a> <a href=\\"https://laborcenter.berkeley.edu/\\" target=\\"_blank\\" rel=\\"noreferrer\\">UC Berkeley Labor Center — &quot;California Furloughs 2009&quot;</a> — 193,000 state workers furloughed; 2-3 unpaid days per month; 13.8% effective pay reduction</p>\\n<p><a id=\\"source-61\\"><strong>61.</strong></a> <a href=\\"https://www.calhr.ca.gov/\\" target=\\"_blank\\" rel=\\"noreferrer\\">CalHR — Furlough Program Manual</a> — Furlough hours banked as leave credits; paid out at separation at current base pay rate after COLA increases</p>\\n<p><a id=\\"source-62\\"><strong>62.</strong></a> <a href=\\"https://www.csmonitor.com/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Christian Science Monitor — &quot;Government Jobs: A Recession Refuge?&quot; (2009)</a> — Public sector employment didn't drop during 1991 recession; didn't decline after dot-com bust until 2004; lagged private sector contractions by years</p>\\n<p><a id=\\"source-63\\"><strong>63.</strong></a> <a href=\\"https://www.bls.gov/opub/mlr/2011/\\" target=\\"_blank\\" rel=\\"noreferrer\\">BLS Monthly Labor Review (2011) — &quot;The Recession of 2007-2009&quot;</a> — State and local governments shed 68,000 jobs (0.3% decline) vs. millions in private sector</p>\\n<p><a id=\\"source-64\\"><strong>64.</strong></a> <a href=\\"https://www.governing.com/\\" target=\\"_blank\\" rel=\\"noreferrer\\">Governing — &quot;State Budget Actions in Recessions&quot; (2024)</a> — FY2010: 26 states used layoffs, 22 states used furloughs as primary budget-balancing tool</p>\\n<p><a id=\\"source-65\\"><strong>65.</strong></a> <a href=\\"https://lao.ca.gov/\\" target=\\"_blank\\" rel=\\"noreferrer\\">California Legislative Analyst's Office — 2025-26 Budget Analysis</a> — California has used furloughs in 9 fiscal years since 1992</p>\\n<p><a id=\\"source-66\\"><strong>66.</strong></a> <a href=\\"https://www.ncbi.nlm.nih.gov/pmc/\\" target=\\"_blank\\" rel=\\"noreferrer\\">PMC / Annals of the American Academy of Political and Social Science — &quot;Safety Net Programs in the Great Recession&quot;</a> — Safety net caseloads rose from 276 million to 310 million recipients during the Great Recession; countercyclical demand expanded public sector workload</p>\\n<p><a id=\\"source-67\\"><strong>67.</strong></a> <a href=\\"https://www.bls.gov/news.release/union2.nr0.htm\\" target=\\"_blank\\" rel=\\"noreferrer\\">BLS — &quot;Union Members — 2025&quot;</a> — Public sector union membership rate 32.9% vs. private sector 5.9%; local government workers at 37.8%</p>\\n<hr>\\n<p><em>This analysis reflects the views of PenPublic and is informed by publicly available economic research and reporting. We encourage readers to review the cited sources and draw their own conclusions.</em></p>\\n<p><em><a href=\\"https://penpublic.com\\" target=\\"_blank\\" rel=\\"noreferrer\\">PenPublic</a> — Your guide to public sector careers.</em></p>\\n","frontmatter":{"title":"The AI Bubble Won't Take Your Job — But Its Collapse Might","date":"2026-03-01T12:00:00.000Z","description":"Why the coming AI reckoning makes public sector careers the smartest move you can make","author":"Penny","tags":["AI","Economy","Public Sector Jobs"]},"excerpt":"<h1 id=\\"the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" tabindex=\\"-1\\">The AI Bubble Won't Take Your Job — But Its Collapse Might <a class=\\"header-anchor\\" href=\\"#the-ai-bubble-won-t-take-your-job-—-but-its-collapse-might\\" aria-label=\\"Permalink to &quot;The AI Bubble Won't Take Your Job — But Its Collapse Might&quot;\\">&ZeroWidthSpace;</a></h1>\\n<p><em>Why the coming AI reckoning makes public sector careers the smartest move you can make</em></p>\\n<p><em>By Penny | March 1, 2026 (updated Mar 3, 2026)</em></p>\\n","url":"/blog/2026-03-01_ai-bubble-government-jobs.html"}]}}`),a={name:"blog/2025-06-27_Retirement-Benefits-at-CSU-and-UC-Systems.md"};function s(i,e,l,h,c,u){return r(),o("div",null,e[0]||(e[0]=[n("",21)]))}const g=t(a,[["render",s]]);export{d as __pageData,g as default};
